pub fn router(state: Arc<AppState>) -> Router {
    Router::new()
        .route("/health", get(health))
        .route("/admin/metrics", get(admin_metrics))
        .route("/admin/cache-validation", get(admin_cache_validation))
        .route("/admin/cache-affinity", get(admin_cache_affinity))
        .route("/admin/cache-capabilities", get(admin_cache_capabilities))
        .route(
            "/admin/cache-capabilities/probe",
            post(admin_probe_cache_capabilities),
        )
        .route(
            "/admin/response-session-reuse/probe",
            post(admin_probe_response_session_reuse),
        )
        .route(
            "/admin/responses-websocket/probe",
            post(admin_probe_responses_websocket),
        )
        .route("/v1/models", get(list_models))
        .route("/v1/chat/completions", post(chat_completions))
        .route("/v1/responses", post(responses))
        .route("/v1/responses/compact", post(responses_compact_legacy))
        .route("/codex/v1/models", get(codex_list_models))
        .route("/codex/v1/chat/completions", post(codex_chat_completions))
        .route("/codex/v1/responses", post(codex_responses))
        .route(
            "/codex/v1/responses/compact",
            post(codex_responses_compact_legacy),
        )
        .route(
            "/v1/responses/:response_id/compact",
            post(responses_compact),
        )
        .route(
            "/codex/v1/responses/:response_id/compact",
            post(codex_responses_compact),
        )
        .route("/v1/messages", post(messages))
        .layer(DefaultBodyLimit::max(200 * 1024 * 1024))
        .with_state(state)
}
