async fn insert_cache_entries(
    state: &AppState,
    keys: Vec<String>,
    semantic_text: Option<String>,
    semantic_shape: Option<String>,
    content_type: String,
    status: u16,
    body: Vec<u8>,
    decision: &RouteDecision,
    config: &AppConfig,
) {
    let now = Utc::now();
    let expires_at = now + Duration::seconds(config.cache.max_age_seconds as i64);
    let entries = keys
        .into_iter()
        .map(|key| CacheEntry {
            key,
            semantic_text: semantic_text.clone(),
            semantic_shape: semantic_shape.clone(),
            semantic_vector: Vec::new(),
            content_type: content_type.clone(),
            status,
            body: body.clone(),
            created_at: now,
            expires_at,
            provider_id: decision.provider.id.clone(),
            model: decision.model.clone(),
            workspace_fingerprint: Some(config.workspace_fingerprint.clone()),
        })
        .collect();
    if let Err(err) = state.cache.insert_many(entries, &config.cache).await {
        state
            .metrics
            .record_error("cache_insert", &err.to_string())
            .await;
    }
}

#[cfg(test)]
fn responses_prewarm_bucket_count(
    channel: &Channel,
    usage_record: Option<&UsageRecord>,
    gap_breakdown: Option<&ProviderCacheGapBreakdown>,
) -> u64 {
    if !matches!(channel, Channel::Responses) {
        return 0;
    }
    let (Some(record), Some(gap)) = (usage_record, gap_breakdown) else {
        return 0;
    };
    if record.input_tokens < 4096 || record.cache_read_tokens == 0 {
        return 0;
    }
    let ratio = provider_cache_ratio(record).unwrap_or(0.0);
    let net_save_tokens = gap
        .avoidable_tokens
        .max(gap.new_tail_tokens)
        .saturating_sub(record.input_tokens.saturating_sub(record.cache_read_tokens));
    if net_save_tokens < BACKGROUND_PREWARM_MIN_NET_SAVE_TOKENS {
        return 0;
    }

    // Avoidable gaps are already-seen prefix buckets that failed to hit. They
    // get first claim on follow-up prewarm, but this app is cost-first: one
    // user request may add at most one extra upstream request after the base
    // prewarm. More bucket filling made hit-rate graphs prettier while
    // increasing real upstream spend.
    if gap.avoidable_tokens > 0 {
        let max_avoidable = if ratio >= 0.98 {
            8192
        } else if ratio >= 0.95 {
            4096
        } else if ratio >= 0.90 {
            2048
        } else {
            0
        };
        if max_avoidable > 0 && gap.avoidable_tokens <= max_avoidable {
            return BACKGROUND_PREWARM_MAX_EXTRA_BUCKET_REQUESTS;
        }
        return 0;
    }

    // v0.0.52 cost-first baseline: pure new tails must warm naturally through
    // the user's real stream. Do not add a companion non-streaming request.
    0
}

#[cfg(test)]
fn responses_foreground_prewarm_settle_delay(
    trigger_tokens: u64,
    record: &UsageRecord,
) -> TokioDuration {
    let ratio = provider_cache_ratio(record).unwrap_or(0.0);
    if ratio < 0.90 {
        return TokioDuration::from_millis(500);
    }
    if trigger_tokens >= 4096 {
        TokioDuration::from_millis(1800)
    } else if trigger_tokens >= 1536 {
        TokioDuration::from_millis(1400)
    } else if trigger_tokens >= 1024 {
        TokioDuration::from_millis(1200)
    } else if trigger_tokens >= 512 {
        TokioDuration::from_millis(950)
    } else {
        TokioDuration::from_millis(650)
    }
}

#[cfg(test)]
fn foreground_prewarm_responses_missing_state_decision(body: &Value) -> ForegroundPrewarmDecision {
    let _ = body;
    // Cost-first rule from v0.0.52: do not send a companion sync request before
    // the first real stream just because the in-memory prefix state is missing.
    ForegroundPrewarmDecision::Skip("missing_prefix_state_cost_first")
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[cfg(test)]
enum ForegroundPrewarmDecision {
    Run(u64),
    Skip(&'static str),
}

#[cfg(test)]
fn foreground_prewarm_responses_decision(
    state: &PrefixWarmState,
    estimated_current_bucket: Option<u64>,
) -> ForegroundPrewarmDecision {
    let avoidable_decision = foreground_prewarm_responses_avoidable_tokens(state);
    if matches!(avoidable_decision, ForegroundPrewarmDecision::Run(_)) {
        return avoidable_decision;
    }
    let _ = estimated_current_bucket;
    avoidable_decision
}

#[cfg(test)]
fn foreground_prewarm_responses_avoidable_tokens(
    state: &PrefixWarmState,
) -> ForegroundPrewarmDecision {
    if state.input_tokens < 4096 {
        return ForegroundPrewarmDecision::Skip("input_below_4k");
    }
    let avoidable = state
        .avoidable_shortfall_tokens_128
        .max(state.avoidable_shortfall_tokens);
    if state.cache_read_tokens == 0 && avoidable == 0 {
        return ForegroundPrewarmDecision::Skip("cache_read_zero");
    }
    if avoidable == 0 {
        return ForegroundPrewarmDecision::Skip("no_avoidable_gap");
    }
    let effective_cache_read_tokens = if state.cache_read_tokens == 0 && avoidable > 0 {
        state
            .seen_bucket_tokens
            .max(state.seen_bucket_tokens_128)
            .min(provider_cache_bucket_max_128(state.input_tokens))
    } else {
        state.cache_read_tokens
    };
    let ratio = effective_cache_read_tokens as f64 / state.input_tokens.max(1) as f64;
    if !(128..=90_000).contains(&avoidable) {
        return ForegroundPrewarmDecision::Skip("no_avoidable_gap");
    }
    if ratio < 0.90 {
        return ForegroundPrewarmDecision::Skip("ratio_low");
    }
    let trigger_tokens = avoidable;
    let cold_read_regression = state.cache_read_tokens == 0
        && avoidable >= 4096
        && effective_cache_read_tokens >= 32_000
        && ratio >= 0.90;
    let high_waterline = effective_cache_read_tokens >= 90_000 && ratio >= 0.99;
    let near_full = ratio >= 0.992;
    let enough_signal = if trigger_tokens <= 512 {
        if state.input_tokens < 32_000 {
            if state.input_tokens < 8192 && state.small_gap_recovery_streak >= 1 {
                ratio >= 0.90
            } else if state.small_gap_recovery_streak >= 1 {
                ratio >= 0.955
            } else {
                (state.avoidable_shortfall_streak >= 2 || state.small_gap_recovery_streak >= 1)
                    && ratio >= 0.955
            }
        } else if state.small_gap_recovery_streak >= 1 && ratio >= 0.975 {
            true
        } else if high_waterline {
            state.avoidable_shortfall_streak >= 1 || state.small_gap_recovery_streak >= 1
        } else if near_full {
            state.avoidable_shortfall_streak >= 2 || state.small_gap_recovery_streak >= 1
        } else {
            state.avoidable_shortfall_streak >= 4 && ratio >= 0.985
        }
    } else if trigger_tokens <= 2048 {
        if state.input_tokens < 32_000 {
            (state.avoidable_shortfall_streak >= 1 || state.small_gap_recovery_streak >= 1)
                && ratio >= 0.96
        } else if state.avoidable_shortfall_streak >= 1 && ratio >= 0.955 {
            true
        } else if state.small_gap_recovery_streak >= 1 && ratio >= 0.975 {
            true
        } else if high_waterline {
            state.avoidable_shortfall_streak >= 1 || state.small_gap_recovery_streak >= 1
        } else if near_full {
            state.avoidable_shortfall_streak >= 2 || state.small_gap_recovery_streak >= 1
        } else {
            state.avoidable_shortfall_streak >= 2 && ratio >= 0.975
        }
    } else if trigger_tokens <= 4096 {
        if state.small_gap_recovery_streak >= 1 && ratio >= 0.90 {
            true
        } else if high_waterline {
            state.avoidable_shortfall_streak >= 1 || state.small_gap_recovery_streak >= 1
        } else {
            state.avoidable_shortfall_streak >= 2 && ratio >= 0.975
        }
    } else if trigger_tokens <= 16_384 {
        cold_read_regression
            || (effective_cache_read_tokens >= 128_000
                && state.avoidable_shortfall_streak >= 3
                && ratio >= 0.95)
    } else {
        cold_read_regression || (effective_cache_read_tokens >= 128_000 && ratio >= 0.90)
    };
    if enough_signal {
        ForegroundPrewarmDecision::Run(trigger_tokens)
    } else {
        ForegroundPrewarmDecision::Skip("streak_low")
    }
}

#[cfg(test)]
fn should_background_prewarm(
    config: &AppConfig,
    channel: &Channel,
    usage_record: Option<&UsageRecord>,
    gap_breakdown: Option<&ProviderCacheGapBreakdown>,
) -> bool {
    let _ = (config, channel, usage_record, gap_breakdown);
    false
}

async fn select_provider_api_key(
    state: &AppState,
    provider_id: &str,
    exclude_key_id: Option<&str>,
    affinity_key: Option<&str>,
) -> Result<SelectedProviderKey> {
    let affinity_map_key = affinity_key.map(|key| provider_key_affinity_map_key(provider_id, key));
    let preferred_key_id = if exclude_key_id.is_none() {
        if let Some(map_key) = affinity_map_key.as_deref() {
            state
                .provider_key_affinity
                .lock()
                .await
                .get(map_key)
                .cloned()
        } else {
            None
        }
    } else {
        None
    };
    let selected = {
        let mut config = state.config.write().await;
        config
            .select_provider_key_for_request(
                provider_id,
                preferred_key_id.as_deref(),
                exclude_key_id,
            )
            .with_context(|| format!("failed to select provider key for {provider_id}"))?
    };
    let Some(selected) = selected else {
        return Err(anyhow!("provider API key is not configured"));
    };
    if let (Some(map_key), Some(key_id)) = (affinity_map_key, selected.key_id.as_ref()) {
        state
            .provider_key_affinity
            .lock()
            .await
            .insert(map_key, key_id.clone());
    }
    Ok(selected)
}

fn provider_key_affinity_map_key(provider_id: &str, affinity_key: &str) -> String {
    format!("{provider_id}\0{affinity_key}")
}

async fn note_selected_provider_key_status(
    state: &AppState,
    provider_id: &str,
    selected: &SelectedProviderKey,
    status: u16,
    error_summary: Option<&str>,
) {
    if selected.key_id.is_none() {
        return;
    }
    let Some(key_id) = selected.key_id.as_deref() else {
        return;
    };
    let Ok(status_code) = StatusCode::from_u16(status) else {
        return;
    };
    if status_code.is_success() {
        mark_selected_provider_key_success(state, provider_id, key_id).await;
        return;
    }
    let mut config = state.config.write().await;
    if is_provider_key_failure_status(status_code)
        || error_summary
            .map(is_provider_key_failure_message)
            .unwrap_or(false)
    {
        let message = error_summary
            .filter(|message| !message.trim().is_empty())
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| format!("upstream returned HTTP {status_code}"));
        config.mark_provider_key_failure(provider_id, selected.key_id.as_deref(), &message, true);
        state.journal_config(&config);
    }
}

async fn mark_selected_provider_key_success(state: &AppState, provider_id: &str, key_id: &str) {
    let mut config = state.config.write().await;
    config.mark_provider_key_success(provider_id, Some(key_id));
    state.journal_config(&config);
}

fn spawn_selected_provider_key_success(
    state: Arc<AppState>,
    provider_id: String,
    selected: &SelectedProviderKey,
) -> Option<tokio::task::JoinHandle<()>> {
    let key_id = selected.key_id.clone()?;
    let tracker = state.relay_tasks.clone();
    tracker
        .spawn(async move {
            mark_selected_provider_key_success(&state, &provider_id, &key_id).await;
        })
        .ok()
}

fn is_provider_key_failure_status(status: StatusCode) -> bool {
    matches!(
        status,
        StatusCode::UNAUTHORIZED
            | StatusCode::PAYMENT_REQUIRED
            | StatusCode::FORBIDDEN
            | StatusCode::TOO_MANY_REQUESTS
    )
}

fn is_provider_key_failure_message(message: &str) -> bool {
    let lower = message.to_ascii_lowercase();
    lower.contains("insufficient")
        || lower.contains("quota")
        || lower.contains("balance")
        || lower.contains("billing")
        || lower.contains("credit")
        || lower.contains("invalid api key")
        || lower.contains("invalid_api_key")
        || lower.contains("unauthorized")
        || lower.contains("forbidden")
        || message.contains("\u{4f59}\u{989d}\u{4e0d}\u{8db3}")
        || message.contains("\u{989d}\u{5ea6}\u{4e0d}\u{8db3}")
        || message.contains("\u{6b20}\u{8d39}")
        || message.contains("\u{4f59}\u{989d}")
}

async fn send_main_upstream_request(
    state: &AppState,
    api_key: &str,
    plan: OneShotRequestPlan,
    inbound_headers: &HeaderMap,
) -> Result<UpstreamSendOutcome> {
    OneShotTransport::new(state, api_key, inbound_headers)
        .dispatch(plan, None)
        .await
}

async fn send_agent_upstream_request(
    state: &AppState,
    api_key: &str,
    plan: OneShotRequestPlan,
    inbound_headers: &HeaderMap,
    decision: &RouteDecision,
    token: AttemptToken,
) -> Result<UpstreamSendOutcome> {
    OneShotTransport::new(state, api_key, inbound_headers)
        .dispatch(
            plan,
            Some(AgentAttemptDispatch {
                token,
                provider: decision.provider.name.clone(),
                model: decision.model.clone(),
            }),
        )
        .await
}

#[derive(Debug)]
struct ResponseSessionReuseProbeResponse {
    status: u16,
    content_type: String,
    bytes: Vec<u8>,
}

pub(crate) async fn probe_and_record_provider_cache_capabilities(
    state: &AppState,
    provider_id: &str,
    model_id: &str,
    requested_channel: Option<Channel>,
) -> Result<ProviderCacheCapabilityProbeResult> {
    probe_and_record_provider_cache_capabilities_with_key(
        state,
        provider_id,
        model_id,
        requested_channel,
        None,
    )
    .await
}

async fn probe_and_record_provider_cache_capabilities_with_key(
    state: &AppState,
    provider_id: &str,
    model_id: &str,
    requested_channel: Option<Channel>,
    selected_key: Option<SelectedProviderKey>,
) -> Result<ProviderCacheCapabilityProbeResult> {
    let provider_id = provider_id.trim();
    let model_id = model_id.trim();
    if provider_id.is_empty() || model_id.is_empty() {
        return Err(anyhow!(
            "provider and actual upstream model are required for cache capability verification"
        ));
    }
    let (provider, probe_target) = {
        let config = state.config.read().await;
        let provider = config
            .providers
            .iter()
            .find(|provider| provider.id == provider_id)
            .cloned()
            .ok_or_else(|| anyhow!("provider {provider_id} was not found"))?;
        let probe_target = config
            .cache_capability_probe_target(provider_id)
            .ok_or_else(|| anyhow!("provider {provider_id} was not found"))?;
        (provider, probe_target)
    };
    if !provider.enabled {
        return Err(anyhow!("provider {} is disabled", provider.name));
    }
    let probe_channel = requested_channel.unwrap_or_else(|| provider.channel.clone());
    if !matches!(probe_channel, Channel::Responses | Channel::Chat) {
        return Err(anyhow!(
            "native OpenAI cache capability verification requires a Chat or Responses provider"
        ));
    }
    let selected_key = match selected_key {
        Some(selected_key) => selected_key,
        None => select_provider_api_key(state, provider_id, None, None).await?,
    };
    if selected_key.secret.trim().is_empty() {
        return Err(anyhow!("provider API key is not configured"));
    }

    let nonce = Uuid::new_v4().simple().to_string();
    let baseline_body = cache_capability::baseline_probe_body(&probe_channel, model_id, &nonce);
    let baseline = send_provider_management_probe_request(
        state,
        &provider,
        &selected_key.secret,
        &probe_channel,
        &baseline_body,
        CACHE_CAPABILITY_PROBE_REQUEST_KIND,
    )
    .await?;
    let baseline_status = Some(baseline.status);
    let mut fields = Vec::with_capacity(ProviderCacheCapabilityField::ALL.len());
    if !is_successful_probe_response(&baseline) {
        let message = format!(
            "baseline request returned HTTP {}: {}",
            baseline.status,
            upstream_error_summary(&baseline.bytes)
        );
        fields.extend(ProviderCacheCapabilityField::ALL.into_iter().map(|field| {
            ProviderCacheCapabilityProbeFieldResult {
                field,
                status: ProviderCacheCapabilityStatus::Error,
                enabled: false,
                effect_status: ProviderCacheEffectStatus::Unverified,
                message: message.clone(),
                http_status: Some(baseline.status),
            }
        }));
    } else {
        for field in ProviderCacheCapabilityField::ALL {
            let body = cache_capability::field_probe_body(&probe_channel, model_id, &nonce, field);
            let response = send_provider_management_probe_request(
                state,
                &provider,
                &selected_key.secret,
                &probe_channel,
                &body,
                CACHE_CAPABILITY_PROBE_REQUEST_KIND,
            )
            .await?;
            let structured_summary = structured_upstream_error_summary(&response.bytes);
            let summary = structured_summary
                .clone()
                .unwrap_or_else(|| upstream_error_summary(&response.bytes));
            let status = if is_successful_probe_response(&response) {
                ProviderCacheCapabilityStatus::Verified
            } else if explicit_cache_field_rejection(
                response.status,
                structured_summary.as_deref(),
                field,
            ) {
                ProviderCacheCapabilityStatus::Unsupported
            } else {
                ProviderCacheCapabilityStatus::Error
            };
            let message = match status {
                ProviderCacheCapabilityStatus::Verified => {
                    format!("{} accepted by upstream", field.json_name())
                }
                ProviderCacheCapabilityStatus::Unsupported => {
                    format!("{} rejected by upstream: {}", field.json_name(), summary)
                }
                ProviderCacheCapabilityStatus::Error => format!(
                    "{} probe returned HTTP {} without field-specific rejection evidence: {}",
                    field.json_name(),
                    response.status,
                    summary
                ),
                ProviderCacheCapabilityStatus::Unverified => unreachable!(),
            };
            fields.push(ProviderCacheCapabilityProbeFieldResult {
                field,
                enabled: false,
                effect_status: ProviderCacheEffectStatus::Unverified,
                status,
                message,
                http_status: Some(response.status),
            });
        }
    }

    let persist_version = {
        let mut config = state.config.write().await;
        if config.cache_capability_probe_target(provider_id).as_ref() != Some(&probe_target) {
            return Err(anyhow!(
                "provider settings changed while cache capability verification was running; verify again"
            ));
        }
        for result in &fields {
            config.record_cache_capability_probe_for_key(
                provider_id,
                model_id,
                probe_channel.clone(),
                selected_key.key_id.as_deref(),
                result.field,
                result.status.clone(),
                (result.status != ProviderCacheCapabilityStatus::Verified)
                    .then(|| result.message.clone()),
            );
        }
        for result in &mut fields {
            if let Some(saved) = config.cache_capability_for_key(
                provider_id,
                model_id,
                &probe_channel,
                selected_key.key_id.as_deref(),
                result.field,
            ) {
                result.enabled = saved.enabled;
                result.effect_status = saved.effect_status.clone();
            }
        }
        state.publish_config_snapshot(&config)?
    };
    state.wait_for_config_snapshot(persist_version).await?;

    Ok(ProviderCacheCapabilityProbeResult {
        provider_id: provider_id.to_string(),
        model_id: model_id.to_string(),
        channel: probe_channel,
        key_id: selected_key.key_id,
        baseline_status,
        fields,
        checked_at: Utc::now(),
    })
}

fn explicit_cache_field_rejection(
    status: u16,
    summary: Option<&str>,
    field: ProviderCacheCapabilityField,
) -> bool {
    if !matches!(status, 400 | 422) && !(200..300).contains(&status) {
        return false;
    }
    summary.is_some_and(|summary| cache_field_rejection_signal(summary, field))
}

fn cache_field_rejection_signal(summary: &str, field: ProviderCacheCapabilityField) -> bool {
    let lower = summary.to_ascii_lowercase();
    lower.contains(field.json_name())
        && [
            "unsupported",
            "not supported",
            "unknown",
            "unrecognized",
            "not permitted",
            "extra inputs are not permitted",
            "invalid parameter",
            "invalid_request",
        ]
        .iter()
        .any(|marker| lower.contains(marker))
}

async fn note_runtime_cache_capability_rejection(
    state: &AppState,
    decision: &RouteDecision,
    active_channel: &Channel,
    diagnostics: &UpstreamRequestDiagnostics,
    status: u16,
    error_summary: &str,
) {
    let rejected = diagnostics
        .sent_cache_capability_fields
        .iter()
        .copied()
        .filter(|field| explicit_cache_field_rejection(status, Some(error_summary), *field))
        .collect::<Vec<_>>();
    if rejected.is_empty() {
        return;
    }

    let mut config = state.config.write().await;
    let mut changed = false;
    for field in rejected {
        if config.cache_capability_status_for_key(
            &decision.provider.id,
            &decision.model,
            active_channel,
            diagnostics.cache_capability_key_id.as_deref(),
            field,
        ) == ProviderCacheCapabilityStatus::Unsupported
        {
            continue;
        }
        config.record_cache_capability_probe_for_key(
            &decision.provider.id,
            &decision.model,
            active_channel.clone(),
            diagnostics.cache_capability_key_id.as_deref(),
            field,
            ProviderCacheCapabilityStatus::Unsupported,
            Some(format!(
                "runtime rejection: {}",
                truncate_log_message(error_summary)
            )),
        );
        changed = true;
    }
    if changed {
        state.journal_config(&config);
    }
}

pub(crate) async fn probe_provider_response_session_reuse(
    state: &AppState,
    provider_id: &str,
    model_id: &str,
) -> Result<ProviderResponseSessionReuseProbeResult> {
    let model_id = model_id.trim();
    if model_id.is_empty() {
        return Err(anyhow!(
            "an actual upstream model id is required for verification"
        ));
    }
    let provider = {
        let config = state.config.read().await;
        config
            .providers
            .iter()
            .find(|provider| provider.id == provider_id)
            .cloned()
            .ok_or_else(|| anyhow!("provider {provider_id} was not found"))?
    };
    if !provider.enabled {
        return Err(anyhow!("provider {} is disabled", provider.name));
    }
    let selected_key = select_provider_api_key(state, provider_id, None, None).await?;
    if selected_key.secret.trim().is_empty() {
        return Err(anyhow!("provider API key is not configured"));
    }

    let nonce = format!("ato-session-{}", Uuid::new_v4().simple());
    let stable_prefix = "Atoapi response-session cache verification stable context. ".repeat(192);
    let seed_body = json!({
        "model": model_id,
        "input": format!(
            "{stable_prefix}\nRemember the exact token {nonce}. Reply only ACK."
        ),
        "store": true,
        "stream": false,
        "max_output_tokens": 32,
    });
    let first = send_response_session_reuse_probe_request(
        state,
        &provider,
        &selected_key.secret,
        &seed_body,
    )
    .await?;
    if !is_successful_probe_response(&first) {
        return Ok(response_session_reuse_probe_result(
            provider_id,
            model_id,
            probe_status_for_failure(first.status, &first.bytes),
            format!(
                "seed request returned HTTP {}: {}",
                first.status,
                upstream_error_summary(&first.bytes)
            ),
            Some(first.status),
            None,
        ));
    }
    let first_usage = provider_usage_from_bytes(&first.bytes);
    let Some(previous_response_id) = response_id_from_bytes(&first.bytes) else {
        return Ok(response_session_reuse_probe_result(
            provider_id,
            model_id,
            ProviderResponseSessionReuseStatus::Unsupported,
            "seed response did not include a reusable response id".to_string(),
            Some(first.status),
            None,
        ));
    };

    let continuation_body = json!({
        "model": model_id,
        "previous_response_id": previous_response_id,
        "input": "Return only the exact verification token from the immediately previous turn.",
        "store": true,
        "stream": false,
        "max_output_tokens": 32,
    });
    let continuation = send_response_session_reuse_probe_request(
        state,
        &provider,
        &selected_key.secret,
        &continuation_body,
    )
    .await?;
    if !is_successful_probe_response(&continuation) {
        return Ok(response_session_reuse_probe_result(
            provider_id,
            model_id,
            probe_status_for_failure(continuation.status, &continuation.bytes),
            format!(
                "continuation returned HTTP {}: {}",
                continuation.status,
                upstream_error_summary(&continuation.bytes)
            ),
            Some(first.status),
            Some(continuation.status),
        ));
    }
    let continuation_usage = provider_usage_from_bytes(&continuation.bytes);
    let output = serde_json::from_slice::<Value>(&continuation.bytes)
        .ok()
        .and_then(|value| extract_response_text(&value))
        .unwrap_or_default();
    if !output
        .to_ascii_lowercase()
        .contains(&nonce.to_ascii_lowercase())
    {
        return Ok(with_response_session_probe_usage(
            response_session_reuse_probe_result(
                provider_id,
                model_id,
                ProviderResponseSessionReuseStatus::Unsupported,
                "continuation succeeded but did not preserve the verification token".to_string(),
                Some(first.status),
                Some(continuation.status),
            ),
            &first_usage,
            &continuation_usage,
            false,
        ));
    }

    if let Some(message) = response_session_probe_usage_error(&first_usage, &continuation_usage) {
        Ok(with_response_session_probe_usage(
            response_session_reuse_probe_result(
                provider_id,
                model_id,
                ProviderResponseSessionReuseStatus::Unverified,
                message.to_string(),
                Some(first.status),
                Some(continuation.status),
            ),
            &first_usage,
            &continuation_usage,
            false,
        ))
    } else {
        Ok(with_response_session_probe_usage(
            response_session_reuse_probe_result(
                provider_id,
                model_id,
                ProviderResponseSessionReuseStatus::Verified,
                format!(
                    "verification passed; semantic continuation and cached-token usage were preserved (seed input {}, continuation input {}, cached {})",
                    first_usage.input_tokens,
                    continuation_usage.input_tokens,
                    continuation_usage.cache_read_tokens
                ),
                Some(first.status),
                Some(continuation.status),
            ),
            &first_usage,
            &continuation_usage,
            true,
        ))
    }
}

fn response_session_probe_usage_error(
    first: &UsageRecord,
    continuation: &UsageRecord,
) -> Option<&'static str> {
    if first.input_tokens == 0 {
        return Some("semantic continuation succeeded but the seed response did not report input usage; session reuse remains disabled");
    }
    if continuation.input_tokens == 0 {
        return Some("semantic continuation succeeded but the continuation did not report input usage; session reuse remains disabled");
    }
    if continuation.input_tokens < first.input_tokens {
        return Some("semantic continuation succeeded but continuation usage did not include the seed context; session reuse remains disabled");
    }
    if continuation.cache_read_tokens < PROVIDER_CACHE_MIN_BUCKET_TOKENS {
        return Some("semantic continuation succeeded but the continuation did not report one full 128-token cache bucket; no cache benefit was verified");
    }
    None
}

fn with_response_session_probe_usage(
    mut result: ProviderResponseSessionReuseProbeResult,
    first: &UsageRecord,
    continuation: &UsageRecord,
    usage_verified: bool,
) -> ProviderResponseSessionReuseProbeResult {
    result.first_input_tokens = (first.input_tokens > 0).then_some(first.input_tokens);
    result.first_cached_tokens = (first.input_tokens > 0).then_some(first.cache_read_tokens);
    result.continuation_input_tokens =
        (continuation.input_tokens > 0).then_some(continuation.input_tokens);
    result.continuation_cached_tokens =
        (continuation.input_tokens > 0).then_some(continuation.cache_read_tokens);
    result.usage_verified = usage_verified;
    result
}

pub(crate) async fn probe_provider_responses_websocket(
    state: &AppState,
    provider_id: &str,
    model_id: &str,
) -> Result<responses_websocket_probe::ResponsesWebSocketProbeResult> {
    let provider_id = provider_id.trim();
    let model_id = model_id.trim();
    if provider_id.is_empty() || model_id.is_empty() {
        return Err(anyhow!(
            "provider and actual upstream model are required for WebSocket verification"
        ));
    }
    let provider = {
        let config = state.config.read().await;
        config
            .providers
            .iter()
            .find(|provider| provider.id == provider_id)
            .cloned()
            .ok_or_else(|| anyhow!("provider {provider_id} was not found"))?
    };
    if !provider.enabled {
        return Err(anyhow!("provider {} is disabled", provider.name));
    }
    let selected_key = select_provider_api_key(state, provider_id, None, None).await?;
    if selected_key.secret.trim().is_empty() {
        return Err(anyhow!("provider API key is not configured"));
    }

    Ok(responses_websocket_probe::probe_responses_websocket(
        responses_websocket_probe::ResponsesWebSocketProbeTarget {
            provider_id: provider.id.clone(),
            model_id: model_id.to_string(),
            responses_url: upstream_url(&provider.base_url, &Channel::Responses),
            api_key: selected_key.secret,
            use_system_proxy: provider.use_system_proxy,
            custom_user_agent: provider.custom_user_agent.clone(),
        },
    )
    .await)
}

pub(crate) async fn probe_and_record_provider_response_session_reuse(
    state: &AppState,
    provider_id: &str,
    model_id: &str,
) -> Result<ProviderResponseSessionReuseProbeResult> {
    let provider_id = provider_id.trim();
    let model_id = model_id.trim();
    if provider_id.is_empty() || model_id.is_empty() {
        return Err(anyhow!(
            "provider and actual upstream model are required for verification"
        ));
    }
    let (probe_target, probe_record_snapshot) = {
        let config = state.config.read().await;
        (
            config
                .response_session_reuse_probe_target(provider_id)
                .ok_or_else(|| anyhow!("provider {provider_id} was not found"))?,
            config.response_session_reuse_record_snapshot(provider_id, model_id),
        )
    };

    let mut result = match probe_provider_response_session_reuse(state, provider_id, model_id).await
    {
        Ok(result) => result,
        Err(err) => response_session_reuse_probe_result(
            provider_id,
            model_id,
            ProviderResponseSessionReuseStatus::Error,
            err.to_string(),
            None,
            None,
        ),
    };

    let persist_version = {
        let mut config = state.config.write().await;
        if config
            .response_session_reuse_probe_target(provider_id)
            .as_ref()
            != Some(&probe_target)
            || config.response_session_reuse_record_snapshot(provider_id, model_id)
                != probe_record_snapshot
        {
            result.status = ProviderResponseSessionReuseStatus::Error;
            result.enabled = false;
            result.usage_verified = false;
            result.message = "Provider settings or session-reuse preference changed while compatibility verification was running; verify again."
                .to_string();
            result.checked_at = Some(Utc::now());
            return Ok(result);
        }
        config.record_response_session_reuse_probe(
            provider_id,
            model_id,
            result.status.clone(),
            result.usage_verified,
            (!matches!(&result.status, ProviderResponseSessionReuseStatus::Verified))
                .then(|| result.message.clone()),
        );
        state.publish_config_snapshot(&config)?
    };
    state.wait_for_config_snapshot(persist_version).await?;
    result.checked_at = Some(Utc::now());
    Ok(result)
}

async fn send_response_session_reuse_probe_request(
    state: &AppState,
    provider: &ProviderConfig,
    api_key: &str,
    body: &Value,
) -> Result<ResponseSessionReuseProbeResponse> {
    send_provider_management_probe_request(
        state,
        provider,
        api_key,
        &Channel::Responses,
        body,
        RESPONSE_SESSION_PROBE_REQUEST_KIND,
    )
    .await
}

async fn send_provider_management_probe_request(
    state: &AppState,
    provider: &ProviderConfig,
    api_key: &str,
    channel: &Channel,
    body: &Value,
    request_kind: &'static str,
) -> Result<ResponseSessionReuseProbeResponse> {
    let started = Instant::now();
    let mut management_headers = HeaderMap::new();
    management_headers.insert(
        X_ATOAPI_REQUEST_KIND_HEADER,
        HeaderValue::from_static(request_kind),
    );
    let plan = RequestPlan::new(
        provider,
        upstream_url(&provider.base_url, channel),
        channel.clone(),
        body,
    )
    .with_gzip_enabled(false);
    let outcome =
        send_main_upstream_request(state, api_key, plan.into_one_shot(), &management_headers)
            .await?;
    let status = outcome.response.status().as_u16();
    let content_type = outcome
        .response
        .headers()
        .get(header::CONTENT_TYPE)
        .and_then(|value| value.to_str().ok())
        .unwrap_or("application/json")
        .to_string();
    let headers_at_ms = started.elapsed().as_millis() as u64;
    let body = read_upstream_body_with_diagnostics(
        outcome.response,
        &content_type,
        started,
        headers_at_ms,
    )
    .await?;
    Ok(ResponseSessionReuseProbeResponse {
        status,
        content_type,
        bytes: body.bytes,
    })
}

fn is_successful_probe_response(response: &ResponseSessionReuseProbeResponse) -> bool {
    (200..300).contains(&response.status)
        && !upstream_body_has_error(&response.bytes, &response.content_type)
}

fn probe_status_for_failure(status: u16, bytes: &[u8]) -> ProviderResponseSessionReuseStatus {
    if response_session_rejection_classification(status, &upstream_error_summary(bytes))
        == ResponseSessionRejectionClass::Unsupported
    {
        ProviderResponseSessionReuseStatus::Unsupported
    } else {
        ProviderResponseSessionReuseStatus::Error
    }
}

fn response_session_reuse_probe_result(
    provider_id: &str,
    model_id: &str,
    status: ProviderResponseSessionReuseStatus,
    message: String,
    first_status: Option<u16>,
    continuation_status: Option<u16>,
) -> ProviderResponseSessionReuseProbeResult {
    ProviderResponseSessionReuseProbeResult {
        provider_id: provider_id.to_string(),
        model_id: model_id.to_string(),
        enabled: status == ProviderResponseSessionReuseStatus::Verified,
        status,
        message,
        checked_at: Some(Utc::now()),
        first_status,
        continuation_status,
        first_input_tokens: None,
        first_cached_tokens: None,
        continuation_input_tokens: None,
        continuation_cached_tokens: None,
        usage_verified: false,
    }
}

fn build_upstream_request_headers(
    inbound_headers: &HeaderMap,
    api_key: &str,
    channel: &Channel,
    stream: bool,
    custom_user_agent: Option<&str>,
    content_encoding_gzip: bool,
) -> HeaderMap {
    let mut outbound = HeaderMap::new();
    for (name, value) in inbound_headers {
        let name_text = name.as_str();
        if upstream_header_is_blocked(name_text)
            || name == header::CONTENT_TYPE
            || name == header::CONTENT_ENCODING
            || name == header::ACCEPT_ENCODING
            || name == header::USER_AGENT
        {
            continue;
        }
        outbound.append(name.clone(), value.clone());
    }

    outbound.insert(
        header::CONTENT_TYPE,
        HeaderValue::from_static("application/json"),
    );
    if let Ok(value) = HeaderValue::from_str(&format!("Bearer {api_key}")) {
        outbound.insert(header::AUTHORIZATION, value);
    }
    if let Ok(value) = HeaderValue::from_str(api_key) {
        outbound.insert("x-api-key", value);
    }
    let user_agent = custom_user_agent
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .and_then(|value| HeaderValue::from_str(value).ok())
        .unwrap_or_else(|| HeaderValue::from_static(crate::ATOAPI_USER_AGENT));
    outbound.insert(header::USER_AGENT, user_agent);
    if stream {
        outbound.insert(
            header::ACCEPT,
            HeaderValue::from_static("text/event-stream"),
        );
    }
    outbound.insert(
        header::ACCEPT_ENCODING,
        HeaderValue::from_static("identity"),
    );
    if content_encoding_gzip {
        outbound.insert(header::CONTENT_ENCODING, HeaderValue::from_static("gzip"));
    }
    if matches!(channel, Channel::Anthropic) && !outbound.contains_key("anthropic-version") {
        outbound.insert("anthropic-version", HeaderValue::from_static("2023-06-01"));
    }
    outbound
}

fn upstream_header_is_blocked(name: &str) -> bool {
    matches!(
        name,
        "host"
            | "content-length"
            | "transfer-encoding"
            | "connection"
            | "keep-alive"
            | "proxy-authenticate"
            | "proxy-authorization"
            | "te"
            | "trailer"
            | "upgrade"
            | "authorization"
            | "x-api-key"
            | "x-goog-api-key"
            | "forwarded"
            | "x-forwarded-for"
            | "x-forwarded-host"
            | "x-forwarded-port"
            | "x-forwarded-proto"
            | "cf-connecting-ip"
            | "cf-ipcountry"
            | "cf-ray"
            | "cf-visitor"
            | "true-client-ip"
            | "fastly-client-ip"
            | "x-azure-clientip"
            | "x-azure-fdid"
            | "x-azure-ref"
            | "akamai-origin-hop"
            | "x-akamai-config-log-detail"
            | "x-request-id"
            | "x-correlation-id"
            | "x-trace-id"
            | "x-amzn-trace-id"
            | "x-b3-traceid"
            | "x-b3-spanid"
            | "x-b3-parentspanid"
            | "x-b3-sampled"
            | "b3"
            | "traceparent"
            | "tracestate"
            | X_CODEX_TURN_METADATA_HEADER
    ) || name.starts_with("x-forwarded-")
        || name.starts_with("cf-")
        || name.starts_with("x-b3-")
}

async fn dispatch_prepared_one_shot_with_diagnostics(
    state: &AppState,
    api_key: &str,
    plan: OneShotRequestPlan,
    inbound_headers: &HeaderMap,
    agent_attempt: Option<AgentAttemptDispatch>,
) -> Result<UpstreamSendOutcome> {
    let agent_transport = agent_attempt.is_some();
    let prepared = plan.wire();
    let channel = plan.channel();
    let url = plan.url();
    let outbound_prefix_fingerprints = prepared.outbound_prefix_fingerprints().cloned();
    let original_body = prepared.body().clone();
    let request_body_encode_ms = prepared.encode_ms();
    let original_body_len = original_body.len() as u64;
    let gzip_cooldown_key = request_body_gzip_cooldown_key(url, channel);
    let gzip_cooldown_active = plan.request_body_gzip_enabled()
        && request_body_gzip_cooldown_active(state, &gzip_cooldown_key).await;
    let gzip_threshold = request_body_gzip_threshold_bytes(channel);
    let use_gzip = plan.request_body_gzip_enabled()
        && !gzip_cooldown_active
        && original_body.len() >= gzip_threshold;
    let (compressed_body, gzip_encode_ms) = if use_gzip {
        if let Some(body) = prepared.cached_gzip_body() {
            (Some(body), 0)
        } else {
            let gzip_encode_started = Instant::now();
            let body = gzip_request_body(&original_body)
                .ok()
                .map(Bytes::from)
                .map(|body| prepared.cache_gzip_body(body));
            (body, gzip_encode_started.elapsed().as_millis() as u64)
        }
    } else {
        (None, 0)
    };
    let mut diagnostics = UpstreamRequestDiagnostics {
        network_path: if plan.use_system_proxy() {
            "system-proxy"
        } else {
            "direct"
        },
        request_body_bytes: original_body_len,
        request_body_encode_ms,
        gzip_encode_ms,
        gzip_attempted: compressed_body.is_some(),
        sent_body_bytes: compressed_body
            .as_ref()
            .map(|body| body.len() as u64)
            .unwrap_or(original_body_len),
        outbound_prefix_fingerprints,
        ..UpstreamRequestDiagnostics::default()
    };
    diagnostics.attempts = 1;
    let sending_gzip = compressed_body.is_some();
    let outbound_headers = build_upstream_request_headers(
        inbound_headers,
        api_key,
        channel,
        prepared.is_stream(),
        plan.custom_user_agent(),
        sending_gzip,
    );
    let client = if agent_transport {
        state
            .transport_clients
            .agent_client(plan.use_system_proxy())
    } else {
        state.upstream_client(plan.use_system_proxy())
    };
    let request_body = compressed_body.unwrap_or(original_body);
    let request = client
        .post(url)
        .headers(outbound_headers)
        .body(request_body);

    if let Some(dispatch) = agent_attempt {
        let began = begin_agent_upstream_attempt(
            state,
            &dispatch.token,
            &dispatch.provider,
            &dispatch.model,
            channel,
        )
        .await;
        if !began {
            return Err(anyhow!(
                "Agent attempt {} was not authorized for upstream dispatch",
                dispatch.token.attempt_id()
            ));
        }
    }
    let send_started = Instant::now();
    match request.send().await {
        Ok(response) => {
            let headers_ms = send_started.elapsed().as_millis() as u64;
            diagnostics.headers_ms = headers_ms;
            observe_upstream_response_timing(&mut diagnostics, &response, headers_ms);
            // Do not retry an incompatible gzip request. Learn that state for
            // the next independent inbound and preserve this original result.
            if sending_gzip && should_retry_without_gzip(response.status()) {
                note_request_body_gzip_fallback(state, &gzip_cooldown_key).await;
            }
            Ok(UpstreamSendOutcome {
                response,
                diagnostics,
            })
        }
        Err(err) => {
            let headers_ms = send_started.elapsed().as_millis() as u64;
            diagnostics.headers_ms = headers_ms;
            diagnostics.last_attempt_headers_ms = headers_ms;
            diagnostics.http_version = None;
            diagnostics.remote_addr = None;
            diagnostics.pool_diagnostic = None;
            diagnostics.server_timing = None;
            diagnostics.timing_source = None;
            diagnostics.reported_processing_ms = None;
            diagnostics.non_processing_ms = None;
            Err(err.into())
        }
    }
}

async fn read_upstream_body_with_diagnostics(
    upstream: reqwest::Response,
    content_type: &str,
    started: Instant,
    headers_at_ms: u64,
) -> reqwest::Result<UpstreamBodyReadOutcome> {
    if is_text_event_stream(content_type) {
        let mut stream = upstream.bytes_stream();
        let mut body = Vec::new();
        let mut first_chunk_at_ms = None;
        let mut chunks = 0u64;
        while let Some(chunk) = stream.next().await {
            let chunk = chunk?;
            if first_chunk_at_ms.is_none() {
                first_chunk_at_ms = Some(started.elapsed().as_millis() as u64);
            }
            chunks += 1;
            body.extend_from_slice(&chunk);
        }
        let aggregate_done_ms = started.elapsed().as_millis() as u64;
        Ok(UpstreamBodyReadOutcome {
            bytes: body,
            first_chunk_ms: first_chunk_at_ms.map(|at| at.saturating_sub(headers_at_ms)),
            aggregate_done_ms,
            sse_chunks: Some(chunks),
        })
    } else {
        let bytes = upstream.bytes().await?.to_vec();
        Ok(UpstreamBodyReadOutcome {
            bytes,
            first_chunk_ms: None,
            aggregate_done_ms: started.elapsed().as_millis() as u64,
            sse_chunks: None,
        })
    }
}

fn responses_wire_prefix_fingerprints(
    channel: &Channel,
    body: &Value,
) -> Option<ResponsesWirePrefixFingerprints> {
    if !matches!(channel, Channel::Responses) {
        return None;
    }

    let pre_input_wire = responses_wire_pre_input(body);
    let input = body.get("input").cloned().unwrap_or(Value::Null);
    let (input_history, input_full, input_item_count, input_prefixes) =
        responses_wire_input_fingerprints(&input);

    Some(ResponsesWirePrefixFingerprints {
        version: 2,
        cache_metadata: truncated_wire_segment_hash(
            "cache_metadata",
            responses_wire_selected_members(
                body,
                &[
                    "prompt_cache_key",
                    "prompt_cache_retention",
                    "prompt_cache_options",
                ],
            )
            .as_bytes(),
        ),
        instructions: truncated_wire_segment_hash(
            "instructions",
            responses_wire_selected_members(body, &["instructions"]).as_bytes(),
        ),
        tools_schema: truncated_wire_segment_hash(
            "tools_schema",
            responses_wire_selected_members(
                body,
                &[
                    "tools",
                    "tool_choice",
                    "parallel_tool_calls",
                    "text",
                    "response_format",
                ],
            )
            .as_bytes(),
        ),
        input_history,
        input_full,
        input_item_count,
        input_prefixes,
        pre_input_wire: truncated_wire_segment_hash("pre_input_wire", pre_input_wire.as_bytes()),
    })
}

fn maybe_responses_wire_prefix_fingerprints(
    channel: &Channel,
    body: &Value,
) -> Option<ResponsesWirePrefixFingerprints> {
    if !prefix_diagnostics_enabled() {
        return None;
    }
    responses_wire_prefix_fingerprints(channel, body)
}

fn prefix_diagnostics_enabled() -> bool {
    static ENABLED: OnceLock<bool> = OnceLock::new();
    *ENABLED.get_or_init(|| {
        std::env::var(PREFIX_DIAGNOSTICS_ENV)
            .ok()
            .is_some_and(|value| prefix_diagnostics_enabled_value(Some(&value)))
    })
}

fn prefix_diagnostics_enabled_value(value: Option<&str>) -> bool {
    value.is_some_and(|value| matches!(value.trim(), "1" | "true" | "on" | "enabled"))
}

fn responses_wire_input_fingerprints(input: &Value) -> (String, String, u64, Vec<String>) {
    const PREFIX_WINDOW: usize = 32;

    let Value::Array(items) = input else {
        return (
            truncated_wire_segment_hash("input", b"null"),
            truncated_wire_segment_hash(
                "input",
                serde_json::to_string(input)
                    .unwrap_or_else(|_| "null".to_string())
                    .as_bytes(),
            ),
            0,
            Vec::new(),
        );
    };

    let mut hasher = wire_segment_hasher("input");
    hasher.update(b"[");
    let mut prefixes = Vec::with_capacity(items.len().min(PREFIX_WINDOW));
    for (index, item) in items.iter().enumerate() {
        let mut prefix_hasher = hasher.clone();
        prefix_hasher.update(b"]");
        if prefixes.len() == PREFIX_WINDOW {
            prefixes.remove(0);
        }
        prefixes.push(truncated_wire_segment_digest(prefix_hasher));
        if index > 0 {
            hasher.update(b",");
        }
        hasher.update(serde_json::to_vec(item).unwrap_or_else(|_| b"null".to_vec()));
    }
    hasher.update(b"]");
    let input_full = truncated_wire_segment_digest(hasher);
    let input_history = prefixes
        .last()
        .cloned()
        .unwrap_or_else(|| input_full.clone());
    (input_history, input_full, items.len() as u64, prefixes)
}

fn responses_wire_selected_members(body: &Value, keys: &[&str]) -> String {
    let Some(object) = body.as_object() else {
        return "null".to_string();
    };
    let members = keys
        .iter()
        .filter_map(|key| object.get(*key).map(|value| format_json_member(key, value)))
        .collect::<Vec<_>>();
    format!("{{{}}}", members.join(","))
}

fn responses_wire_pre_input(body: &Value) -> String {
    let Some(object) = body.as_object() else {
        return "null".to_string();
    };
    let members = [
        "model",
        "prompt_cache_key",
        "prompt_cache_retention",
        "prompt_cache_options",
        "instructions",
        "tools",
        "tool_choice",
        "parallel_tool_calls",
    ]
    .iter()
    .filter_map(|key| object.get(*key).map(|value| format_json_member(key, value)))
    .collect::<Vec<_>>();
    let mut prefix = format!("{{{}", members.join(","));
    if object.contains_key("input") && !members.is_empty() {
        prefix.push(',');
    }
    prefix
}

fn truncated_wire_segment_hash(label: &str, bytes: &[u8]) -> String {
    let mut hasher = wire_segment_hasher(label);
    hasher.update(bytes);
    truncated_wire_segment_digest(hasher)
}

fn wire_segment_hasher(label: &str) -> Sha256 {
    let mut hasher = Sha256::new();
    hasher.update(label.as_bytes());
    hasher.update(b"\0");
    hasher
}

fn truncated_wire_segment_digest(hasher: Sha256) -> String {
    let digest = format!("{:x}", hasher.finalize());
    format!("sha256-128:{}", &digest[..32])
}

fn serialize_responses_body_for_provider_prefix(body: &Value) -> String {
    String::from_utf8(serialize_responses_body_bytes_for_provider_prefix(body))
        .unwrap_or_else(|_| "null".to_string())
}

#[cfg(test)]
fn legacy_serialize_responses_body_for_provider_prefix(body: &Value) -> String {
    let Some(map) = body.as_object() else {
        return serde_json::to_string(body).unwrap_or_else(|_| "null".to_string());
    };

    let mut parts = Vec::with_capacity(map.len());
    for key in RESPONSES_WIRE_ORDERED_KEYS {
        if let Some(value) = map.get(key) {
            parts.push(format_json_member(key, value));
        }
    }
    let mut remaining = map
        .keys()
        .filter(|key| !RESPONSES_WIRE_ORDERED_KEYS.contains(&key.as_str()))
        .collect::<Vec<_>>();
    remaining.sort();
    for key in remaining {
        if let Some(value) = map.get(key) {
            parts.push(format_json_member(key, value));
        }
    }
    format!("{{{}}}", parts.join(","))
}

fn serialize_chat_body_for_provider_prefix(body: &Value) -> String {
    const ORDERED_KEYS: [&str; 21] = [
        "model",
        "prompt_cache_key",
        "prompt_cache_retention",
        "prompt_cache_options",
        "messages",
        "tools",
        "tool_choice",
        "parallel_tool_calls",
        "response_format",
        "max_tokens",
        "max_completion_tokens",
        "temperature",
        "top_p",
        "seed",
        "presence_penalty",
        "frequency_penalty",
        "logit_bias",
        "stop",
        "stream",
        "store",
        "service_tier",
    ];

    let Some(map) = body.as_object() else {
        return serde_json::to_string(body).unwrap_or_else(|_| "null".to_string());
    };

    let mut parts = Vec::with_capacity(map.len());
    for key in ORDERED_KEYS {
        if let Some(value) = map.get(key) {
            parts.push(format_json_member(key, value));
        }
    }

    let mut remaining = map
        .keys()
        .filter(|key| !ORDERED_KEYS.contains(&key.as_str()))
        .collect::<Vec<_>>();
    remaining.sort();
    for key in remaining {
        if let Some(value) = map.get(key) {
            parts.push(format_json_member(key, value));
        }
    }

    format!("{{{}}}", parts.join(","))
}

fn format_json_member(key: &str, value: &Value) -> String {
    let key = serde_json::to_string(key).unwrap_or_else(|_| "\"\"".to_string());
    let value = serde_json::to_string(value).unwrap_or_else(|_| "null".to_string());
    format!("{key}:{value}")
}

async fn stream_upstream(
    state: Arc<AppState>,
    upstream: reqwest::Response,
    content_type: String,
    status: u16,
    started: Instant,
    request_id: String,
    client_channel: Channel,
    decision: RouteDecision,
    eligible: bool,
    cache_keys: Vec<String>,
    metrics_cache_key: String,
    semantic_text: Option<String>,
    semantic_shape: Option<String>,
    provider_prefix_key: Option<String>,
    provider_prefix_fingerprint: Option<String>,
    provider_prefix_family_key: Option<String>,
    route_affinity_key: Option<String>,
    config: AppConfig,
    _prefix_guard: Option<tokio::sync::OwnedMutexGuard<()>>,
    prefix_state_key: Option<String>,
    _response_session_guard: Option<tokio::sync::OwnedMutexGuard<()>>,
    response_session_key: Option<String>,
    response_session_scope_key: Option<String>,
    full_response_input: Option<Value>,
    used_response_session: bool,
    retried_full_response: bool,
    diagnostics: BodyDiagnostics,
    tail_input_diagnostics: TailInputDiagnostics,
    session_anchor_diagnostics: SessionAnchorDiagnostics,
    response_session_reuse_diagnostics: ResponseSessionReuseDiagnostics,
    cross_protocol_tool_context: Option<transform_codex_chat::CodexToolContext>,
    agent_log_id: Option<String>,
    agent_log_label: Option<String>,
    requested_model: Option<String>,
    prefix_guard_wait: PrefixGuardWaitDiagnostics,
    local_prepare_ms: u64,
    upstream_request_diagnostics: UpstreamRequestDiagnostics,
    upstream_response_headers_at_ms: u64,
    agent_attempt_id: Option<String>,
    mut shadow_affinity_decision: Option<ShadowAffinityDecision>,
    agent_generation: bool,
    response_handoff: Option<cache_directed_relay::DispatchHandoff<Response>>,
) -> Response {
    // Streaming must behave like a normal proxy: do not hold prefix/session locks
    // for the whole SSE response. The guarded section has already covered request
    // preparation and send; holding it through output serializes unrelated turns
    // and inflates TTFT/total time.
    drop(_prefix_guard);
    drop(_response_session_guard);

    let convert_codex_chat_sse_to_responses_sse = matches!(client_channel, Channel::Responses)
        && matches!(decision.upstream_channel, Channel::Chat);
    let convert_anthropic_sse_to_responses_sse = matches!(client_channel, Channel::Responses)
        && matches!(decision.upstream_channel, Channel::Anthropic);
    let convert_anthropic_sse_to_chat_sse = matches!(client_channel, Channel::Chat)
        && matches!(decision.upstream_channel, Channel::Anthropic);
    let convert_chat_sse_to_anthropic_sse = matches!(client_channel, Channel::Anthropic)
        && matches!(decision.upstream_channel, Channel::Chat);
    let convert_responses_sse_to_chat_sse = matches!(client_channel, Channel::Chat)
        && matches!(decision.upstream_channel, Channel::Responses);
    let convert_responses_sse_to_anthropic_sse = matches!(client_channel, Channel::Anthropic)
        && matches!(decision.upstream_channel, Channel::Responses);
    let response_content_type = if convert_codex_chat_sse_to_responses_sse
        || convert_anthropic_sse_to_responses_sse
        || convert_anthropic_sse_to_chat_sse
        || convert_chat_sse_to_anthropic_sse
        || convert_responses_sse_to_chat_sse
        || convert_responses_sse_to_anthropic_sse
    {
        "text/event-stream".to_string()
    } else {
        content_type.clone()
    };
    let content_type_for_cache = response_content_type.clone();
    let (downstream_sender, mut downstream_receiver) =
        mpsc::channel::<Result<RelayBodyChunk, std::io::Error>>(STREAM_RELAY_CHANNEL_CAPACITY);
    let downstream_byte_budget = Arc::new(Semaphore::new(STREAM_RELAY_BYTE_BUDGET));
    let relay_tracker = state.relay_tasks.clone();
    let relay_reservation = if response_handoff.is_none() {
        match relay_tracker.reserve() {
            Ok(reservation) => Some(reservation),
            Err(_) => {
                // The upstream response head already exists, but no relay may
                // expose it after shutdown has stopped accepting owners. Record
                // the failed inbound before returning a local 503.
                let admission_body = json!({ "stream": true });
                record_upstream_transport_failure(
                    &state,
                    &request_id,
                    &started,
                    &client_channel,
                    &decision.upstream_channel,
                    &decision,
                    eligible.then_some(metrics_cache_key.as_str()),
                    provider_prefix_key.as_deref(),
                    provider_prefix_fingerprint.as_deref(),
                    &prefix_guard_wait,
                    local_prepare_ms,
                    &diagnostics,
                    &admission_body,
                    used_response_session,
                    &response_session_reuse_diagnostics,
                    requested_model.clone(),
                    agent_log_id.as_deref(),
                    "stream-relay-admission",
                    upstream_request_diagnostics.attempts,
                    &[],
                    "stream_relay_admission",
                    "proxy relay is shutting down",
                )
                .await;
                return json_error(
                    StatusCode::SERVICE_UNAVAILABLE,
                    "proxy relay is shutting down",
                );
            }
        }
    } else {
        None
    };

    let relay = async move {
        let raw_stream = upstream.bytes_stream();
        let mut responses_to_chat_stream_summary = None;
        let mut responses_to_anthropic_stream_summary = None;
        let mut chat_to_anthropic_stream_summary = None;
        let mut stream: Pin<Box<dyn Stream<Item = Result<Bytes, String>> + Send>> =
            if convert_codex_chat_sse_to_responses_sse {
                let tool_context = cross_protocol_tool_context.clone().unwrap_or_default();
                Box::pin(
                    streaming_codex_chat::create_responses_sse_stream_from_chat_with_context_and_model(
                        raw_stream,
                        tool_context,
                        decision.model.clone(),
                    )
                    .map(|item| item.map_err(|err| err.to_string())),
                )
            } else if convert_anthropic_sse_to_responses_sse {
                let context = streaming_codex_anthropic::AnthropicResponsesContext {
                    tool_context: cross_protocol_tool_context.unwrap_or_default(),
                };
                Box::pin(
                    streaming_codex_anthropic::create_responses_sse_stream_from_anthropic(
                        raw_stream,
                        context,
                        decision.model.clone(),
                    )
                    .map(|item| item.map_err(|err| err.to_string())),
                )
            } else if convert_anthropic_sse_to_chat_sse {
                // Keep the raw Anthropic stream pull-based: the existing
                // Anthropic→Responses and Responses→Chat adapters compose
                // without collecting the body, so the first Chat delta can
                // leave the owner relay before `message_stop`.
                let intermediate =
                    streaming_codex_anthropic::create_responses_sse_stream_from_anthropic(
                        raw_stream,
                        streaming_codex_anthropic::AnthropicResponsesContext {
                            tool_context: transform_codex_chat::CodexToolContext::default(),
                        },
                        decision.model.clone(),
                    );
                let (adapted, summary) =
                    streaming_responses_chat::create_chat_sse_stream_from_responses(
                        intermediate,
                        decision.model.clone(),
                        diagnostics.chat_stream_include_usage,
                    );
                responses_to_chat_stream_summary = Some(summary);
                Box::pin(adapted.map(|item| item.map_err(|err| err.to_string())))
            } else if convert_chat_sse_to_anthropic_sse {
                let (adapted, summary) =
                    streaming_chat_anthropic::create_anthropic_sse_stream_from_chat(
                        raw_stream,
                        decision.model.clone(),
                    );
                chat_to_anthropic_stream_summary = Some(summary);
                Box::pin(adapted.map(|item| item.map_err(|err| err.to_string())))
            } else if convert_responses_sse_to_chat_sse {
                let (adapted, summary) =
                    streaming_responses_chat::create_chat_sse_stream_from_responses(
                        raw_stream,
                        decision.model.clone(),
                        diagnostics.chat_stream_include_usage,
                    );
                responses_to_chat_stream_summary = Some(summary);
                Box::pin(adapted.map(|item| item.map_err(|err| err.to_string())))
            } else if convert_responses_sse_to_anthropic_sse {
                let (adapted, summary) =
                    streaming_responses_anthropic::create_anthropic_sse_stream_from_responses(
                        raw_stream,
                        decision.model.clone(),
                    );
                responses_to_anthropic_stream_summary = Some(summary);
                Box::pin(adapted.map(|item| item.map_err(|err| err.to_string())))
            } else {
                Box::pin(raw_stream.map(|item| item.map_err(|err| err.to_string())))
            };
        let mut first_chunk_at: Option<u64> = None;
        let mut first_model_output_at: Option<u64> = None;
        let mut cache_capture = BoundedCacheCapture::new(eligible);
        let mut session_error_body = Vec::new();
        let mut stream_state = ResponsesStreamState::default();
        let mut sse_chunks = 0u64;
        let mut sse_end_reason = "upstream_eof".to_string();
        let mut stream_upstream_wait_ms = 0u64;
        let mut stream_client_backpressure_ms = 0u64;
        let mut downstream_disconnected = false;
        let mut downstream_disconnect_stage = None;
        let mut first_chunk_accepted_by_relay = false;
        let mut terminal_accepted_by_relay = false;
        let mut stream_end = StreamEnd::CleanEof;
        let mut stream_transport_error = None;
        let mut stream_metric_errors = Vec::<(String, String)>::new();
        let state_for_stream = state.clone();
        loop {
            let upstream_wait_started = Instant::now();
            let next_chunk = stream.next().await;
            stream_upstream_wait_ms = stream_upstream_wait_ms
                .saturating_add(upstream_wait_started.elapsed().as_millis() as u64);
            let Some(chunk) = next_chunk else {
                break;
            };
            let chunk = match chunk {
                Ok(chunk) => chunk,
                Err(err) => {
                    stream_metric_errors.push(("upstream_stream".to_string(), err.clone()));
                    sse_end_reason = "upstream_stream_error".to_string();
                    stream_end = StreamEnd::TransportError;
                    stream_transport_error = Some(err);
                    break;
                }
            };
            let chunk_received_at = started.elapsed().as_millis() as u64;
            if first_chunk_at.is_none() {
                first_chunk_at = Some(chunk_received_at);
            }
            sse_chunks += 1;
            for relay_chunk in relay_chunk_parts(&chunk) {
                let mut accepted_by_relay = false;
                if !downstream_disconnected {
                    let client_backpressure_started = Instant::now();
                    let permit = downstream_byte_budget
                        .clone()
                        .acquire_many_owned(relay_chunk.len() as u32)
                        .await;
                    let send_failed = match permit {
                        Ok(permit) => downstream_sender
                            .send(Ok(RelayBodyChunk {
                                bytes: relay_chunk.clone(),
                                permit,
                            }))
                            .await
                            .is_err(),
                        Err(_) => true,
                    };
                    if send_failed {
                        downstream_disconnected = true;
                        downstream_disconnect_stage = Some(
                            if terminal_accepted_by_relay {
                                "after_terminal"
                            } else {
                                "before_terminal"
                            }
                            .to_string(),
                        );
                    } else {
                        accepted_by_relay = true;
                    }
                    stream_client_backpressure_ms = stream_client_backpressure_ms
                        .saturating_add(client_backpressure_started.elapsed().as_millis() as u64);
                }
                if accepted_by_relay && !first_chunk_accepted_by_relay {
                    first_chunk_accepted_by_relay = true;
                    tokio::task::yield_now().await;
                }
                let observation = stream_state.ingest(&relay_chunk);
                if first_model_output_at.is_none() && observation.model_output_started {
                    first_model_output_at = Some(chunk_received_at);
                }
                let terminal_seen = match client_channel {
                    Channel::Responses => observation.responses_completed_event_seen,
                    Channel::Anthropic => observation.message_stop_event_seen,
                    Channel::Chat => observation.done_marker_seen,
                };
                if accepted_by_relay && terminal_seen {
                    terminal_accepted_by_relay = true;
                }
                cache_capture.push(&relay_chunk);
                if used_response_session && session_error_body.len() < 65_536 {
                    let remaining = 65_536usize.saturating_sub(session_error_body.len());
                    session_error_body
                        .extend_from_slice(&relay_chunk[..relay_chunk.len().min(remaining)]);
                }
            }
        }
        let cache_body = cache_capture.finish();
        let mut stream_metadata = stream_state.finish();
        if let Some(summary_handle) = responses_to_chat_stream_summary {
            if let Ok(summary) = summary_handle.lock() {
                if summary.usage.has_usage() {
                    stream_metadata.usage = summary.usage.clone();
                }
                if summary.response_id.is_some() {
                    stream_metadata.response_id = summary.response_id.clone();
                }
                stream_metadata.compaction_output_seen |= summary.compaction_output_seen;
                stream_metadata.model_output_seen |= summary.model_output_seen;
            }
        }
        if let Some(summary_handle) = responses_to_anthropic_stream_summary {
            if let Ok(summary) = summary_handle.lock() {
                if summary.usage.has_usage() {
                    stream_metadata.usage = summary.usage.clone();
                }
                if summary.response_id.is_some() {
                    stream_metadata.response_id = summary.response_id.clone();
                }
                stream_metadata.compaction_output_seen |= summary.compaction_output_seen;
                stream_metadata.model_output_seen |= summary.model_output_seen;
            }
        }
        if let Some(summary_handle) = chat_to_anthropic_stream_summary {
            if let Ok(summary) = summary_handle.lock() {
                if summary.usage.has_usage() {
                    stream_metadata.usage = summary.usage.clone();
                }
                if summary.response_id.is_some() {
                    stream_metadata.response_id = summary.response_id.clone();
                }
                stream_metadata.compaction_output_seen |= summary.compaction_output_seen;
                stream_metadata.model_output_seen |= summary.model_output_seen;
            }
        }
        let terminal_verdict = evaluate_terminal(
            &client_channel,
            TerminalCompatibility::Strict,
            &stream_metadata,
            stream_end,
        );
        if terminal_verdict.trailing_transport_anomaly {
            sse_end_reason = "upstream_trailing_transport_anomaly".to_string();
        } else if let Some(failure) = terminal_verdict.failure {
            sse_end_reason = match failure {
                TerminalFailure::ErrorEvent => "upstream_sse_error",
                TerminalFailure::FrameTooLarge => "upstream_sse_frame_too_large",
                TerminalFailure::IncompleteEof => "upstream_incomplete_eof",
                TerminalFailure::TransportErrorBeforeTerminal => "upstream_stream_error",
            }
            .to_string();
        }
        if !downstream_disconnected && !terminal_verdict.success {
            let relay_error = match terminal_verdict.failure {
                Some(TerminalFailure::TransportErrorBeforeTerminal) => stream_transport_error
                    .unwrap_or_else(|| "upstream stream failed before completion".to_string()),
                Some(TerminalFailure::IncompleteEof) => {
                    "upstream stream ended before a completion event".to_string()
                }
                Some(TerminalFailure::FrameTooLarge) => {
                    "upstream SSE frame exceeded the inspection limit".to_string()
                }
                Some(TerminalFailure::ErrorEvent) | None => String::new(),
            };
            if !relay_error.is_empty()
                && downstream_sender
                    .send(Err(std::io::Error::other(relay_error)))
                    .await
                    .is_err()
            {
                downstream_disconnected = true;
                downstream_disconnect_stage = Some("before_terminal".to_string());
            }
        }
        // The client has received every upstream byte. Close its body before
        // usage, cache, metrics, and persistence settlement continue.
        drop(downstream_sender);
        if !terminal_verdict.success {
            if let Some(error_summary) = stream_metadata.error_summary.as_deref() {
                note_runtime_cache_capability_rejection(
                    &state_for_stream,
                    &decision,
                    &decision.upstream_channel,
                    &upstream_request_diagnostics,
                    status,
                    error_summary,
                )
                .await;
            }
        }
        if used_response_session
            && is_verified_third_party_response_session_reuse(&config, &decision)
            && stream_metadata.error_event_seen
        {
            let error_summary = upstream_error_summary(&session_error_body);
            let rejection = response_session_rejection_classification(status, &error_summary);
            if !error_summary.is_empty() {
                stream_metric_errors.push((
                    "verified_response_session_delta_rejected".to_string(),
                    error_summary.clone(),
                ));
            }
            let cooldown_key = response_session_error_cooldown_key(&decision);
            note_response_session_error_cooldown_for_rejection(
                &state_for_stream,
                cooldown_key.as_deref(),
                status,
                &error_summary,
            )
            .await;
            if matches!(
                rejection,
                ResponseSessionRejectionClass::StaleReference
                    | ResponseSessionRejectionClass::Unsupported
            ) {
                clear_response_session_reference(
                    &state_for_stream,
                    response_session_key.as_deref(),
                    None,
                )
                .await;
            }
            if rejection == ResponseSessionRejectionClass::Unsupported {
                invalidate_verified_third_party_response_session_reuse(
                    &state_for_stream,
                    &decision.provider.id,
                    &decision.model,
                    &error_summary,
                )
                .await;
            }
        }
        let stream_success_for_cache = (200..300).contains(&status) && terminal_verdict.success;
        let confirmed_compaction = confirmed_responses_compaction(
            &decision.upstream_channel,
            diagnostics.compaction_trigger_requested,
            diagnostics.trusted_codex_compaction_requested,
            stream_metadata.compaction_output_seen,
            stream_metadata.model_output_seen,
            (200..300).contains(&status),
            terminal_verdict.success,
        );
        let terminal_error_scope = match terminal_verdict.failure {
            Some(TerminalFailure::ErrorEvent | TerminalFailure::IncompleteEof) => {
                Some("upstream_sse_error")
            }
            Some(TerminalFailure::FrameTooLarge) => Some("upstream_sse_frame_too_large"),
            Some(TerminalFailure::TransportErrorBeforeTerminal) | None => None,
        };
        if !stream_success_for_cache {
            if let Some(error_scope) = terminal_error_scope {
                stream_metric_errors.push((error_scope.to_string(), sse_end_reason.clone()));
            }
        }
        let total_ms = started.elapsed().as_millis() as u64;
        let usage_observation = if stream_success_for_cache {
            collect_provider_usage_from_record(
                &state_for_stream,
                stream_metadata.usage.clone(),
                &decision,
                prefix_state_key.as_deref(),
                used_response_session,
            )
            .await
        } else {
            None
        };
        let usage_record = usage_observation.as_ref().map(|item| item.raw.clone());
        let prefix_usage_record = usage_observation
            .as_ref()
            .map(|item| item.effective.clone());
        if stream_success_for_cache && !confirmed_compaction {
            update_response_session_with_id(
                &state_for_stream,
                response_session_key.as_deref(),
                response_session_scope_key.as_deref(),
                full_response_input.as_ref(),
                stream_metadata.response_id.clone(),
            )
            .await;
        }
        let prefix_observation = observe_provider_prefix_usage(
            &state_for_stream,
            prefix_state_key.as_deref(),
            provider_prefix_family_key.as_deref(),
            usage_record.as_ref(),
            prefix_usage_record.as_ref(),
            &tail_input_diagnostics,
            used_response_session,
            retried_full_response,
            prefix_guard_wait.budget_exhausted,
            stream_success_for_cache,
        )
        .await;
        let gap_breakdown = prefix_observation.gap;
        let prefix_lag = usage_record
            .as_ref()
            .map(|record| {
                prefix_lag_diagnostics_from_previous(
                    prefix_observation.previous.as_ref(),
                    record,
                    gap_breakdown.as_ref(),
                    &prefix_guard_wait,
                    &tail_input_diagnostics,
                )
            })
            .unwrap_or_default();
        if confirmed_compaction {
            let shadow_assignment_key =
                mark_shadow_compaction_boundary(&mut shadow_affinity_decision);
            finalize_confirmed_responses_compaction(
                &state_for_stream,
                response_session_key.as_deref(),
                prefix_state_key.as_deref(),
                provider_prefix_family_key.as_deref(),
                shadow_assignment_key.as_deref(),
            )
            .await;
        }
        if stream_success_for_cache {
            note_provider_route_affinity(
                &state_for_stream,
                route_affinity_key.as_deref(),
                &decision.provider.id,
            )
            .await;
            clear_prefix_error_cooldown(&state_for_stream, prefix_state_key.as_deref()).await;
        }
        let ttft_ms = first_model_output_at.or(first_chunk_at).unwrap_or(total_ms);
        let upstream_first_chunk_ms = first_chunk_at
            .unwrap_or(total_ms)
            .saturating_sub(upstream_response_headers_at_ms);
        let mut request_log = RequestLog {
            id: request_id.clone(),
            at: Utc::now(),
            inbound_request_id: Some(request_id.clone()),
            upstream_request_id: Some(Uuid::new_v4().to_string()),
            upstream_attempt_index: Some(1),
            upstream_attempt_total: Some(upstream_request_diagnostics.attempts),
            client_channel: client_channel.label().to_string(),
            upstream_channel: decision.upstream_channel.label().to_string(),
            provider: decision.provider.name.clone(),
            provider_id: Some(decision.provider.id.clone()),
            model: decision.model.clone(),
            requested_model,
            agent_reasoning_effort: None,
            configured_reasoning_effort: None,
            effective_reasoning_effort: None,
            reasoning_effort_source: None,
            cache_status: if confirmed_compaction {
                "compact"
            } else if stream_success_for_cache {
                if eligible {
                    "miss"
                } else {
                    "bypass"
                }
            } else {
                "error"
            }
            .to_string(),
            cold_start: None,
            agent_id: agent_log_id.clone(),
            agent_label: agent_log_label.clone(),
            upstream_call_kind: Some("stream".to_string()),
            upstream_call_source: Some(
                if confirmed_compaction {
                    "responses-compaction-v2"
                } else {
                    "main"
                }
                .to_string(),
            ),
            cache_key: if eligible && stream_success_for_cache && !confirmed_compaction {
                Some(metrics_cache_key.clone())
            } else {
                None
            },
            provider_prefix_key: provider_prefix_key.clone(),
            provider_prefix_fingerprint: provider_prefix_fingerprint.clone(),
            outbound_prefix_fingerprints: upstream_request_diagnostics
                .outbound_prefix_fingerprints
                .clone(),
            provider_cache_diagnostic: usage_record.as_ref().map(provider_cache_diagnostic),
            shadow_affinity_mode: None,
            shadow_affinity_arm: None,
            shadow_affinity_realm_id: None,
            shadow_affinity_cohort_id: None,
            shadow_affinity_lane: None,
            shadow_affinity_shard: None,
            shadow_affinity_policy_epoch: None,
            shadow_affinity_anchor_epoch: None,
            shadow_affinity_trusted_identity: None,
            shadow_affinity_decision: None,
            shadow_affinity_skip_reason: None,
            shadow_affinity_policy_compute_ms: None,
            prefix_guard_wait_ms: Some(prefix_guard_wait.wait_ms),
            prefix_guard_wait_reason: prefix_guard_wait.reason.clone(),
            prefix_guard_wait_source: prefix_guard_wait.source.clone(),
            prefix_guard_state_age_ms: prefix_guard_wait.state_age_ms,
            prefix_guard_skip_reason: prefix_guard_wait.skip_reason.clone(),
            prefix_guard_wait_effect: prefix_guard_wait_effect(
                &prefix_guard_wait,
                usage_record.as_ref(),
                gap_breakdown.as_ref(),
            ),
            prefix_lag_classification: None,
            prefix_lag_input_delta_tokens: None,
            prefix_lag_cache_delta_tokens: None,
            prefix_lag_previous_gap_tokens: None,
            prefix_cache_instability_score: prefix_guard_wait.cache_instability_score,
            prefix_seen_bucket_tokens: prefix_guard_wait.seen_bucket_tokens,
            prefix_state_cache_read_tokens: prefix_guard_wait.state_cache_read_tokens,
            status,
            ttft_ms,
            first_byte_ms: first_chunk_at,
            upstream_ttft_ms: Some(upstream_ttft_ms(ttft_ms, Some(prefix_guard_wait.wait_ms))),
            local_prepare_ms: Some(local_prepare_ms),
            upstream_headers_ms: Some(upstream_request_diagnostics.headers_ms),
            upstream_last_attempt_headers_ms: Some(
                upstream_request_diagnostics.last_attempt_headers_ms,
            ),
            upstream_http_version: upstream_request_diagnostics.http_version.clone(),
            upstream_network_path: Some(upstream_request_diagnostics.network_path.to_string()),
            upstream_remote_addr: upstream_request_diagnostics.remote_addr.clone(),
            upstream_pool_diagnostic: upstream_request_diagnostics.pool_diagnostic.clone(),
            upstream_trace_id: upstream_request_diagnostics.upstream_trace_id.clone(),
            upstream_trace_source: upstream_request_diagnostics.upstream_trace_source.clone(),
            upstream_server_timing: upstream_request_diagnostics.server_timing.clone(),
            upstream_timing_source: upstream_request_diagnostics.timing_source.clone(),
            upstream_reported_processing_ms: upstream_request_diagnostics.reported_processing_ms,
            upstream_non_processing_ms: upstream_request_diagnostics.non_processing_ms,
            upstream_first_chunk_ms: Some(upstream_first_chunk_ms),
            stream_upstream_wait_ms: Some(stream_upstream_wait_ms),
            stream_client_backpressure_ms: Some(stream_client_backpressure_ms),
            aggregate_done_ms: None,
            upstream_retry_wait_ms: Some(upstream_request_diagnostics.retry_wait_ms),
            upstream_attempts: Some(upstream_request_diagnostics.attempts),
            request_body_bytes: Some(upstream_request_diagnostics.request_body_bytes),
            sent_body_bytes: Some(upstream_request_diagnostics.sent_body_bytes),
            request_body_encode_ms: Some(upstream_request_diagnostics.request_body_encode_ms),
            gzip_encode_ms: Some(upstream_request_diagnostics.gzip_encode_ms),
            gzip_attempted: Some(upstream_request_diagnostics.gzip_attempted),
            gzip_fallback_used: Some(upstream_request_diagnostics.gzip_fallback_used),
            upstream_header_wait_class: Some(upstream_header_wait_class(
                &upstream_request_diagnostics,
            )),
            total_ms,
            input_tokens: usage_record.as_ref().map(|record| record.input_tokens),
            output_tokens: usage_record.as_ref().map(|record| record.output_tokens),
            cache_read_tokens: usage_record.as_ref().map(|record| record.cache_read_tokens),
            cache_shortfall_tokens: usage_record.as_ref().map(provider_cache_shortfall),
            cache_new_tail_gap_tokens: gap_breakdown.as_ref().map(|gap| gap.new_tail_tokens),
            cache_avoidable_gap_tokens: gap_breakdown.as_ref().map(|gap| gap.avoidable_tokens),
            cache_provider_unstable_gap_tokens: gap_breakdown
                .as_ref()
                .map(|gap| gap.provider_unstable_tokens),
            provider_cache_token_ratio: usage_record.as_ref().and_then(provider_cache_ratio),
            tail_input_items: None,
            tail_message_chars: None,
            tail_tool_call_chars: None,
            tail_tool_output_chars: None,
            tail_largest_tool_output_chars: None,
            tail_tool_output_lines: None,
            tail_tool_output_repeated_line_chars: None,
            tail_tool_output_timestamp_like_count: None,
            tail_tool_output_path_like_count: None,
            tail_tool_output_url_like_count: None,
            tail_tool_output_hash_like_count: None,
            tail_tool_output_json_like_chars: None,
            tail_tool_output_noise_hint: None,
            tail_source: None,
            response_session_reused: Some(used_response_session),
            response_session_candidate_count: Some(
                response_session_reuse_diagnostics.candidate_count,
            ),
            response_session_skip_reason: response_session_reuse_diagnostics.skip_reason.clone(),
            response_session_exact_key_hit: Some(response_session_reuse_diagnostics.exact_key_hit),
            response_session_scope_match_count: Some(
                response_session_reuse_diagnostics.scope_match_count,
            ),
            response_session_append_delta_match: Some(
                response_session_reuse_diagnostics.append_delta_match,
            ),
            response_session_delta_items: Some(response_session_reuse_diagnostics.delta_items),
            response_session_cooldown_active: Some(
                response_session_reuse_diagnostics.cooldown_active,
            ),
            response_session_rejected_status: response_session_reuse_diagnostics.rejected_status,
            session_anchor_hash: None,
            session_anchor_source: None,
            session_anchor_changed: None,
            session_anchor_peer_count: None,
            inbound_body_bytes: None,
            original_body_bytes: None,
            send_body_bytes: None,
            send_body_is_delta: None,
            payload_too_large_rescue_attempted: None,
            payload_too_large_rescue_used: None,
            sse_end_reason: Some(sse_end_reason),
            downstream_disconnected: Some(downstream_disconnected),
            downstream_disconnect_stage,
            sse_completed_event_seen: Some(stream_metadata.completed_event_seen),
            sse_done_marker_seen: Some(stream_metadata.done_marker_seen),
            sse_chunks: Some(sse_chunks),
        };
        apply_prefix_lag_diagnostics(&mut request_log, prefix_lag);
        apply_session_anchor_diagnostics(&mut request_log, &session_anchor_diagnostics);
        apply_body_diagnostics(&mut request_log, &diagnostics);
        apply_tail_input_diagnostics(&mut request_log, &tail_input_diagnostics);
        if agent_generation {
            let (attempt_outcome, inbound_outcome, error_scope, terminal_state) =
                if terminal_verdict.success {
                    (
                        AgentAttemptOutcome::HttpSuccess,
                        AgentInboundOutcome::Success,
                        None,
                        if terminal_verdict.trailing_transport_anomaly {
                            "response_completed_with_trailing_transport_anomaly"
                        } else {
                            "response_completed"
                        },
                    )
                } else {
                    match terminal_verdict.failure {
                        Some(TerminalFailure::IncompleteEof) => (
                            AgentAttemptOutcome::StreamError,
                            AgentInboundOutcome::Incomplete,
                            Some("upstream_incomplete_eof".to_string()),
                            "incomplete_eof",
                        ),
                        Some(TerminalFailure::ErrorEvent) => (
                            AgentAttemptOutcome::StreamError,
                            AgentInboundOutcome::StreamError,
                            Some("upstream_sse_error".to_string()),
                            "sse_error",
                        ),
                        Some(TerminalFailure::FrameTooLarge) => (
                            AgentAttemptOutcome::StreamError,
                            AgentInboundOutcome::StreamError,
                            Some("upstream_sse_frame_too_large".to_string()),
                            "sse_frame_too_large",
                        ),
                        Some(TerminalFailure::TransportErrorBeforeTerminal) => (
                            AgentAttemptOutcome::StreamError,
                            AgentInboundOutcome::TransportError,
                            Some("upstream_stream_error".to_string()),
                            "transport_error_before_terminal",
                        ),
                        None => (
                            AgentAttemptOutcome::HttpError,
                            AgentInboundOutcome::HttpError,
                            Some("upstream_stream".to_string()),
                            "stream_failed",
                        ),
                    }
                };
            finalize_agent_generation(
                &state_for_stream,
                &request_id,
                agent_attempt_id,
                request_log,
                attempt_outcome,
                inbound_outcome,
                Some(status),
                error_scope,
                terminal_state,
                usage_record.clone(),
                response_session_key
                    .clone()
                    .or(session_anchor_diagnostics.hash.clone()),
                stream_metric_errors.clone(),
                shadow_affinity_decision,
                Some(&upstream_request_diagnostics),
            )
            .await;
        } else {
            let mut transaction = MetricsTransaction::upstream(request_log);
            if let Some(usage_record) = usage_record {
                transaction.observe_usage(
                    usage_record,
                    response_session_key
                        .as_deref()
                        .or(session_anchor_diagnostics.hash.as_deref()),
                );
            }
            for (scope, message) in stream_metric_errors {
                transaction.observe_error(scope, message);
            }
            state_for_stream.metrics.commit(transaction).await;
        }
        if eligible && stream_success_for_cache && !confirmed_compaction {
            let Some(cache_body) = cache_body else {
                return;
            };
            insert_cache_entries(
                &state_for_stream,
                cache_keys,
                semantic_text,
                semantic_shape,
                content_type_for_cache,
                status,
                cache_body,
                &decision,
                &config,
            )
            .await;
        }
    };

    let stream_body = async_stream::stream! {
        while let Some(chunk) = downstream_receiver.recv().await {
            match chunk {
                Ok(RelayBodyChunk { bytes, permit }) => {
                    yield Ok::<Bytes, std::io::Error>(bytes);
                    drop(permit);
                }
                Err(error) => yield Err(error),
            }
        }
    };

    let response = Response::builder()
        .status(status)
        .header(header::CONTENT_TYPE, response_content_type)
        .body(Body::from_stream(stream_body))
        .unwrap_or_else(|_| {
            json_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "failed to build stream response",
            )
        });

    if let Some(handoff) = response_handoff {
        let _ = handoff.send(response);
        relay.await;
        Response::new(Body::empty())
    } else {
        relay_reservation
            .expect("normal stream responses reserve a relay owner before body construction")
            .spawn(relay);
        response
    }
}

async fn authorize_for_agent(
    state: &AppState,
    headers: &HeaderMap,
    forced_agent_id: Option<&'static str>,
) -> Result<Option<String>, Response> {
    let config = state.config.read().await;
    let bearer = headers
        .get(header::AUTHORIZATION)
        .and_then(|value| value.to_str().ok())
        .and_then(|value| value.strip_prefix("Bearer "))
        .map(str::trim);
    let x_key = headers
        .get("x-api-key")
        .and_then(|value| value.to_str().ok())
        .map(str::trim);
    let presented_key = bearer.or(x_key);

    if let Some(agent_id) = forced_agent_id {
        let Some(agent) = config.agent_injections.iter().find(|agent| {
            agent.id == agent_id && agent.enabled && agent.kind != AgentInjectionKind::ProxyMode
        }) else {
            return Err(json_error(
                StatusCode::UNAUTHORIZED,
                "agent injection is not enabled",
            ));
        };
        if config.local_key.trim().is_empty() {
            return Ok(Some(agent.id.clone()));
        }
        let scoped_key = agent_injection::agent_local_key(&config.local_key, &agent.id);
        let accepted = presented_key == Some(PROXY_TOKEN_PLACEHOLDER)
            || presented_key == Some(config.local_key.as_str())
            || presented_key == Some(scoped_key.as_str());
        if accepted {
            return Ok(Some(agent.id.clone()));
        }
        return Err(json_error(
            StatusCode::UNAUTHORIZED,
            "invalid local proxy key",
        ));
    }

    if config.local_key.trim().is_empty() {
        return Ok(None);
    }
    if presented_key == Some(config.local_key.as_str()) {
        Ok(None)
    } else if let Some(agent) = presented_key.and_then(|key| agent_for_local_key(&config, key)) {
        Ok(Some(agent.id.clone()))
    } else {
        Err(json_error(
            StatusCode::UNAUTHORIZED,
            "invalid local proxy key",
        ))
    }
}

async fn authorize_admin(state: &AppState, headers: &HeaderMap) -> Result<(), Response> {
    let config = state.config.read().await;
    if config.local_key.trim().is_empty() {
        return Ok(());
    }
    let presented_key = headers
        .get(header::AUTHORIZATION)
        .and_then(|value| value.to_str().ok())
        .and_then(|value| value.strip_prefix("Bearer "))
        .or_else(|| {
            headers
                .get("x-api-key")
                .and_then(|value| value.to_str().ok())
        })
        .map(str::trim);
    if presented_key == Some(config.local_key.as_str()) {
        Ok(())
    } else {
        Err(json_error(
            StatusCode::UNAUTHORIZED,
            "invalid local administration key",
        ))
    }
}

fn agent_for_local_key<'a>(config: &'a AppConfig, key: &str) -> Option<&'a AgentInjectionConfig> {
    config.agent_injections.iter().find(|agent| {
        agent.enabled && agent_injection::agent_local_key(&config.local_key, &agent.id) == key
    })
}

fn route_is_agent_provider_bound(
    config: &AppConfig,
    _request: &Value,
    _client_channel: &Channel,
    authorized_agent_id: Option<&str>,
) -> bool {
    authorized_agent_id
        .and_then(|agent_id| {
            config
                .agent_injections
                .iter()
                .find(|agent| agent.id == agent_id && agent.enabled)
        })
        .and_then(|agent| agent.provider_id.as_deref())
        .is_some()
}

async fn provider_route_affinity_for_request(
    state: &AppState,
    config: &AppConfig,
    request: &Value,
    client_channel: &Channel,
    route_is_agent_bound: bool,
) -> (Option<String>, Option<String>) {
    let key = provider_route_affinity_key(config, request, client_channel);
    if route_is_agent_bound {
        return (key, None);
    }

    let provider_id = lookup_provider_route_affinity(state, config, key.as_deref()).await;
    (key, provider_id)
}

fn provider_route_affinity_key(
    config: &AppConfig,
    request: &Value,
    client_channel: &Channel,
) -> Option<String> {
    if !matches!(client_channel, Channel::Responses) {
        return None;
    }

    let mut material = request.clone();
    strip_provider_cache_key_fields(&mut material);
    canonicalize_responses_instruction_shape(&mut material);
    strip_response_session_volatile_fields(&mut material);
    strip_dynamic_invocation_fields(&mut material);
    trim_response_session_input_to_anchor(&mut material);
    stabilize_responses_provider_prefix(&mut material);
    canonicalize_object_keys(&mut material, "$.provider_route_affinity_key");

    let model = request
        .get("model")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|model| !model.is_empty())
        .unwrap_or("*");
    let mut hasher = Sha256::new();
    hasher.update(config.workspace_fingerprint.as_bytes());
    hasher.update(b"\0");
    hasher.update(client_channel.label().as_bytes());
    hasher.update(b"\0");
    hasher.update(model.as_bytes());
    hasher.update(b"\0");
    hasher.update(serialize_responses_body_for_provider_prefix(&material).as_bytes());
    Some(format!("{:x}", hasher.finalize()))
}

async fn lookup_provider_route_affinity(
    state: &AppState,
    config: &AppConfig,
    affinity_key: Option<&str>,
) -> Option<String> {
    let key = affinity_key?;
    let provider_id = state
        .provider_route_affinity
        .lock()
        .await
        .get(key)
        .cloned()?;
    if config
        .providers
        .iter()
        .any(|provider| provider.id == provider_id && provider.enabled)
    {
        return Some(provider_id);
    }
    state.provider_route_affinity.lock().await.remove(key);
    None
}

async fn note_provider_route_affinity(
    state: &AppState,
    affinity_key: Option<&str>,
    provider_id: &str,
) {
    let Some(key) = affinity_key else {
        return;
    };
    if provider_id.trim().is_empty() {
        return;
    }
    state
        .provider_route_affinity
        .lock()
        .await
        .insert(key.to_string(), provider_id.to_string());
}

async fn maybe_clear_provider_route_affinity_after_status(
    state: &AppState,
    affinity_key: Option<&str>,
    provider_id: &str,
    status: u16,
    error_summary: Option<&str>,
) {
    let Ok(status_code) = StatusCode::from_u16(status) else {
        return;
    };
    if is_provider_key_failure_status(status_code)
        || error_summary
            .map(is_provider_key_failure_message)
            .unwrap_or(false)
    {
        clear_provider_route_affinity(state, affinity_key, provider_id).await;
    }
}

async fn clear_provider_route_affinity(
    state: &AppState,
    affinity_key: Option<&str>,
    provider_id: &str,
) {
    let Some(key) = affinity_key else {
        return;
    };
    let mut affinities = state.provider_route_affinity.lock().await;
    if affinities
        .get(key)
        .map(|current| current == provider_id)
        .unwrap_or(false)
    {
        affinities.remove(key);
    }
}

fn apply_provider_route_affinity(
    config: &AppConfig,
    decision: RouteDecision,
    request: &Value,
    client_channel: &Channel,
    preferred_provider_id: Option<&str>,
) -> RouteDecision {
    if !matches!(client_channel, Channel::Responses) {
        return decision;
    }
    let Some(preferred_provider_id) = preferred_provider_id else {
        return decision;
    };
    if preferred_provider_id == decision.provider.id {
        return decision;
    }
    let Some(provider) = config
        .providers
        .iter()
        .find(|provider| provider.id == preferred_provider_id && provider.enabled)
    else {
        return decision;
    };

    let requested_model = request
        .get("model")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|model| !model.is_empty());
    let model = if let Some(requested_model) = requested_model {
        if let Some(model) = resolve_provider_model_id(provider, requested_model) {
            model
        } else {
            return decision;
        }
    } else if let Some(model) = resolve_provider_model_id(provider, &decision.model) {
        model
    } else if let Some(model) = provider
        .models
        .iter()
        .find(|model| model.enabled)
        .map(|model| model.id.clone())
    {
        model
    } else {
        return decision;
    };

    RouteDecision {
        upstream_channel: effective_upstream_channel_for_provider(config, provider, client_channel),
        provider: provider.clone(),
        model,
    }
}

fn decide_route(
    config: &AppConfig,
    request: &Value,
    client_channel: &Channel,
    authorized_agent_id: Option<&str>,
) -> Result<RouteDecision, String> {
    let requested_model = request
        .get("model")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned);
    let authorized_agent = authorized_agent_id.and_then(|agent_id| {
        config
            .agent_injections
            .iter()
            .find(|agent| agent.id == agent_id && agent.enabled)
    });

    let profile = config
        .route_profiles
        .iter()
        .find(|profile| &profile.client_channel == client_channel);
    let preferred_channel = authorized_agent
        .and_then(|agent| agent.provider_id.as_deref())
        .and_then(|provider_id| {
            config
                .providers
                .iter()
                .find(|provider| provider.id == provider_id && provider.enabled)
        })
        .map(|provider| provider.channel.clone())
        .or_else(|| profile.map(|profile| profile.upstream_channel.clone()))
        .unwrap_or_else(|| client_channel.clone());

    let agent_provider = authorized_agent
        .and_then(|agent| agent.provider_id.as_deref())
        .and_then(|provider_id| {
            config
                .providers
                .iter()
                .find(|provider| provider.id == provider_id && provider.enabled)
        });

    let configured_provider = agent_provider.or_else(|| {
        config
            .active_provider_id
            .as_deref()
            .and_then(|provider_id| {
                config
                    .providers
                    .iter()
                    .find(|provider| provider.id == provider_id && provider.enabled)
            })
            .or_else(|| {
                profile
                    .and_then(|profile| profile.provider_id.as_deref())
                    .and_then(|provider_id| {
                        config
                            .providers
                            .iter()
                            .find(|provider| provider.id == provider_id && provider.enabled)
                    })
            })
    });

    let requested_model_provider = requested_model.as_deref().and_then(|model| {
        config.providers.iter().find(|provider| {
            provider.enabled && provider_supports_requested_model(provider, Some(model))
        })
    });

    let provider = if let Some(provider) = agent_provider {
        provider
    } else {
        configured_provider
            .filter(|provider| {
                provider_supports_requested_model(provider, requested_model.as_deref())
            })
            .or(requested_model_provider)
            .or_else(|| {
                config
                    .providers
                    .iter()
                    .find(|provider| provider.enabled && provider.channel == preferred_channel)
            })
            .or_else(|| config.providers.iter().find(|provider| provider.enabled))
            .ok_or_else(|| "no enabled provider configured".to_string())?
    };

    let agent_model = authorized_agent
        .and_then(|agent| agent.model_id.clone())
        .and_then(|model| resolve_provider_model_id(provider, &model));
    let requested_model_for_provider = requested_model
        .as_deref()
        .and_then(|model| resolve_provider_model_id(provider, model));

    let model = requested_model_for_provider
        .or(requested_model)
        .or(agent_model)
        .or_else(|| {
            profile
                .and_then(|profile| profile.model_alias.as_ref())
                .cloned()
        })
        .or_else(|| {
            provider
                .models
                .iter()
                .find(|model| model.enabled)
                .map(|model| model.id.clone())
        })
        .ok_or_else(|| format!("provider {} has no model configured", provider.name))?;

    Ok(RouteDecision {
        upstream_channel: effective_upstream_channel_for_provider(config, provider, client_channel),
        provider: provider.clone(),
        model,
    })
}

fn effective_upstream_channel_for_provider(
    config: &AppConfig,
    provider: &ProviderConfig,
    client_channel: &Channel,
) -> Channel {
    if config.provider_channel_mode_for_provider(&provider.id) == ProviderChannelMode::Manual {
        return provider.channel.clone();
    }
    auto_upstream_channel_for_provider(provider, client_channel)
}

fn auto_upstream_channel_for_provider(
    provider: &ProviderConfig,
    _client_channel: &Channel,
) -> Channel {
    // Auto mode keeps the provider capability hint for normal requests.
    // Responses compact/non-stream fast paths may switch to Chat later in the
    // pipeline, where payload shape and fallback diagnostics are available.
    provider.channel.clone()
}

fn should_preempt_codex_responses_via_chat(
    _config: &AppConfig,
    forced_agent_id: Option<&str>,
    client_channel: &Channel,
    decision: &RouteDecision,
) -> bool {
    forced_agent_id == Some("codex")
        && matches!(client_channel, Channel::Responses)
        && matches!(decision.upstream_channel, Channel::Chat)
}

fn provider_supports_requested_model(
    provider: &ProviderConfig,
    requested_model: Option<&str>,
) -> bool {
    let Some(model) = requested_model else {
        return true;
    };
    resolve_provider_model_id(provider, model).is_some()
}

fn resolve_provider_model_id(provider: &ProviderConfig, requested_model: &str) -> Option<String> {
    let requested = requested_model.trim();
    if requested.is_empty() {
        return None;
    }
    if provider.models.is_empty() {
        return Some(requested.to_string());
    }
    if let Some(model) = provider
        .models
        .iter()
        .find(|item| item.enabled && item.id == requested)
    {
        return Some(model.id.clone());
    }
    if let Some(model) = provider.models.iter().find(|item| {
        item.enabled
            && model_request_alias(item)
                .map(|alias| alias == requested)
                .unwrap_or(false)
    }) {
        return Some(model.id.clone());
    }
    let requested_alias = requested.to_ascii_lowercase();
    provider
        .models
        .iter()
        .find(|item| {
            item.enabled
                && model_request_alias(item)
                    .map(|alias| alias.to_ascii_lowercase() == requested_alias)
                    .unwrap_or(false)
        })
        .or_else(|| {
            provider.models.iter().find(|item| {
                item.enabled
                    && codex_model_alias(&item.id)
                        .map(|alias| alias == requested_alias)
                        .unwrap_or(false)
            })
        })
        .map(|model| model.id.clone())
}

fn set_request_model(request: &mut Value, model: &str) {
    if let Some(object) = request.as_object_mut() {
        object.insert("model".to_string(), Value::String(model.to_string()));
    }
}

fn apply_model_reasoning_effort(
    client_request: &Value,
    upstream_request: &mut Value,
    upstream_channel: &Channel,
    decision: &RouteDecision,
) -> ReasoningEffortDiagnostics {
    let agent = request_reasoning_effort(client_request);
    let model = model_for_route_decision(decision);
    let configured = model
        .filter(|model| model.reasoning_effort_override_enabled)
        .and_then(|model| model.reasoning_effort.as_deref())
        .and_then(normalize_request_reasoning_effort);
    let (mut effective, mut source) = if let Some(configured) = configured.clone() {
        (Some(configured), Some("model_override".to_string()))
    } else if agent.is_some() {
        (agent.clone(), Some("agent".to_string()))
    } else {
        (None, Some("agent_default".to_string()))
    };

    if let (Some(requested), Some(model)) = (effective.as_deref(), model) {
        if let Some(capped) = strongest_supported_reasoning_effort_at_or_below(
            requested,
            &model.supported_reasoning_efforts,
            &HashSet::new(),
        ) {
            if capped != requested {
                source = Some(
                    if configured.is_some() && requested == "ultra" && capped == "max" {
                        "model_override_ultra_to_max"
                    } else if configured.is_some() {
                        "model_override_supported_cap"
                    } else {
                        "agent_supported_cap"
                    }
                    .to_string(),
                );
                effective = Some(capped);
            }
        }
    }

    if let Some(effective) = effective.as_deref() {
        set_request_reasoning_effort(upstream_request, upstream_channel, effective);
    }

    ReasoningEffortDiagnostics {
        agent,
        configured,
        effective,
        source,
    }
}

fn model_for_route_decision(decision: &RouteDecision) -> Option<&ModelConfig> {
    decision
        .provider
        .models
        .iter()
        .find(|model| model.id == decision.model)
        .or_else(|| {
            decision.provider.models.iter().find(|model| {
                model_request_alias(model)
                    .is_some_and(|alias| alias.eq_ignore_ascii_case(&decision.model))
            })
        })
}

fn reasoning_effort_rank(effort: &str) -> Option<usize> {
    REASONING_EFFORT_VALUES
        .iter()
        .position(|candidate| *candidate == effort)
}

fn strongest_supported_reasoning_effort_at_or_below(
    requested: &str,
    supported: &[String],
    rejected: &HashSet<String>,
) -> Option<String> {
    let requested_rank = reasoning_effort_rank(requested)?;
    supported
        .iter()
        .filter_map(|effort| normalize_request_reasoning_effort(effort))
        .filter(|effort| !rejected.contains(effort))
        .filter_map(|effort| {
            reasoning_effort_rank(&effort)
                .filter(|rank| *rank <= requested_rank)
                .map(|rank| (rank, effort))
        })
        .max_by_key(|(rank, _)| *rank)
        .map(|(_, effort)| effort)
}

fn next_lower_reasoning_effort(current: &str, rejected: &HashSet<String>) -> Option<String> {
    let current_rank = reasoning_effort_rank(current)?;
    REASONING_EFFORT_VALUES[..current_rank]
        .iter()
        .rev()
        .find(|candidate| !rejected.contains(**candidate))
        .map(|candidate| (*candidate).to_string())
}

fn reasoning_effort_rejection_key(
    decision: &RouteDecision,
    upstream_channel: &Channel,
    effort: &str,
) -> String {
    format!(
        "{}\0{}\0{}\0{}",
        decision.provider.id,
        decision.model,
        upstream_channel.label(),
        effort
    )
}

async fn rejected_reasoning_efforts(
    state: &AppState,
    decision: &RouteDecision,
    upstream_channel: &Channel,
) -> HashSet<String> {
    let now = Instant::now();
    let ttl = TokioDuration::from_secs(REASONING_EFFORT_REJECTION_COOLDOWN_SECS);
    let mut rejections = state.reasoning_effort_rejections.lock().await;
    rejections.retain(|_, rejected_at| now.duration_since(*rejected_at) < ttl);
    REASONING_EFFORT_VALUES
        .iter()
        .filter(|effort| {
            rejections.contains_key(&reasoning_effort_rejection_key(
                decision,
                upstream_channel,
                effort,
            ))
        })
        .map(|effort| (*effort).to_string())
        .collect()
}

async fn note_reasoning_effort_rejection(
    state: &AppState,
    decision: &RouteDecision,
    upstream_channel: &Channel,
    effort: &str,
) {
    state.reasoning_effort_rejections.lock().await.insert(
        reasoning_effort_rejection_key(decision, upstream_channel, effort),
        Instant::now(),
    );
}

/// Advances only the exact persisted manual override that sent the rejected
/// effort. A concurrent settings edit wins instead of being overwritten.
async fn journal_model_reasoning_effort_fallback(
    state: &AppState,
    decision: &RouteDecision,
    current_effort: &str,
    next_effort: &str,
) -> bool {
    let Some(model_id) = model_for_route_decision(decision).map(|model| model.id.clone()) else {
        return false;
    };
    let Some(current_effort) = normalize_request_reasoning_effort(current_effort) else {
        return false;
    };
    let Some(next_effort) = normalize_request_reasoning_effort(next_effort) else {
        return false;
    };

    let mut config = state.config.write().await;
    let now = Utc::now();
    let Some(provider) = config
        .providers
        .iter_mut()
        .find(|provider| provider.id == decision.provider.id)
    else {
        return false;
    };
    let Some(model) = provider
        .models
        .iter_mut()
        .find(|model| model.id == model_id)
    else {
        return false;
    };
    let configured_effort = model
        .reasoning_effort
        .as_deref()
        .and_then(normalize_request_reasoning_effort);
    if !model.reasoning_effort_override_enabled
        || configured_effort.as_deref() != Some(current_effort.as_str())
    {
        return false;
    }

    model.reasoning_effort = Some(next_effort);
    provider.updated_at = now;
    config.updated_at = now;
    state.journal_config(&config);
    true
}

async fn apply_runtime_reasoning_effort_cap(
    state: &AppState,
    upstream_request: &mut Value,
    upstream_channel: &Channel,
    decision: &RouteDecision,
    diagnostics: &mut ReasoningEffortDiagnostics,
) -> bool {
    let Some(current) = diagnostics.effective.clone() else {
        return false;
    };
    let rejected = rejected_reasoning_efforts(state, decision, upstream_channel).await;
    if !rejected.contains(&current) {
        return false;
    }
    let Some(next) = next_lower_reasoning_effort(&current, &rejected) else {
        return false;
    };
    set_request_reasoning_effort(upstream_request, upstream_channel, &next);
    diagnostics.effective = Some(next);
    diagnostics.source = Some(
        if diagnostics.configured.is_some() {
            "model_override_runtime_cap"
        } else {
            "agent_runtime_cap"
        }
        .to_string(),
    );
    true
}

fn is_explicit_reasoning_effort_rejection(
    status: u16,
    error_body: &[u8],
    current_effort: &str,
) -> bool {
    if !(400..=599).contains(&status) {
        return false;
    }

    // Classify the full upstream diagnostic while keeping only a capped summary
    // in logs. For JSON responses, inspect the declared error message rather
    // than arbitrary echoed request fields.
    let error = upstream_error_text_for_reasoning_classification(error_body).to_ascii_lowercase();
    let normalized_effort = normalize_request_reasoning_effort(current_effort);
    let level_list_rejection = normalized_effort.is_some_and(|effort| {
        error.contains("level")
            && error.contains("valid levels")
            && (error.contains(&format!("\"{effort}\""))
                || error.contains(&format!("'{effort}'"))
                || error.contains(&format!("level {effort}")))
    });
    if level_list_rejection {
        return true;
    }
    const PARAMETER_TERMS: &[&str] = &[
        "reasoning.effort",
        "reasoning_effort",
        "reasoning effort",
        "reasoning",
        "thinking.effort",
        "thinking_effort",
        "thinking effort",
        "thinking",
    ];
    const REJECTION_TERMS: &[&str] = &[
        "unsupported_parameter",
        "unsupported parameter",
        "not supported",
        "unsupported",
        "invalid_parameter",
        "invalid parameter",
        "not available",
        "unavailable",
        "invalid",
    ];

    PARAMETER_TERMS.iter().any(|parameter| {
        REJECTION_TERMS
            .iter()
            .any(|rejection| error_terms_are_nearby(&error, parameter, rejection))
    })
}

fn upstream_error_text_for_reasoning_classification(error_body: &[u8]) -> String {
    if let Ok(value) = serde_json::from_slice::<Value>(error_body) {
        return value
            .pointer("/error/message")
            .or_else(|| value.get("message"))
            .or_else(|| value.pointer("/error/detail"))
            .or_else(|| value.get("detail"))
            .and_then(Value::as_str)
            .unwrap_or_default()
            .to_string();
    }
    String::from_utf8_lossy(error_body).into_owned()
}

fn error_terms_are_nearby(error: &str, parameter: &str, rejection: &str) -> bool {
    const MAX_TERM_DISTANCE_CHARS: usize = 120;
    error.match_indices(parameter).any(|(parameter_at, _)| {
        error.match_indices(rejection).any(|(rejection_at, _)| {
            let start = parameter_at.min(rejection_at);
            let end = (parameter_at + parameter.len()).max(rejection_at + rejection.len());
            error[start..end].chars().count() <= MAX_TERM_DISTANCE_CHARS
        })
    })
}

fn request_reasoning_effort(request: &Value) -> Option<String> {
    [
        request.pointer("/reasoning/effort"),
        request.get("reasoning_effort"),
        request.pointer("/thinking/effort"),
        request.pointer("/thinking/level"),
    ]
    .into_iter()
    .flatten()
    .find_map(Value::as_str)
    .and_then(normalize_request_reasoning_effort)
}

fn normalize_request_reasoning_effort(value: &str) -> Option<String> {
    match value.trim().to_ascii_lowercase().as_str() {
        "off" | "disabled" => Some("none".to_string()),
        normalized => normalize_reasoning_effort(normalized),
    }
}

fn set_request_reasoning_effort(request: &mut Value, channel: &Channel, effort: &str) {
    let Some(object) = request.as_object_mut() else {
        return;
    };
    match channel {
        Channel::Responses => {
            object.remove("reasoning_effort");
            let reasoning = object
                .entry("reasoning".to_string())
                .or_insert_with(|| Value::Object(Map::new()));
            if !reasoning.is_object() {
                *reasoning = Value::Object(Map::new());
            }
            if let Some(reasoning) = reasoning.as_object_mut() {
                reasoning.insert("effort".to_string(), Value::String(effort.to_string()));
            }
        }
        Channel::Chat => {
            object.insert(
                "reasoning_effort".to_string(),
                Value::String(effort.to_string()),
            );
            if let Some(reasoning) = object.get_mut("reasoning").and_then(Value::as_object_mut) {
                reasoning.remove("effort");
                if reasoning.is_empty() {
                    object.remove("reasoning");
                }
            }
        }
        Channel::Anthropic => {}
    }
}

fn requested_model_for_log(request: &Value, upstream_model: &str) -> Option<String> {
    let requested = request.get("model").and_then(Value::as_str)?.trim();
    if requested.is_empty() || requested == upstream_model.trim() {
        return None;
    }
    Some(requested.to_string())
}

fn request_agent_log_fields(
    config: &AppConfig,
    authorized_agent_id: Option<&str>,
) -> (Option<String>, Option<String>) {
    let Some(agent_id) = authorized_agent_id else {
        return (None, None);
    };
    let agent_label = config
        .agent_injections
        .iter()
        .find(|agent| agent.id == agent_id)
        .map(|agent| agent.label.clone())
        .unwrap_or_else(|| agent_id.to_string());
    (Some(agent_id.to_string()), Some(agent_label))
}

/// Reapplies verified provider-native cache controls after a compatibility or
/// rescue path rebuilds the outbound request body.  The initial request and
/// every one-shot fallback must use the same capability decision; otherwise a
/// promoted `prompt_cache_options` record would silently disappear on the
/// fallback body and make the cache result depend on the error path.
fn apply_native_cache_controls(
    request: &mut Value,
    config: &AppConfig,
    decision: &RouteDecision,
    active_channel: &Channel,
    key_id: Option<&str>,
) -> Vec<String> {
    if !smart_hit_enabled(config) || !matches!(active_channel, Channel::Responses | Channel::Chat) {
        return Vec::new();
    }
    let native_cache_plan = cache_capability::plan(
        config,
        &decision.provider,
        &decision.model,
        active_channel,
        key_id,
    );
    cache_capability::apply(request, active_channel, native_cache_plan)
}

fn optimize_provider_prefix(request: &mut Value, config: &AppConfig, decision: &RouteDecision) {
    if !smart_hit_enabled(config) {
        strip_provider_cache_key_fields(request);
        return;
    }

    match decision.upstream_channel {
        Channel::Chat => {
            stabilize_chat_provider_request(request);
            let cache_key =
                provider_prompt_cache_key_for_outbound(config, decision, request, &Channel::Chat);
            if let Some(object) = request.as_object_mut() {
                object.insert("prompt_cache_key".to_string(), Value::String(cache_key));
            }
            apply_openai_prompt_cache_retention(request, decision);
        }
        Channel::Responses => {
            stabilize_responses_provider_prefix(request);
            let cache_key = provider_prompt_cache_key_for_outbound(
                config,
                decision,
                request,
                &Channel::Responses,
            );
            if let Some(object) = request.as_object_mut() {
                object.insert("prompt_cache_key".to_string(), Value::String(cache_key));
            }
            apply_openai_prompt_cache_retention(request, decision);
            canonicalize_object_keys(request, "$.responses_prefix");
        }
        Channel::Anthropic => {
            stabilize_anthropic_provider_request(request);
            add_anthropic_cache_control(request);
        }
    }
}

fn apply_session_provider_cache_key(
    request: &mut Value,
    config: &AppConfig,
    identity: Option<&SessionIdentity>,
) {
    if !smart_hit_enabled(config) {
        return;
    }
    let (Some(object), Some(identity)) = (request.as_object_mut(), identity) else {
        return;
    };
    object.insert(
        "prompt_cache_key".to_string(),
        Value::String(identity.provider_cache_key.clone()),
    );
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct CandidatePromptCacheRoutingOutcome {
    applied: bool,
    changed: bool,
}

fn apply_candidate_prompt_cache_routing(
    request: &mut Value,
    decision: &ShadowAffinityDecision,
) -> CandidatePromptCacheRoutingOutcome {
    let Some(object) = request.as_object_mut() else {
        return CandidatePromptCacheRoutingOutcome::default();
    };
    if cache_affinity::provider_native_candidate_applied(decision) {
        return CandidatePromptCacheRoutingOutcome {
            applied: true,
            changed: object.remove("prompt_cache_key").is_some(),
        };
    }
    let Some(cache_key) = cache_affinity::static_cohort_prompt_cache_key(decision) else {
        return CandidatePromptCacheRoutingOutcome::default();
    };
    let next = Value::String(cache_key);
    let changed = object.get("prompt_cache_key") != Some(&next);
    if changed {
        object.insert("prompt_cache_key".to_string(), next);
    }
    CandidatePromptCacheRoutingOutcome {
        applied: true,
        changed,
    }
}

fn record_prepared_wire_changed_field(changed_fields: &mut Vec<String>, key: &str) {
    if !changed_fields.iter().any(|field| field == key) {
        changed_fields.push(key.to_string());
    }
}

fn extend_prepared_wire_changed_fields(
    changed_fields: &mut Vec<String>,
    additional_fields: impl IntoIterator<Item = String>,
) {
    for field in additional_fields {
        record_prepared_wire_changed_field(changed_fields, &field);
    }
}

fn copy_responses_prefix_cache_fields_for_native_stream(
    outbound: &mut Value,
    prefix_body: &Value,
    config: &AppConfig,
    decision: &RouteDecision,
) {
    strip_provider_cache_key_fields(outbound);
    if !smart_hit_enabled(config) {
        return;
    }
    let Some(cache_key) = openai_prompt_cache_key(prefix_body) else {
        return;
    };
    if let Some(object) = outbound.as_object_mut() {
        object.insert("prompt_cache_key".to_string(), Value::String(cache_key));
    }
    apply_openai_prompt_cache_retention(outbound, decision);
}

fn stabilize_responses_provider_prefix(request: &mut Value) {
    if let Some(object) = request.as_object_mut() {
        for key in [
            "request_id",
            "client_request_id",
            "trace_id",
            "span_id",
            "event_id",
            "run_id",
            "session_id",
            "thread_id",
            "nonce",
            "timestamp",
            "created_at",
            "updated_at",
            "traceparent",
            "metadata",
            "user",
        ] {
            object.remove(key);
        }
    }

    stabilize_responses_tool_call_ids(request);
    strip_responses_provider_noise(request);
}

fn stabilize_responses_tool_call_ids(value: &mut Value) {
    let mut call_ids = HashMap::new();
    let mut occurrences = HashMap::new();
    assign_deterministic_function_call_ids(value, &mut call_ids, &mut occurrences);
    if !call_ids.is_empty() {
        replace_responses_call_id_refs(value, &call_ids);
    }
}

fn assign_deterministic_function_call_ids(
    value: &mut Value,
    call_ids: &mut HashMap<String, String>,
    occurrences: &mut HashMap<String, usize>,
) {
    match value {
        Value::Object(map) => {
            if map.get("type").and_then(Value::as_str) == Some("function_call") {
                if let Some(old_call_id) = map.get("call_id").and_then(Value::as_str) {
                    let payload = stable_function_call_payload(map);
                    let occurrence = occurrences.entry(payload.clone()).or_insert(0);
                    let stable_call_id = deterministic_call_id(&payload, *occurrence);
                    *occurrence += 1;
                    call_ids.insert(old_call_id.to_string(), stable_call_id.clone());
                    map.insert("call_id".to_string(), Value::String(stable_call_id));
                }
            }
            for child in map.values_mut() {
                assign_deterministic_function_call_ids(child, call_ids, occurrences);
            }
        }
        Value::Array(items) => {
            for item in items {
                assign_deterministic_function_call_ids(item, call_ids, occurrences);
            }
        }
        _ => {}
    }
}

fn replace_responses_call_id_refs(value: &mut Value, call_ids: &HashMap<String, String>) {
    match value {
        Value::Object(map) => {
            if let Some(current) = map.get("call_id").and_then(Value::as_str) {
                if let Some(stable) = call_ids.get(current) {
                    map.insert("call_id".to_string(), Value::String(stable.clone()));
                }
            }
            for child in map.values_mut() {
                replace_responses_call_id_refs(child, call_ids);
            }
        }
        Value::Array(items) => {
            for item in items {
                replace_responses_call_id_refs(item, call_ids);
            }
        }
        _ => {}
    }
}

fn stable_function_call_payload(map: &Map<String, Value>) -> String {
    let mut payload = Value::Object(map.clone());
    strip_responses_provider_noise(&mut payload);
    if let Some(object) = payload.as_object_mut() {
        object.remove("call_id");
    }
    canonical_json_string(&payload)
}

fn deterministic_call_id(payload: &str, occurrence: usize) -> String {
    let mut hasher = Sha256::new();
    hasher.update(payload.as_bytes());
    hasher.update(b"\0");
    hasher.update(occurrence.to_string().as_bytes());
    let digest = format!("{:x}", hasher.finalize());
    format!("call_apx_{}", &digest[..24])
}

fn strip_responses_provider_noise(value: &mut Value) {
    match value {
        Value::Object(map) => {
            for key in [
                "id",
                "request_id",
                "client_request_id",
                "trace_id",
                "span_id",
                "event_id",
                "run_id",
                "item_id",
                "tool_call_id",
                "tool_use_id",
                "output_index",
                "content_index",
                "metadata",
                "status",
                "expires_at",
                "completed_at",
                "created_at",
                "updated_at",
            ] {
                map.remove(key);
            }
            for child in map.values_mut() {
                strip_responses_provider_noise(child);
            }
        }
        Value::Array(items) => {
            for item in items {
                strip_responses_provider_noise(item);
            }
        }
        _ => {}
    }
}

fn normalize_responses_request(request: &mut Value) {
    let Some(object) = request.as_object_mut() else {
        return;
    };

    remove_null_or_empty_fields(object);
    if let Some(input) = object.get_mut("input") {
        let mut promoted = None;
        if input.is_string() {
            let original = std::mem::take(input);
            *input = normalized_prompt_input(original);
        } else {
            promoted = promote_responses_instruction_input(input);
            normalize_responses_input(input);
        }
        append_instructions(object, promoted);
    } else if let Some(prompt) = object.remove("prompt") {
        object.insert("input".to_string(), normalized_prompt_input(prompt));
    } else if let Some(messages) = object.remove("messages") {
        append_instructions(object, extract_system_text_from_messages(&messages));
        object.insert("input".to_string(), normalized_messages_input(messages));
    }
    for alias in ["max_tokens", "max_completion_tokens"] {
        if let Some(max_tokens) = object.remove(alias) {
            object
                .entry("max_output_tokens".to_string())
                .or_insert(max_tokens);
        }
    }
    if let Some(tools) = object.get_mut("tools") {
        normalize_tool_definitions(tools);
    }
    if let Some(tool_choice) = object.get_mut("tool_choice") {
        canonicalize_object_keys(tool_choice, "$.tool_choice");
    }
    if let Some(input) = object.get_mut("input") {
        normalize_responses_input(input);
    }
    remove_null_or_empty_fields(object);
    canonicalize_object_keys(request, "$.responses");
}

fn normalized_prompt_input(prompt: Value) -> Value {
    match prompt {
        Value::String(text) => json!([{
            "type": "message",
            "role": "user",
            "content": [{ "type": "input_text", "text": text }]
        }]),
        other => other,
    }
}

fn normalized_messages_input(messages: Value) -> Value {
    let Value::Array(items) = messages else {
        return normalized_prompt_input(messages);
    };
    let normalized = items
        .into_iter()
        .filter(|message| {
            !is_instruction_role(
                message
                    .get("role")
                    .and_then(Value::as_str)
                    .unwrap_or_default(),
            )
        })
        .map(|message| {
            let mut normalized = message;
            normalize_responses_input(&mut normalized);
            normalized
        })
        .collect::<Vec<_>>();
    Value::Array(normalized)
}

fn extract_system_text_from_messages(messages: &Value) -> Option<String> {
    let items = messages.as_array()?;
    let parts = items
        .iter()
        .filter(|message| {
            is_instruction_role(
                message
                    .get("role")
                    .and_then(Value::as_str)
                    .unwrap_or_default(),
            )
        })
        .filter_map(|message| {
            message
                .get("content")
                .or_else(|| message.get("text"))
                .and_then(extract_text)
        })
        .collect::<Vec<_>>();
    merge_text_parts(parts)
}

fn promote_responses_instruction_input(input: &mut Value) -> Option<String> {
    let Value::Array(items) = input else {
        return None;
    };

    let mut promoted = Vec::new();
    let mut retained = Vec::with_capacity(items.len());
    for item in std::mem::take(items) {
        let role = item.get("role").and_then(Value::as_str).unwrap_or_default();
        if is_instruction_role(role) {
            if let Some(text) = item
                .get("content")
                .or_else(|| item.get("text"))
                .and_then(extract_text)
            {
                promoted.push(text);
            }
        } else {
            retained.push(item);
        }
    }
    *items = retained;
    merge_text_parts(promoted)
}

fn append_instructions(object: &mut Map<String, Value>, promoted: Option<String>) {
    let Some(promoted) = promoted else {
        return;
    };
    let mut parts = Vec::new();
    if let Some(existing) = object.get("instructions").and_then(extract_text) {
        parts.push(existing);
    }
    if parts
        .last()
        .map(|existing| existing.trim() != promoted.trim())
        .unwrap_or(true)
    {
        parts.push(promoted);
    }
    if let Some(merged) = merge_text_parts(parts) {
        object.insert("instructions".to_string(), Value::String(merged));
    }
}

fn is_instruction_role(role: &str) -> bool {
    matches!(role, "system" | "developer")
}

fn remove_null_or_empty_fields(object: &mut Map<String, Value>) {
    object.retain(|_, value| match value {
        Value::Null => false,
        Value::String(text) => !text.trim().is_empty(),
        Value::Array(items) => !items.is_empty(),
        Value::Object(map) => !map.is_empty(),
        _ => true,
    });
}

fn normalize_tool_definitions(value: &mut Value) {
    let Value::Array(items) = value else {
        canonicalize_object_keys(value, "$.tools");
        return;
    };
    for item in items.iter_mut() {
        normalize_tool_definition(item);
    }
    items.sort_by(|left, right| tool_sort_key(left).cmp(&tool_sort_key(right)));
}

fn normalize_chat_tool_definitions(value: &mut Value) {
    let Value::Array(items) = value else {
        canonicalize_object_keys(value, "$.chat_tools");
        return;
    };
    for item in items.iter_mut() {
        let Some(object) = item.as_object_mut() else {
            canonicalize_object_keys(item, "$.chat_tools[]");
            continue;
        };

        let is_function = object.get("type").and_then(Value::as_str) == Some("function")
            || object.contains_key("function")
            || object.contains_key("name");
        if is_function {
            object.insert("type".to_string(), Value::String("function".to_string()));
            if !object.contains_key("function") {
                let mut function = Map::new();
                for key in ["name", "description", "parameters", "strict"] {
                    if let Some(value) = object.remove(key) {
                        function.insert(key.to_string(), value);
                    }
                }
                object.insert("function".to_string(), Value::Object(function));
            }
            if let Some(function) = object.get_mut("function").and_then(Value::as_object_mut) {
                if let Some(parameters) = function.get_mut("parameters") {
                    normalize_json_schema(parameters);
                }
            }
        }
        canonicalize_object_keys(item, "$.chat_tools[]");
    }
    items.sort_by(|left, right| tool_sort_key(left).cmp(&tool_sort_key(right)));
}

fn normalize_tool_definition(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        canonicalize_object_keys(value, "$.tools[]");
        return;
    };

    if object.get("type").is_none() && object.contains_key("name") {
        object.insert("type".to_string(), Value::String("function".to_string()));
    }

    if let Some(function) = object
        .remove("function")
        .and_then(|value| value.as_object().cloned())
    {
        object
            .entry("type".to_string())
            .or_insert_with(|| Value::String("function".to_string()));
        if let Some(name) = function.get("name").cloned() {
            object.entry("name".to_string()).or_insert(name);
        }
        if let Some(description) = function.get("description").cloned() {
            object
                .entry("description".to_string())
                .or_insert(description);
        }
        if let Some(parameters) = function.get("parameters").cloned() {
            object.entry("parameters".to_string()).or_insert(parameters);
        }
    }

    if let Some(parameters) = object.get_mut("parameters") {
        normalize_json_schema(parameters);
    }
    if let Some(parameters) = object
        .get_mut("function")
        .and_then(Value::as_object_mut)
        .and_then(|function| function.get_mut("parameters"))
    {
        normalize_json_schema(parameters);
    }
    canonicalize_object_keys(value, "$.tools[]");
}

fn tool_sort_key(value: &Value) -> String {
    let tool_type = value
        .get("type")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let name = value
        .get("name")
        .or_else(|| value.pointer("/function/name"))
        .and_then(Value::as_str)
        .unwrap_or_default();
    format!(
        "{tool_type}\0{name}\0{}",
        serde_json::to_string(value).unwrap_or_default()
    )
}

fn normalize_json_schema(value: &mut Value) {
    match value {
        Value::Object(map) => {
            if let Some(required) = map.get_mut("required").and_then(Value::as_array_mut) {
                required.sort_by(|left, right| {
                    left.as_str()
                        .unwrap_or_default()
                        .cmp(right.as_str().unwrap_or_default())
                });
            }
            for child in map.values_mut() {
                normalize_json_schema(child);
            }
        }
        Value::Array(items) => {
            for item in items {
                normalize_json_schema(item);
            }
        }
        _ => {}
    }
}

fn canonicalize_object_keys(value: &mut Value, path: &str) {
    match value {
        Value::Object(map) => {
            let mut keys = map.keys().cloned().collect::<Vec<_>>();
            keys.sort();
            let mut normalized = Map::new();
            for key in keys {
                if let Some(mut child) = map.remove(&key) {
                    canonicalize_object_keys(&mut child, &format!("{path}.{key}"));
                    normalized.insert(key, child);
                }
            }
            *map = normalized;
        }
        Value::Array(items) => {
            if path.ends_with(".required") && items.iter().all(Value::is_string) {
                items.sort_by(|left, right| {
                    left.as_str()
                        .unwrap_or_default()
                        .cmp(right.as_str().unwrap_or_default())
                });
                return;
            }
            for item in items {
                canonicalize_object_keys(item, &format!("{path}[]"));
            }
        }
        _ => {}
    }
}

fn normalize_responses_input(value: &mut Value) {
    match value {
        Value::Object(map) => {
            let item_type = map
                .get("type")
                .and_then(Value::as_str)
                .unwrap_or_default()
                .to_string();
            if item_type == "message"
                || map.contains_key("role")
                || map.contains_key("content")
                || map.contains_key("text")
            {
                normalize_responses_message(map);
                return;
            }
            for (key, child) in map.iter_mut() {
                if matches!(
                    (item_type.as_str(), key.as_str()),
                    ("function_call", "arguments") | ("function_call_output", "output")
                ) {
                    normalize_json_string(child);
                } else {
                    normalize_responses_input(child);
                }
            }
        }
        Value::Array(items) => {
            for item in items {
                normalize_responses_input(item);
            }
        }
        _ => {}
    }
}

fn normalize_responses_message(map: &mut Map<String, Value>) {
    map.entry("type".to_string())
        .or_insert_with(|| Value::String("message".to_string()));
    if !map.contains_key("role") {
        map.insert("role".to_string(), Value::String("user".to_string()));
    }
    if !map.contains_key("content") {
        if let Some(text) = map.remove("text") {
            map.insert("content".to_string(), text);
        }
    }
    if let Some(content) = map.get_mut("content") {
        normalize_content_blocks(content);
    }
}

fn normalize_content_blocks(value: &mut Value) {
    match value {
        Value::String(text) => {
            *value = json!([{ "type": "input_text", "text": text }]);
        }
        Value::Array(items) => {
            for item in items {
                if let Some(object) = item.as_object_mut() {
                    if object.get("type").is_none() && object.contains_key("text") {
                        object.insert("type".to_string(), Value::String("input_text".to_string()));
                    } else if object.get("type").and_then(Value::as_str) == Some("text") {
                        object.insert("type".to_string(), Value::String("input_text".to_string()));
                    }
                }
            }
        }
        _ => {}
    }
}

fn normalize_json_string(value: &mut Value) {
    let Some(text) = value.as_str() else {
        return;
    };
    let trimmed = text.trim();
    if !(trimmed.starts_with('{') || trimmed.starts_with('[')) {
        return;
    }
    if let Ok(parsed) = serde_json::from_str::<Value>(trimmed) {
        *value = Value::String(canonical_json_string(&parsed));
    }
}

fn canonical_json_string(value: &Value) -> String {
    match value {
        Value::Object(map) => {
            let mut keys = map.keys().collect::<Vec<_>>();
            keys.sort();
            let body = keys
                .into_iter()
                .map(|key| format!("{:?}:{}", key, canonical_json_string(&map[key])))
                .collect::<Vec<_>>()
                .join(",");
            format!("{{{body}}}")
        }
        Value::Array(items) => {
            let body = items
                .iter()
                .map(canonical_json_string)
                .collect::<Vec<_>>()
                .join(",");
            format!("[{body}]")
        }
        _ => value.to_string(),
    }
}

fn provider_prompt_cache_key(
    config: &AppConfig,
    decision: &RouteDecision,
    request: &Value,
    channel: &Channel,
) -> String {
    let model_key = provider_prefix_model_key(decision);
    let mut hasher = Sha256::new();
    hasher.update(config.workspace_fingerprint.as_bytes());
    hasher.update(b"\0");
    hasher.update(model_key.as_bytes());
    hasher.update(b"\0");
    hasher.update(channel.label().as_bytes());
    hasher.update(b"\0");
    hasher.update(provider_prompt_cache_key_material(request, channel).as_bytes());
    format!("{:x}", hasher.finalize())
}

fn provider_prompt_cache_key_material(request: &Value, channel: &Channel) -> String {
    if !matches!(channel, Channel::Responses) {
        return provider_prefix_sample(request, channel);
    }

    let mut material = request.clone();
    strip_provider_cache_key_fields(&mut material);
    strip_provider_prefix_context_fields(&mut material);
    canonicalize_responses_instruction_shape(&mut material);
    strip_response_session_volatile_fields(&mut material);
    trim_response_session_input_to_anchor(&mut material);
    stabilize_responses_provider_prefix(&mut material);
    canonicalize_object_keys(&mut material, "$.provider_prompt_cache_key");
    serialize_responses_body_for_provider_prefix(&material)
}

fn provider_prompt_cache_key_for_outbound(
    config: &AppConfig,
    decision: &RouteDecision,
    request: &Value,
    channel: &Channel,
) -> String {
    request
        .get("prompt_cache_key")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|key| provider_prompt_cache_key_is_valid(key))
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| provider_prompt_cache_key(config, decision, request, channel))
}

fn provider_prompt_cache_key_is_valid(key: &str) -> bool {
    !key.is_empty() && key.len() <= 64
}

fn openai_prompt_cache_key(request: &Value) -> Option<String> {
    request
        .get("prompt_cache_key")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
}

fn provider_prefix_fingerprint(request: &Value, channel: &Channel) -> String {
    let mut hasher = Sha256::new();
    hasher.update(channel.label().as_bytes());
    hasher.update(b"\0");
    hasher.update(provider_prefix_fingerprint_sample(request, channel).as_bytes());
    format!("{:x}", hasher.finalize())
}

fn provider_prefix_sample(request: &Value, channel: &Channel) -> String {
    const SAMPLE_CHARS: usize = 64 * 1024;

    let mut prefix = request.clone();
    strip_provider_cache_key_fields(&mut prefix);
    strip_provider_prefix_context_fields(&mut prefix);
    match channel {
        Channel::Responses => {
            canonicalize_responses_instruction_shape(&mut prefix);
            stabilize_responses_provider_prefix(&mut prefix);
            strip_dynamic_invocation_fields(&mut prefix);
            strip_responses_dynamic_provider_cache_tail(&mut prefix);
            canonicalize_object_keys(&mut prefix, "$.provider_prefix_sample");
        }
        Channel::Chat => {
            stabilize_chat_provider_prefix_sample(&mut prefix);
            strip_chat_dynamic_provider_cache_tail(&mut prefix);
            canonicalize_object_keys(&mut prefix, "$.chat_provider_prefix_sample");
        }
        Channel::Anthropic => {}
    }

    let serialized = if matches!(channel, Channel::Responses) {
        serialize_responses_body_for_provider_prefix(&prefix)
    } else if matches!(channel, Channel::Chat) {
        serialize_chat_body_for_provider_prefix(&prefix)
    } else {
        serde_json::to_string(&prefix).unwrap_or_else(|_| "null".to_string())
    };
    serialized.chars().take(SAMPLE_CHARS).collect()
}

fn provider_prefix_fingerprint_sample(request: &Value, channel: &Channel) -> String {
    const SAMPLE_CHARS: usize = 64 * 1024;

    let mut prefix = request.clone();
    strip_provider_cache_key_fields(&mut prefix);
    strip_provider_prefix_context_fields(&mut prefix);
    match channel {
        Channel::Responses => {
            canonicalize_responses_instruction_shape(&mut prefix);
            stabilize_responses_provider_prefix(&mut prefix);
            strip_dynamic_invocation_fields(&mut prefix);
            trim_responses_provider_cache_tail_to_session_anchor(&mut prefix);
            canonicalize_object_keys(&mut prefix, "$.provider_prefix_fingerprint");
        }
        Channel::Chat => {
            stabilize_chat_provider_prefix_sample(&mut prefix);
            strip_chat_dynamic_provider_cache_tail(&mut prefix);
            canonicalize_object_keys(&mut prefix, "$.chat_provider_prefix_fingerprint");
        }
        Channel::Anthropic => {}
    }

    let serialized = if matches!(channel, Channel::Responses) {
        serialize_responses_body_for_provider_prefix(&prefix)
    } else if matches!(channel, Channel::Chat) {
        serialize_chat_body_for_provider_prefix(&prefix)
    } else {
        serde_json::to_string(&prefix).unwrap_or_else(|_| "null".to_string())
    };
    serialized.chars().take(SAMPLE_CHARS).collect()
}

fn strip_provider_prefix_context_fields(value: &mut Value) {
    if let Some(object) = value.as_object_mut() {
        object.remove("model");
    }
}

fn strip_responses_dynamic_provider_cache_tail(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };
    object.remove("input");
    object.remove("previous_response_id");
    object.remove("stream");
    object.remove("include");
    object.remove("metadata");
    object.remove("user");
    object.remove("service_tier");
    object.remove("truncation");
}

fn trim_responses_provider_cache_tail_to_session_anchor(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };
    object.remove("previous_response_id");
    object.remove("stream");
    object.remove("include");
    object.remove("metadata");
    object.remove("user");
    object.remove("service_tier");
    object.remove("truncation");
    if let Some(input) = object.get_mut("input") {
        if let Some(items) = input.as_array_mut() {
            if items.len() > 1 {
                items.truncate(1);
            }
        }
    }
}

fn canonicalize_responses_instruction_shape(request: &mut Value) {
    let Some(object) = request.as_object_mut() else {
        return;
    };

    let mut promoted_parts = Vec::new();
    if let Some(existing) = object.get("instructions").and_then(extract_text) {
        promoted_parts.push(existing);
    }

    if let Some(input) = object.get_mut("input") {
        if let Some(promoted) = promote_responses_instruction_input(input) {
            promoted_parts.push(promoted);
        }
        normalize_responses_input(input);
    }
    if let Some(messages) = object.get_mut("messages") {
        if let Some(promoted) = extract_system_text_from_messages(messages) {
            promoted_parts.push(promoted);
        }
        *messages = normalized_messages_input(std::mem::take(messages));
    }

    object.remove("instructions");
    let mut merged_parts = Vec::new();
    for part in promoted_parts {
        let trimmed = part.trim();
        if !trimmed.is_empty()
            && !merged_parts
                .iter()
                .any(|existing: &String| existing == trimmed)
        {
            merged_parts.push(trimmed.to_string());
        }
    }
    if let Some(merged) = merge_text_parts(merged_parts) {
        object.insert("instructions".to_string(), Value::String(merged));
    }
    remove_null_or_empty_fields(object);
}

fn stabilize_chat_provider_prefix_sample(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };

    for key in [
        "request_id",
        "client_request_id",
        "trace_id",
        "span_id",
        "event_id",
        "run_id",
        "session_id",
        "thread_id",
        "conversation_id",
        "nonce",
        "timestamp",
        "created_at",
        "updated_at",
        "traceparent",
        "metadata",
        "user",
        "stream_options",
    ] {
        object.remove(key);
    }

    if let Some(tools) = object.get_mut("tools") {
        normalize_chat_tool_definitions(tools);
    }
    if let Some(tool_choice) = object.get_mut("tool_choice") {
        canonicalize_object_keys(tool_choice, "$.chat_tool_choice");
    }
    if let Some(response_format) = object.get_mut("response_format") {
        canonicalize_object_keys(response_format, "$.chat_response_format");
    }
    strip_chat_provider_noise(value);
}

fn stabilize_chat_provider_request(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };

    for key in [
        "request_id",
        "client_request_id",
        "trace_id",
        "span_id",
        "event_id",
        "run_id",
        "nonce",
        "timestamp",
        "created_at",
        "updated_at",
        "traceparent",
    ] {
        object.remove(key);
    }

    if let Some(tools) = object.get_mut("tools") {
        normalize_chat_tool_definitions(tools);
    }
    if let Some(tool_choice) = object.get_mut("tool_choice") {
        canonicalize_object_keys(tool_choice, "$.chat_request_tool_choice");
    }
    if let Some(response_format) = object.get_mut("response_format") {
        canonicalize_object_keys(response_format, "$.chat_request_response_format");
    }
    if let Some(messages) = object.get_mut("messages") {
        normalize_chat_messages_for_request(messages);
    }
    canonicalize_object_keys(value, "$.chat_request");
}

fn normalize_chat_messages_for_request(value: &mut Value) {
    let Value::Array(items) = value else {
        return;
    };
    for item in items {
        normalize_chat_message_for_request(item);
    }
}

fn normalize_chat_message_for_request(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };
    if let Some(content) = object.get_mut("content") {
        normalize_chat_content_for_request(content);
    }
    if let Some(tool_calls) = object.get_mut("tool_calls") {
        normalize_chat_tool_calls_for_request(tool_calls);
    }
    if let Some(arguments) = object.get_mut("arguments") {
        normalize_json_string(arguments);
    }
    canonicalize_object_keys(value, "$.chat_request_message");
}

fn normalize_chat_content_for_request(value: &mut Value) {
    match value {
        Value::Array(items) => {
            for item in items {
                canonicalize_object_keys(item, "$.chat_request_content");
            }
        }
        Value::Object(_) => canonicalize_object_keys(value, "$.chat_request_content"),
        _ => {}
    }
}

fn normalize_chat_tool_calls_for_request(value: &mut Value) {
    match value {
        Value::Array(items) => {
            for item in items {
                normalize_chat_tool_calls_for_request(item);
            }
        }
        Value::Object(map) => {
            if let Some(function) = map.get_mut("function") {
                if let Some(arguments) = function.get_mut("arguments") {
                    normalize_json_string(arguments);
                }
                canonicalize_object_keys(function, "$.chat_request_tool_call.function");
            }
            canonicalize_object_keys(value, "$.chat_request_tool_call");
        }
        _ => {}
    }
}

fn strip_chat_dynamic_provider_cache_tail(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };

    if let Some(messages) = object.get_mut("messages") {
        let stable = chat_stable_prefix_messages(messages);
        if stable.is_empty() {
            object.remove("messages");
        } else {
            *messages = Value::Array(stable);
        }
    }

    object.remove("stream");
    object.remove("metadata");
    object.remove("user");
    object.remove("stream_options");
    object.remove("service_tier");
    object.remove("store");
}

fn chat_stable_prefix_messages(messages: &Value) -> Vec<Value> {
    let Some(items) = messages.as_array() else {
        return Vec::new();
    };
    let mut stable = Vec::new();
    for item in items {
        let Some(role) = item.get("role").and_then(Value::as_str) else {
            break;
        };
        if !matches!(role, "system" | "developer") {
            break;
        }
        let mut cloned = item.clone();
        strip_chat_provider_noise(&mut cloned);
        canonicalize_object_keys(&mut cloned, "$.chat_stable_message");
        stable.push(cloned);
    }
    stable
}

fn strip_chat_provider_noise(value: &mut Value) {
    match value {
        Value::Object(map) => {
            for key in [
                "id",
                "request_id",
                "client_request_id",
                "trace_id",
                "span_id",
                "event_id",
                "run_id",
                "session_id",
                "thread_id",
                "conversation_id",
                "tool_call_id",
                "tool_use_id",
                "item_id",
                "output_index",
                "content_index",
                "metadata",
                "status",
                "expires_at",
                "completed_at",
                "created_at",
                "updated_at",
            ] {
                map.remove(key);
            }
            if let Some(content) = map.get_mut("content") {
                normalize_chat_content_for_prefix(content);
            }
            if let Some(arguments) = map.get_mut("arguments") {
                normalize_json_string(arguments);
            }
            for child in map.values_mut() {
                strip_chat_provider_noise(child);
            }
        }
        Value::Array(items) => {
            for item in items {
                strip_chat_provider_noise(item);
            }
        }
        _ => {}
    }
}

fn normalize_chat_content_for_prefix(value: &mut Value) {
    match value {
        Value::Array(items) => {
            for item in items {
                if let Some(object) = item.as_object_mut() {
                    if object.get("type").and_then(Value::as_str) == Some("text") {
                        object
                            .entry("type".to_string())
                            .or_insert_with(|| Value::String("text".to_string()));
                    }
                }
                strip_chat_provider_noise(item);
            }
        }
        Value::Object(_) => strip_chat_provider_noise(value),
        _ => {}
    }
}

fn strip_provider_cache_key_fields(value: &mut Value) {
    cache_capability::strip_all(value);
}

fn apply_openai_prompt_cache_retention(request: &mut Value, decision: &RouteDecision) {
    if !supports_extended_prompt_cache_retention(decision) {
        if let Some(object) = request.as_object_mut() {
            object.remove("prompt_cache_retention");
        }
        return;
    }
    if let Some(object) = request.as_object_mut() {
        object
            .entry("prompt_cache_retention".to_string())
            .or_insert_with(|| Value::String("24h".to_string()));
    }
}

fn supports_extended_prompt_cache_retention(decision: &RouteDecision) -> bool {
    let model = decision.model.trim().to_ascii_lowercase();
    let base_url = decision.provider.base_url.trim().to_ascii_lowercase();
    model.starts_with("gpt-")
        && (base_url.contains("api.openai.com") || decision.provider.prompt_cache_retention_enabled)
}

fn add_anthropic_cache_control(request: &mut Value) {
    const ANTHROPIC_CACHE_BREAKPOINT_LIMIT: usize = 4;
    let mut remaining =
        ANTHROPIC_CACHE_BREAKPOINT_LIMIT.saturating_sub(count_cache_control_fields(request));
    if remaining == 0 {
        return;
    }
    let static_prefix_tokens = estimated_anthropic_static_prefix_tokens(request);

    if let Some(tools) = request.get_mut("tools") {
        if add_cache_control_to_last_object(tools) {
            remaining = remaining.saturating_sub(1);
        }
    }
    if remaining == 0 {
        return;
    }

    if let Some(system) = request.get_mut("system") {
        if add_cache_control_to_content_value(system) {
            remaining = remaining.saturating_sub(1);
        }
    }
    if remaining == 0 {
        return;
    }

    if let Some(messages) = request.get_mut("messages") {
        add_cache_control_to_stable_message_prefix(messages, remaining, static_prefix_tokens);
    }
}

fn stabilize_anthropic_provider_request(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };

    for key in [
        "request_id",
        "client_request_id",
        "trace_id",
        "span_id",
        "event_id",
        "run_id",
        "nonce",
        "timestamp",
        "created_at",
        "updated_at",
        "traceparent",
    ] {
        object.remove(key);
    }

    if let Some(tools) = object.get_mut("tools") {
        normalize_anthropic_tool_definitions(tools);
    }
    if let Some(tool_choice) = object.get_mut("tool_choice") {
        canonicalize_object_keys(tool_choice, "$.anthropic_request_tool_choice");
    }
    if let Some(system) = object.get_mut("system") {
        normalize_anthropic_content_for_request(system);
    }
    if let Some(messages) = object.get_mut("messages") {
        normalize_anthropic_messages_for_request(messages);
    }
    canonicalize_object_keys(value, "$.anthropic_request");
}

fn normalize_anthropic_tool_definitions(value: &mut Value) {
    let Value::Array(items) = value else {
        canonicalize_object_keys(value, "$.anthropic_tools");
        return;
    };
    for item in items.iter_mut() {
        if let Some(schema) = item.get_mut("input_schema") {
            normalize_json_schema(schema);
        }
        canonicalize_object_keys(item, "$.anthropic_tools[]");
    }
    items.sort_by(|left, right| anthropic_tool_sort_key(left).cmp(&anthropic_tool_sort_key(right)));
}

fn anthropic_tool_sort_key(value: &Value) -> String {
    let name = value
        .get("name")
        .and_then(Value::as_str)
        .unwrap_or_default();
    format!(
        "{name}\0{}",
        serde_json::to_string(value).unwrap_or_default()
    )
}

fn normalize_anthropic_messages_for_request(value: &mut Value) {
    let Value::Array(items) = value else {
        return;
    };
    for item in items {
        if let Some(object) = item.as_object_mut() {
            if let Some(content) = object.get_mut("content") {
                normalize_anthropic_content_for_request(content);
            }
            canonicalize_object_keys(item, "$.anthropic_request_message");
        }
    }
}

fn normalize_anthropic_content_for_request(value: &mut Value) {
    match value {
        Value::Array(items) => {
            for item in items {
                if let Some(object) = item.as_object_mut() {
                    if object.get("type").and_then(Value::as_str) == Some("tool_use") {
                        if let Some(input) = object.get_mut("input") {
                            canonicalize_object_keys(input, "$.anthropic_tool_use_input");
                        }
                    }
                    if object.get("type").and_then(Value::as_str) == Some("tool_result") {
                        if let Some(content) = object.get_mut("content") {
                            normalize_anthropic_content_for_request(content);
                        }
                    }
                    canonicalize_object_keys(item, "$.anthropic_content_block");
                }
            }
        }
        Value::Object(_) => canonicalize_object_keys(value, "$.anthropic_content_object"),
        _ => {}
    }
}

fn add_cache_control_to_stable_message_prefix(
    messages: &mut Value,
    remaining: usize,
    static_prefix_tokens: usize,
) -> usize {
    let Some(items) = messages.as_array_mut() else {
        return 0;
    };
    if items.len() < 2 || remaining == 0 {
        return 0;
    }

    let candidates = anthropic_message_cache_breakpoints(items, remaining, static_prefix_tokens);
    if candidates.is_empty() {
        return 0;
    }

    let mut added = 0usize;
    for index in candidates {
        if let Some(message) = items.get_mut(index) {
            if add_cache_control_to_message(message) {
                added += 1;
                if added >= remaining {
                    break;
                }
            }
        }
    }
    added
}

#[derive(Debug, Clone)]
struct AnthropicMessageCacheCandidate {
    index: usize,
    cumulative_tokens: usize,
}

fn anthropic_message_cache_breakpoints(
    items: &[Value],
    remaining: usize,
    static_prefix_tokens: usize,
) -> Vec<usize> {
    const ANTHROPIC_MIN_CACHEABLE_PREFIX_TOKENS: usize = 1024;
    const ANTHROPIC_LOOKBACK_BLOCKS: usize = 20;

    if items.len() < 2 || remaining == 0 {
        return Vec::new();
    }

    let mut cumulative_tokens = static_prefix_tokens;
    let mut stable = Vec::new();
    for (index, message) in items.iter().take(items.len().saturating_sub(1)).enumerate() {
        cumulative_tokens += estimated_anthropic_cache_tokens(message);
        if message_has_cacheable_content(message) {
            stable.push(AnthropicMessageCacheCandidate {
                index,
                cumulative_tokens,
            });
        }
    }

    let eligible = stable
        .into_iter()
        .filter(|candidate| candidate.cumulative_tokens >= ANTHROPIC_MIN_CACHEABLE_PREFIX_TOKENS)
        .collect::<Vec<_>>();
    if eligible.is_empty() {
        return Vec::new();
    }

    let mut selected = Vec::new();
    let mut max_index = usize::MAX;
    while selected.len() < remaining {
        let candidate = eligible
            .iter()
            .rev()
            .find(|candidate| candidate.index <= max_index);
        let Some(candidate) = candidate else {
            break;
        };
        selected.push(candidate.index);
        max_index = candidate.index.saturating_sub(ANTHROPIC_LOOKBACK_BLOCKS);
    }
    selected
}

fn message_has_cacheable_content(message: &Value) -> bool {
    message
        .as_object()
        .map(|object| object.contains_key("content") || object.contains_key("text"))
        .unwrap_or(false)
}

fn add_cache_control_to_message(message: &mut Value) -> bool {
    let Some(object) = message.as_object_mut() else {
        return false;
    };
    if let Some(content) = object.get_mut("content") {
        return add_cache_control_to_content_value(content);
    }
    if let Some(text) = object.get_mut("text") {
        return add_cache_control_to_content_value(text);
    }
    false
}

fn add_cache_control_to_content_value(value: &mut Value) -> bool {
    match value {
        Value::String(text) => {
            *value = json!([{
                "type": "text",
                "text": text,
                "cache_control": { "type": "ephemeral" }
            }]);
            true
        }
        Value::Array(_) => add_cache_control_to_last_object(value),
        Value::Object(object) => {
            let before = object.contains_key("cache_control");
            object
                .entry("cache_control".to_string())
                .or_insert(json!({ "type": "ephemeral" }));
            !before
        }
        _ => false,
    }
}

fn add_cache_control_to_last_object(value: &mut Value) -> bool {
    if let Value::Array(items) = value {
        if let Some(last) = items.iter_mut().rev().find(|item| item.is_object()) {
            if let Some(object) = last.as_object_mut() {
                let before = object.contains_key("cache_control");
                object
                    .entry("cache_control".to_string())
                    .or_insert(json!({ "type": "ephemeral" }));
                return !before;
            }
        }
    }
    false
}

fn count_cache_control_fields(value: &Value) -> usize {
    match value {
        Value::Object(map) => {
            usize::from(map.contains_key("cache_control"))
                + map.values().map(count_cache_control_fields).sum::<usize>()
        }
        Value::Array(items) => items.iter().map(count_cache_control_fields).sum(),
        _ => 0,
    }
}

fn estimated_anthropic_static_prefix_tokens(request: &Value) -> usize {
    request
        .get("tools")
        .map(estimated_anthropic_cache_tokens)
        .unwrap_or(0)
        + request
            .get("system")
            .map(estimated_anthropic_cache_tokens)
            .unwrap_or(0)
}

fn estimated_anthropic_cache_tokens(value: &Value) -> usize {
    match value {
        Value::String(text) => estimated_text_tokens(text),
        Value::Array(items) => items.iter().map(estimated_anthropic_cache_tokens).sum(),
        Value::Object(map) => map
            .iter()
            .filter(|(key, _)| key.as_str() != "cache_control")
            .map(|(key, value)| {
                estimated_text_tokens(key) + estimated_anthropic_cache_tokens(value)
            })
            .sum(),
        _ => 0,
    }
}

fn estimated_text_tokens(text: &str) -> usize {
    let mut ascii_chars = 0usize;
    let mut non_ascii_chars = 0usize;
    for character in text.chars() {
        if character.is_ascii() {
            ascii_chars += 1;
        } else {
            non_ascii_chars += 1;
        }
    }
    ascii_chars.div_ceil(4) + non_ascii_chars
}

fn transform_request_for_channel(
    request: &Value,
    client_channel: &Channel,
    upstream_channel: &Channel,
) -> Value {
    if client_channel == upstream_channel {
        return request.clone();
    }

    match (client_channel, upstream_channel) {
        (Channel::Chat, Channel::Responses) => chat_to_responses_request(request),
        (Channel::Chat, Channel::Anthropic) => chat_to_anthropic_request(request),
        (Channel::Responses, Channel::Chat) => responses_to_chat_request(request),
        (Channel::Responses, Channel::Anthropic) => responses_to_anthropic_request(request),
        (Channel::Anthropic, Channel::Chat) => anthropic_to_chat_request(request),
        (Channel::Anthropic, Channel::Responses) => anthropic_to_responses_request(request),
        _ => request.clone(),
    }
}

fn set_stream_flag(request: &mut Value, stream: bool) {
    if let Some(object) = request.as_object_mut() {
        object.insert("stream".to_string(), Value::Bool(stream));
    }
}

fn infer_client_requested_stream(
    request: &mut Value,
    client_channel: &Channel,
    forced_agent_id: Option<&str>,
) -> bool {
    if forced_agent_id == Some("codex") && matches!(client_channel, Channel::Responses) {
        set_stream_flag(request, true);
        return true;
    }
    if let Some(stream) = request.get("stream").and_then(Value::as_bool) {
        return stream;
    }
    false
}

fn chat_stream_include_usage_requested(request: &Value, client_channel: &Channel) -> bool {
    matches!(client_channel, Channel::Chat)
        && request
            .pointer("/stream_options/include_usage")
            .and_then(Value::as_bool)
            .unwrap_or(false)
}

fn chat_to_responses_request(request: &Value) -> Value {
    let mut object = Map::new();
    copy_model(request, &mut object);
    if let Some(system) = extract_system_text(request, Channel::Chat) {
        object.insert("instructions".to_string(), Value::String(system));
    }
    let messages = chat_messages_to_responses_input(request.get("messages"));
    if !messages.is_empty() {
        object.insert("input".to_string(), Value::Array(messages));
    }
    copy_fields(
        request,
        &mut object,
        &[
            ("stream", "stream"),
            ("temperature", "temperature"),
            ("top_p", "top_p"),
            ("tools", "tools"),
            ("tool_choice", "tool_choice"),
            ("metadata", "metadata"),
            ("response_format", "response_format"),
            ("seed", "seed"),
            ("presence_penalty", "presence_penalty"),
            ("frequency_penalty", "frequency_penalty"),
            ("n", "n"),
            ("logit_bias", "logit_bias"),
            ("user", "user"),
            ("parallel_tool_calls", "parallel_tool_calls"),
        ],
    );
    copy_max_tokens(request, &mut object, "max_output_tokens");
    if let Some(effort) = request_reasoning_effort(request) {
        object.insert("reasoning".to_string(), json!({ "effort": effort }));
    }
    if let Some(stop) = request.get("stop").cloned() {
        object.insert("stop".to_string(), stop);
    }
    Value::Object(object)
}

fn chat_to_anthropic_request(request: &Value) -> Value {
    let mut object = Map::new();
    copy_model(request, &mut object);
    if let Some(system) = extract_system_text(request, Channel::Chat) {
        object.insert("system".to_string(), Value::String(system));
    }
    let messages = extract_messages(request, Channel::Chat);
    if !messages.is_empty() {
        object.insert("messages".to_string(), Value::Array(messages));
    }
    let max_tokens = request
        .get("max_tokens")
        .or_else(|| request.get("max_output_tokens"))
        .and_then(Value::as_u64)
        .unwrap_or(4096);
    object.insert("max_tokens".to_string(), Value::Number(max_tokens.into()));
    copy_fields(
        request,
        &mut object,
        &[
            ("stream", "stream"),
            ("temperature", "temperature"),
            ("top_p", "top_p"),
            ("tools", "tools"),
            ("tool_choice", "tool_choice"),
            ("metadata", "metadata"),
            ("top_k", "top_k"),
            ("thinking", "thinking"),
        ],
    );
    if let Some(stop_sequences) = normalize_stop_sequences(request.get("stop")) {
        object.insert("stop_sequences".to_string(), stop_sequences);
    } else if let Some(stop_sequences) = normalize_stop_sequences(request.get("stop_sequences")) {
        object.insert("stop_sequences".to_string(), stop_sequences);
    }
    Value::Object(object)
}

fn responses_to_chat_request(request: &Value) -> Value {
    let mut object = Map::new();
    copy_model(request, &mut object);
    let mut messages = extract_messages(request, Channel::Responses);
    if let Some(system) = extract_system_text(request, Channel::Responses) {
        messages.insert(
            0,
            json!({
                "role": "system",
                "content": system,
            }),
        );
    }
    if !messages.is_empty() {
        object.insert("messages".to_string(), Value::Array(messages));
    }
    copy_fields(
        request,
        &mut object,
        &[
            ("stream", "stream"),
            ("temperature", "temperature"),
            ("top_p", "top_p"),
            ("tools", "tools"),
            ("tool_choice", "tool_choice"),
            ("metadata", "metadata"),
            ("response_format", "response_format"),
            ("seed", "seed"),
            ("presence_penalty", "presence_penalty"),
            ("frequency_penalty", "frequency_penalty"),
            ("n", "n"),
            ("logit_bias", "logit_bias"),
            ("user", "user"),
            ("parallel_tool_calls", "parallel_tool_calls"),
        ],
    );
    copy_max_tokens(request, &mut object, "max_tokens");
    if let Some(effort) = request_reasoning_effort(request) {
        object.insert("reasoning_effort".to_string(), Value::String(effort));
    }
    if let Some(stop) = request.get("stop").cloned() {
        object.insert("stop".to_string(), stop);
    }
    Value::Object(object)
}

fn responses_to_anthropic_request(request: &Value) -> Value {
    let tool_context = transform_codex_chat::build_codex_tool_context_from_request(request);
    responses_to_anthropic_request_with_context(request, &tool_context)
}

fn responses_to_anthropic_request_with_context(
    request: &Value,
    tool_context: &transform_codex_chat::CodexToolContext,
) -> Value {
    let mut object = Map::new();
    copy_model(request, &mut object);
    if let Some(system) = extract_system_text(request, Channel::Responses) {
        object.insert("system".to_string(), Value::String(system));
    }
    let messages = responses_to_anthropic_messages(request.get("input"), tool_context);
    if !messages.is_empty() {
        object.insert("messages".to_string(), Value::Array(messages));
    }
    let max_tokens = request
        .get("max_output_tokens")
        .or_else(|| request.get("max_tokens"))
        .and_then(Value::as_u64)
        .unwrap_or(4096);
    object.insert("max_tokens".to_string(), Value::Number(max_tokens.into()));
    copy_fields(
        request,
        &mut object,
        &[
            ("stream", "stream"),
            ("temperature", "temperature"),
            ("top_p", "top_p"),
            ("top_k", "top_k"),
            ("thinking", "thinking"),
        ],
    );
    let tools = responses_tools_to_anthropic(tool_context);
    if !tools.is_empty() {
        object.insert("tools".to_string(), Value::Array(tools));
        if let Some(tool_choice) = request
            .get("tool_choice")
            .and_then(|value| responses_tool_choice_to_anthropic(value, tool_context))
        {
            object.insert("tool_choice".to_string(), tool_choice);
        }
    }
    if let Some(user_id) = request
        .pointer("/metadata/user_id")
        .or_else(|| request.get("user"))
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
    {
        object.insert("metadata".to_string(), json!({ "user_id": user_id }));
    }
    if let Some(stop_sequences) = normalize_stop_sequences(request.get("stop")) {
        object.insert("stop_sequences".to_string(), stop_sequences);
    }
    Value::Object(object)
}

fn responses_tools_to_anthropic(
    tool_context: &transform_codex_chat::CodexToolContext,
) -> Vec<Value> {
    tool_context
        .chat_tools()
        .iter()
        .filter_map(|tool| {
            let function = tool.get("function")?;
            let name = function.get("name").and_then(Value::as_str)?.trim();
            if name.is_empty() {
                return None;
            }
            let mut result = Map::new();
            result.insert("name".to_string(), Value::String(name.to_string()));
            if let Some(description) = function
                .get("description")
                .and_then(Value::as_str)
                .filter(|value| !value.trim().is_empty())
            {
                result.insert(
                    "description".to_string(),
                    Value::String(description.to_string()),
                );
            }
            result.insert(
                "input_schema".to_string(),
                function
                    .get("parameters")
                    .cloned()
                    .unwrap_or_else(|| json!({ "type": "object", "properties": {} })),
            );
            Some(Value::Object(result))
        })
        .collect()
}

fn responses_tool_choice_to_anthropic(
    tool_choice: &Value,
    tool_context: &transform_codex_chat::CodexToolContext,
) -> Option<Value> {
    match tool_choice {
        Value::String(value) => match value.trim().to_ascii_lowercase().as_str() {
            "auto" => Some(json!({ "type": "auto" })),
            "required" | "any" => Some(json!({ "type": "any" })),
            "none" => None,
            _ => None,
        },
        Value::Object(object) => match object.get("type").and_then(Value::as_str) {
            Some("function") => {
                let name = object
                    .get("name")
                    .and_then(Value::as_str)
                    .unwrap_or_default();
                if name.is_empty() {
                    return None;
                }
                let namespace = object.get("namespace").and_then(Value::as_str);
                Some(json!({
                    "type": "tool",
                    "name": tool_context.chat_name_for_response_function(name, namespace)
                }))
            }
            Some("custom") => object
                .get("name")
                .and_then(Value::as_str)
                .filter(|name| !name.is_empty())
                .map(|name| json!({ "type": "tool", "name": name })),
            Some("tool_search") => Some(json!({
                "type": "tool",
                "name": transform_codex_chat::TOOL_SEARCH_PROXY_NAME
            })),
            Some("auto") => Some(json!({ "type": "auto" })),
            Some("required") | Some("any") => Some(json!({ "type": "any" })),
            _ => None,
        },
        _ => None,
    }
}

fn responses_to_anthropic_messages(
    input: Option<&Value>,
    tool_context: &transform_codex_chat::CodexToolContext,
) -> Vec<Value> {
    let mut messages = Vec::new();
    if let Some(Value::String(text)) = input {
        if !text.is_empty() {
            push_anthropic_message(
                &mut messages,
                "user",
                vec![json!({ "type": "text", "text": text })],
            );
        }
        return messages;
    }
    let mut pending_thinking = Vec::new();
    let mut pending_tool_uses = Vec::new();
    let items = match input {
        Some(Value::Array(items)) => items.iter().collect::<Vec<_>>(),
        Some(value) => vec![value],
        None => Vec::new(),
    };

    for item in items {
        match item.get("type").and_then(Value::as_str) {
            Some("function_call") => {
                if let Some(block) =
                    responses_function_call_to_anthropic_tool_use(item, tool_context)
                {
                    pending_tool_uses.push(block);
                }
            }
            Some("custom_tool_call") => {
                if let Some(block) = responses_custom_tool_call_to_anthropic_tool_use(item) {
                    pending_tool_uses.push(block);
                }
            }
            Some("tool_search_call") => {
                if let Some(block) = responses_tool_search_call_to_anthropic_tool_use(item) {
                    pending_tool_uses.push(block);
                }
            }
            Some("function_call_output")
            | Some("custom_tool_call_output")
            | Some("tool_search_output") => {
                flush_pending_anthropic_assistant(
                    &mut messages,
                    &mut pending_thinking,
                    &mut pending_tool_uses,
                );
                if let Some(block) = responses_tool_output_to_anthropic_result(item) {
                    push_anthropic_message(&mut messages, "user", vec![block]);
                }
            }
            Some("reasoning") => {
                if let Some(block) =
                    streaming_codex_anthropic::decode_anthropic_reasoning_envelope(item)
                {
                    pending_thinking.push(block);
                }
            }
            _ => {
                flush_pending_anthropic_assistant(
                    &mut messages,
                    &mut pending_thinking,
                    &mut pending_tool_uses,
                );
                if let Some((role, content)) = responses_message_to_anthropic(item) {
                    push_anthropic_message(&mut messages, role, content);
                }
            }
        }
    }
    flush_pending_anthropic_assistant(&mut messages, &mut pending_thinking, &mut pending_tool_uses);
    messages
}

fn flush_pending_anthropic_assistant(
    messages: &mut Vec<Value>,
    pending_thinking: &mut Vec<Value>,
    pending_tool_uses: &mut Vec<Value>,
) {
    if pending_thinking.is_empty() && pending_tool_uses.is_empty() {
        return;
    }
    let mut content = std::mem::take(pending_thinking);
    content.append(pending_tool_uses);
    push_anthropic_message(messages, "assistant", content);
}

fn responses_function_call_to_anthropic_tool_use(
    item: &Value,
    tool_context: &transform_codex_chat::CodexToolContext,
) -> Option<Value> {
    let call_id = item
        .get("call_id")
        .or_else(|| item.get("id"))
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())?;
    let name = item.get("name").and_then(Value::as_str)?.trim();
    if name.is_empty() {
        return None;
    }
    let namespace = item.get("namespace").and_then(Value::as_str);
    let chat_name = tool_context.chat_name_for_response_function(name, namespace);
    Some(json!({
        "type": "tool_use",
        "id": call_id,
        "name": chat_name,
        "input": anthropic_tool_input(item.get("arguments"))
    }))
}

fn responses_custom_tool_call_to_anthropic_tool_use(item: &Value) -> Option<Value> {
    let call_id = item
        .get("call_id")
        .or_else(|| item.get("id"))
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())?;
    let name = item.get("name").and_then(Value::as_str)?.trim();
    if name.is_empty() {
        return None;
    }
    Some(json!({
        "type": "tool_use",
        "id": call_id,
        "name": name,
        "input": { "input": item.get("input").cloned().unwrap_or_else(|| json!("")) }
    }))
}

fn responses_tool_search_call_to_anthropic_tool_use(item: &Value) -> Option<Value> {
    let call_id = item
        .get("call_id")
        .or_else(|| item.get("id"))
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())?;
    Some(json!({
        "type": "tool_use",
        "id": call_id,
        "name": transform_codex_chat::TOOL_SEARCH_PROXY_NAME,
        "input": anthropic_tool_input(item.get("arguments"))
    }))
}

fn anthropic_tool_input(arguments: Option<&Value>) -> Value {
    let arguments = json_canonical::canonicalize_tool_arguments(arguments);
    match serde_json::from_str::<Value>(&arguments) {
        Ok(Value::Object(object)) => Value::Object(object),
        Ok(value) => json!({ "input": value }),
        Err(_) => json!({ "input": arguments }),
    }
}

fn responses_tool_output_to_anthropic_result(item: &Value) -> Option<Value> {
    let call_id = item
        .get("call_id")
        .or_else(|| item.get("id"))
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())?;
    let content = match item.get("output") {
        Some(Value::String(text)) => Value::String(text.clone()),
        Some(value) => Value::String(json_canonical::canonical_json_string(value)),
        None => Value::String(String::new()),
    };
    Some(json!({
        "type": "tool_result",
        "tool_use_id": call_id,
        "content": content
    }))
}

fn responses_message_to_anthropic(item: &Value) -> Option<(&'static str, Vec<Value>)> {
    let role = item.get("role").and_then(Value::as_str).unwrap_or("user");
    let role = match role {
        "assistant" => "assistant",
        "system" | "developer" | "latest_reminder" => return None,
        _ => "user",
    };
    let content = item
        .get("content")
        .or_else(|| item.get("text"))
        .or_else(|| item.get("input_text"))
        .or_else(|| item.get("output_text"))?;
    let content = responses_content_to_anthropic(content);
    (!content.is_empty()).then_some((role, content))
}

fn responses_content_to_anthropic(value: &Value) -> Vec<Value> {
    match value {
        Value::String(text) => (!text.is_empty())
            .then(|| json!({ "type": "text", "text": text }))
            .into_iter()
            .collect(),
        Value::Array(items) => items
            .iter()
            .flat_map(responses_content_to_anthropic)
            .collect(),
        Value::Object(object) => {
            let type_name = object
                .get("type")
                .and_then(Value::as_str)
                .unwrap_or_default();
            match type_name {
                "input_text" | "output_text" | "text" => object
                    .get("text")
                    .and_then(Value::as_str)
                    .filter(|text| !text.is_empty())
                    .map(|text| vec![json!({ "type": "text", "text": text })])
                    .unwrap_or_default(),
                "input_image" if object.get("image_url").and_then(Value::as_str).is_some() => {
                    let url = object
                        .get("image_url")
                        .and_then(Value::as_str)
                        .unwrap_or_default();
                    vec![json!({ "type": "image", "source": { "type": "url", "url": url } })]
                }
                _ => extract_text(value)
                    .filter(|text| !text.is_empty())
                    .map(|text| vec![json!({ "type": "text", "text": text })])
                    .unwrap_or_default(),
            }
        }
        _ => Vec::new(),
    }
}

fn push_anthropic_message(messages: &mut Vec<Value>, role: &str, mut content: Vec<Value>) {
    if content.is_empty() {
        return;
    }
    if let Some(last_content) = messages.last_mut().and_then(|last| {
        (last.get("role").and_then(Value::as_str) == Some(role))
            .then(|| last.get_mut("content").and_then(Value::as_array_mut))
            .flatten()
    }) {
        last_content.append(&mut content);
        return;
    }
    messages.push(json!({ "role": role, "content": content }));
}

fn anthropic_to_chat_request(request: &Value) -> Value {
    let mut object = Map::new();
    copy_model(request, &mut object);
    let mut messages = anthropic_messages_to_chat_messages(request.get("messages"));
    if let Some(system) = extract_system_text(request, Channel::Anthropic) {
        messages.insert(
            0,
            json!({
                "role": "system",
                "content": system,
            }),
        );
    }
    if !messages.is_empty() {
        object.insert("messages".to_string(), Value::Array(messages));
    }
    copy_fields(
        request,
        &mut object,
        &[
            ("stream", "stream"),
            ("temperature", "temperature"),
            ("top_p", "top_p"),
            ("metadata", "metadata"),
        ],
    );
    let tools = anthropic_tools_to_chat(request.get("tools"));
    if !tools.is_empty() {
        object.insert("tools".to_string(), Value::Array(tools));
        if let Some(tool_choice) = request
            .get("tool_choice")
            .and_then(anthropic_tool_choice_to_chat)
        {
            object.insert("tool_choice".to_string(), tool_choice);
        }
        if request
            .pointer("/tool_choice/disable_parallel_tool_use")
            .and_then(Value::as_bool)
            == Some(true)
        {
            object.insert("parallel_tool_calls".to_string(), Value::Bool(false));
        }
    }
    copy_max_tokens(request, &mut object, "max_tokens");
    if let Some(stop_sequences) = normalize_stop_sequences(request.get("stop_sequences")) {
        object.insert("stop".to_string(), stop_sequences);
    } else if let Some(stop) = request.get("stop").cloned() {
        object.insert("stop".to_string(), stop);
    }
    Value::Object(object)
}

fn anthropic_to_responses_request(request: &Value) -> Value {
    let mut object = Map::new();
    copy_model(request, &mut object);
    if let Some(system) = extract_system_text(request, Channel::Anthropic) {
        object.insert("instructions".to_string(), Value::String(system));
    }
    let messages = anthropic_messages_to_responses_input(request.get("messages"));
    if !messages.is_empty() {
        object.insert("input".to_string(), Value::Array(messages));
    }
    let max_tokens = request
        .get("max_tokens")
        .or_else(|| request.get("max_output_tokens"))
        .and_then(Value::as_u64)
        .unwrap_or(4096);
    object.insert(
        "max_output_tokens".to_string(),
        Value::Number(max_tokens.into()),
    );
    copy_fields(
        request,
        &mut object,
        &[
            ("stream", "stream"),
            ("temperature", "temperature"),
            ("top_p", "top_p"),
            ("metadata", "metadata"),
        ],
    );
    let tools = anthropic_tools_to_responses(request.get("tools"));
    if !tools.is_empty() {
        object.insert("tools".to_string(), Value::Array(tools));
        if let Some(tool_choice) = request
            .get("tool_choice")
            .and_then(anthropic_tool_choice_to_responses)
        {
            object.insert("tool_choice".to_string(), tool_choice);
        }
        if request
            .pointer("/tool_choice/disable_parallel_tool_use")
            .and_then(Value::as_bool)
            == Some(true)
        {
            object.insert("parallel_tool_calls".to_string(), Value::Bool(false));
        }
    }
    Value::Object(object)
}

/// Reject invalid Anthropic tool histories before they can become upstream
/// Chat tool messages or Responses `function_call_output` items. Both target
/// protocols require every tool result to immediately follow the assistant
/// turn that created the call, and require that assistant turn's full call set
/// to be consumed before any later conversational turn.
fn validate_anthropic_tool_history(request: &Value) -> Result<(), String> {
    let Some(messages) = request.get("messages").and_then(Value::as_array) else {
        return Ok(());
    };

    let mut seen_calls = std::collections::HashSet::new();
    let mut pending_calls: Option<std::collections::HashSet<String>> = None;
    for (message_index, message) in messages.iter().enumerate() {
        let role = message.get("role").and_then(Value::as_str).ok_or_else(|| {
            format!("Anthropic message at messages[{message_index}] is missing role")
        })?;
        if !matches!(role, "user" | "assistant") {
            return Err(format!(
                "Anthropic message at messages[{message_index}] has unsupported role `{role}`"
            ));
        }
        let blocks = anthropic_message_content_blocks(
            message
                .get("content")
                .or_else(|| message.get("text"))
                .or_else(|| message.get("message")),
        );

        if let Some(expected_calls) = pending_calls.take() {
            if role != "user" {
                return Err(format!(
                    "Anthropic tool_use calls before messages[{message_index}] must be followed immediately by a user tool_result message"
                ));
            }

            let mut consumed_calls = std::collections::HashSet::new();
            let mut result_prefix_ended = false;
            for (block_index, block) in blocks.iter().enumerate() {
                match block.get("type").and_then(Value::as_str) {
                    Some("tool_result") => {
                        if result_prefix_ended {
                            return Err(format!(
                                "Anthropic tool_result at messages[{message_index}].content[{block_index}] must appear before ordinary user content"
                            ));
                        }
                        let call_id = block
                            .get("tool_use_id")
                            .or_else(|| block.get("call_id"))
                            .and_then(Value::as_str)
                            .filter(|value| !value.is_empty())
                            .ok_or_else(|| {
                                format!(
                                    "Anthropic tool_result at messages[{message_index}].content[{block_index}] is missing tool_use_id"
                                )
                            })?;
                        if !expected_calls.contains(call_id) {
                            return Err(format!(
                                "Anthropic tool_result references unknown or already-consumed tool_use_id `{call_id}`"
                            ));
                        }
                        if !consumed_calls.insert(call_id.to_string()) {
                            return Err(format!(
                                "Anthropic tool_result references unknown or already-consumed tool_use_id `{call_id}`"
                            ));
                        }
                    }
                    Some("tool_use") => {
                        return Err(format!(
                            "Anthropic tool_use at messages[{message_index}].content[{block_index}] must appear in an assistant message"
                        ));
                    }
                    _ => result_prefix_ended = true,
                }
            }

            if consumed_calls.is_empty() {
                return Err(format!(
                    "Anthropic tool_use calls before messages[{message_index}] must be consumed by immediate user tool_result blocks"
                ));
            }
            if consumed_calls != expected_calls {
                return Err(format!(
                    "Anthropic tool_result message at messages[{message_index}] must consume every preceding tool_use before continuing"
                ));
            }
            continue;
        }

        let mut calls_in_message = std::collections::HashSet::new();
        for (block_index, block) in blocks.iter().enumerate() {
            match (role, block.get("type").and_then(Value::as_str)) {
                ("assistant", Some("tool_use")) => {
                    let call_id = block
                        .get("id")
                        .or_else(|| block.get("tool_use_id"))
                        .and_then(Value::as_str)
                        .filter(|value| !value.is_empty())
                        .ok_or_else(|| {
                            format!(
                                "Anthropic tool_use at messages[{message_index}].content[{block_index}] is missing id"
                            )
                        })?;
                    if block
                        .get("name")
                        .and_then(Value::as_str)
                        .map_or(true, |name| name.trim().is_empty())
                    {
                        return Err(format!(
                            "Anthropic tool_use at messages[{message_index}].content[{block_index}] is missing name"
                        ));
                    }
                    if !seen_calls.insert(call_id.to_string()) {
                        return Err(format!("Anthropic tool_use id `{call_id}` is duplicated"));
                    }
                    calls_in_message.insert(call_id.to_string());
                }
                ("assistant", Some("tool_result")) => {
                    return Err(format!(
                        "Anthropic tool_result at messages[{message_index}].content[{block_index}] must appear in a user message"
                    ));
                }
                ("user", Some("tool_use")) => {
                    return Err(format!(
                        "Anthropic tool_use at messages[{message_index}].content[{block_index}] must appear in an assistant message"
                    ));
                }
                ("user", Some("tool_result")) => {
                    return Err(format!(
                        "Anthropic tool_result references unknown or already-consumed tool_use_id"
                    ));
                }
                _ => {}
            }
        }
        if !calls_in_message.is_empty() {
            pending_calls = Some(calls_in_message);
        }
    }
    if pending_calls.is_some() {
        return Err(
            "Anthropic tool_use calls must be followed immediately by a user tool_result message"
                .to_string(),
        );
    }
    Ok(())
}

/// Convert native Anthropic Messages history to Responses input without
/// flattening tool calls/results into text.  The generic message normalizer is
/// intentionally not used here: it cannot preserve `tool_use_id`, which is
/// the only stable join key for a following tool-result turn.
fn anthropic_messages_to_responses_input(messages: Option<&Value>) -> Vec<Value> {
    let Some(messages) = messages.and_then(Value::as_array) else {
        return Vec::new();
    };

    let mut input = Vec::new();
    for message in messages {
        let role = message
            .get("role")
            .and_then(Value::as_str)
            .unwrap_or("user");
        let blocks = anthropic_message_content_blocks(
            message
                .get("content")
                .or_else(|| message.get("text"))
                .or_else(|| message.get("message")),
        );
        match role {
            "assistant" => anthropic_assistant_blocks_to_responses(&mut input, blocks),
            _ => anthropic_user_blocks_to_responses(&mut input, blocks),
        }
    }
    input
}

fn anthropic_message_content_blocks(content: Option<&Value>) -> Vec<Value> {
    match content {
        Some(Value::Array(blocks)) => blocks.clone(),
        Some(Value::String(text)) if !text.trim().is_empty() => {
            vec![json!({ "type": "text", "text": text })]
        }
        Some(value) if !value.is_null() => vec![value.clone()],
        _ => Vec::new(),
    }
}

/// Convert Anthropic Messages history to native Chat Completions messages
/// without collapsing `tool_use` / `tool_result` links into text. Chat allows
/// an assistant message to carry text and `tool_calls`, then requires each
/// corresponding result as a separate `role: tool` message.
fn anthropic_messages_to_chat_messages(messages: Option<&Value>) -> Vec<Value> {
    let Some(messages) = messages.and_then(Value::as_array) else {
        return Vec::new();
    };

    let mut output = Vec::new();
    for message in messages {
        let role = message
            .get("role")
            .and_then(Value::as_str)
            .unwrap_or("user");
        let blocks = anthropic_message_content_blocks(
            message
                .get("content")
                .or_else(|| message.get("text"))
                .or_else(|| message.get("message")),
        );
        if role == "assistant" {
            anthropic_assistant_blocks_to_chat(&mut output, blocks);
        } else {
            anthropic_user_blocks_to_chat(&mut output, blocks);
        }
    }
    output
}

fn anthropic_assistant_blocks_to_chat(output: &mut Vec<Value>, blocks: Vec<Value>) {
    let mut text_parts = Vec::new();
    let mut tool_calls = Vec::new();
    for block in blocks {
        match block.get("type").and_then(Value::as_str) {
            Some("tool_use") => {
                if let Some(call) = anthropic_tool_use_to_chat_call(&block) {
                    tool_calls.push(call);
                }
            }
            // There is no safe Chat equivalent for a signed Anthropic thinking
            // block. Never downgrade it into forged reasoning metadata.
            Some("thinking") | Some("redacted_thinking") => {}
            _ => append_anthropic_chat_text(&mut text_parts, &block),
        }
    }
    if text_parts.is_empty() && tool_calls.is_empty() {
        return;
    }
    let mut message = Map::new();
    message.insert("role".to_string(), Value::String("assistant".to_string()));
    message.insert(
        "content".to_string(),
        merge_text_parts(text_parts)
            .map(Value::String)
            .unwrap_or(Value::Null),
    );
    if !tool_calls.is_empty() {
        message.insert("tool_calls".to_string(), Value::Array(tool_calls));
    }
    output.push(Value::Object(message));
}

fn anthropic_user_blocks_to_chat(output: &mut Vec<Value>, blocks: Vec<Value>) {
    let mut text_parts = Vec::new();
    for block in blocks {
        if block.get("type").and_then(Value::as_str) == Some("tool_result") {
            flush_anthropic_chat_text(output, &mut text_parts);
            if let Some(call_id) = block
                .get("tool_use_id")
                .or_else(|| block.get("call_id"))
                .and_then(Value::as_str)
                .filter(|value| !value.is_empty())
            {
                output.push(json!({
                    "role": "tool",
                    "tool_call_id": call_id,
                    "content": anthropic_tool_result_output(&block),
                }));
            } else {
                let text = anthropic_tool_result_output(&block);
                if !text.trim().is_empty() {
                    text_parts.push(text);
                }
            }
        } else if !matches!(
            block.get("type").and_then(Value::as_str),
            Some("thinking") | Some("redacted_thinking")
        ) {
            append_anthropic_chat_text(&mut text_parts, &block);
        }
    }
    flush_anthropic_chat_text(output, &mut text_parts);
}

fn append_anthropic_chat_text(text_parts: &mut Vec<String>, block: &Value) {
    let text = match block.get("type").and_then(Value::as_str) {
        Some("text") => block
            .get("text")
            .and_then(Value::as_str)
            .map(ToOwned::to_owned),
        Some("tool_result") => Some(anthropic_tool_result_output(block)),
        _ => extract_text(block),
    };
    if let Some(text) = text.filter(|text| !text.trim().is_empty()) {
        text_parts.push(text);
    }
}

fn flush_anthropic_chat_text(output: &mut Vec<Value>, text_parts: &mut Vec<String>) {
    let Some(content) = merge_text_parts(std::mem::take(text_parts)) else {
        return;
    };
    output.push(json!({ "role": "user", "content": content }));
}

fn anthropic_tool_use_to_chat_call(block: &Value) -> Option<Value> {
    let call_id = block
        .get("id")
        .or_else(|| block.get("tool_use_id"))
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())?;
    let name = block
        .get("name")
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())?;
    Some(json!({
        "id": call_id,
        "type": "function",
        "function": {
            "name": name,
            "arguments": block
                .get("input")
                .map(json_canonical::canonical_json_string)
                .unwrap_or_else(|| "{}".to_string()),
        }
    }))
}

fn anthropic_assistant_blocks_to_responses(input: &mut Vec<Value>, blocks: Vec<Value>) {
    let mut message_content = Vec::new();
    for block in blocks {
        match block.get("type").and_then(Value::as_str) {
            Some("tool_use") => {
                flush_anthropic_message_content(input, "assistant", &mut message_content);
                if let Some(tool_call) = anthropic_tool_use_to_responses_call(&block) {
                    input.push(tool_call);
                }
            }
            Some("thinking") | Some("redacted_thinking") => {
                flush_anthropic_message_content(input, "assistant", &mut message_content);
                if let Some(reasoning) =
                    streaming_codex_anthropic::encode_anthropic_reasoning_envelope(&block)
                {
                    input.push(reasoning);
                }
            }
            _ => append_anthropic_text_content(&mut message_content, &block),
        }
    }
    flush_anthropic_message_content(input, "assistant", &mut message_content);
}

fn anthropic_user_blocks_to_responses(input: &mut Vec<Value>, blocks: Vec<Value>) {
    let mut message_content = Vec::new();
    for block in blocks {
        if block.get("type").and_then(Value::as_str) == Some("tool_result") {
            if let Some(call_id) = block
                .get("tool_use_id")
                .or_else(|| block.get("call_id"))
                .and_then(Value::as_str)
                .filter(|value| !value.is_empty())
            {
                flush_anthropic_message_content(input, "user", &mut message_content);
                input.push(json!({
                    "type": "function_call_output",
                    "call_id": call_id,
                    "output": anthropic_tool_result_output(&block),
                }));
            } else {
                // A missing id cannot be represented as a valid Responses
                // tool output. Retain the caller's content as user text rather
                // than inventing a call id that can attach to the wrong call.
                append_anthropic_text_content(&mut message_content, &block);
            }
        } else {
            append_anthropic_text_content(&mut message_content, &block);
        }
    }
    flush_anthropic_message_content(input, "user", &mut message_content);
}

fn flush_anthropic_message_content(input: &mut Vec<Value>, role: &str, content: &mut Vec<Value>) {
    if content.is_empty() {
        return;
    }
    input.push(json!({
        "type": "message",
        "role": role,
        "content": std::mem::take(content),
    }));
}

fn append_anthropic_text_content(content: &mut Vec<Value>, block: &Value) {
    let text = match block.get("type").and_then(Value::as_str) {
        Some("text") => block
            .get("text")
            .and_then(Value::as_str)
            .map(ToOwned::to_owned),
        Some("tool_result") => Some(anthropic_tool_result_output(block)),
        _ => extract_text(block),
    };
    if let Some(text) = text.filter(|text| !text.trim().is_empty()) {
        content.push(json!({ "type": "input_text", "text": text }));
    }
}

fn anthropic_tool_use_to_responses_call(block: &Value) -> Option<Value> {
    let call_id = block
        .get("id")
        .or_else(|| block.get("tool_use_id"))
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())?;
    let name = block
        .get("name")
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())?;
    Some(json!({
        "type": "function_call",
        "call_id": call_id,
        "name": name,
        "arguments": block
            .get("input")
            .map(json_canonical::canonical_json_string)
            .unwrap_or_else(|| "{}".to_string()),
    }))
}

fn anthropic_tool_result_output(block: &Value) -> String {
    let Some(content) = block.get("content") else {
        return String::new();
    };
    let output = match content {
        Value::String(text) => text.clone(),
        Value::Array(parts) => {
            let text = parts
                .iter()
                .filter_map(|part| {
                    (part.get("type").and_then(Value::as_str) == Some("text"))
                        .then(|| part.get("text").and_then(Value::as_str))
                        .flatten()
                })
                .collect::<Vec<_>>();
            if text.len() == parts.len() {
                text.join("\n")
            } else {
                json_canonical::canonical_json_string(content)
            }
        }
        value => json_canonical::canonical_json_string(value),
    };
    if block.get("is_error").and_then(Value::as_bool) == Some(true) {
        format!("[tool_result_error]\n{output}")
    } else {
        output
    }
}

fn anthropic_tools_to_responses(tools: Option<&Value>) -> Vec<Value> {
    tools
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(|tool| {
            let name = tool.get("name").and_then(Value::as_str)?.trim();
            if name.is_empty() {
                return None;
            }
            let mut result = Map::new();
            result.insert("type".to_string(), Value::String("function".to_string()));
            result.insert("name".to_string(), Value::String(name.to_string()));
            if let Some(description) = tool
                .get("description")
                .and_then(Value::as_str)
                .filter(|value| !value.trim().is_empty())
            {
                result.insert(
                    "description".to_string(),
                    Value::String(description.to_string()),
                );
            }
            result.insert(
                "parameters".to_string(),
                tool.get("input_schema")
                    .or_else(|| tool.get("parameters"))
                    .cloned()
                    .unwrap_or_else(|| json!({ "type": "object", "properties": {} })),
            );
            Some(Value::Object(result))
        })
        .collect()
}

fn anthropic_tools_to_chat(tools: Option<&Value>) -> Vec<Value> {
    tools
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(|tool| {
            let name = tool.get("name").and_then(Value::as_str)?.trim();
            if name.is_empty() {
                return None;
            }
            let mut function = Map::new();
            function.insert("name".to_string(), Value::String(name.to_string()));
            if let Some(description) = tool
                .get("description")
                .and_then(Value::as_str)
                .filter(|value| !value.trim().is_empty())
            {
                function.insert(
                    "description".to_string(),
                    Value::String(description.to_string()),
                );
            }
            function.insert(
                "parameters".to_string(),
                tool.get("input_schema")
                    .or_else(|| tool.get("parameters"))
                    .cloned()
                    .unwrap_or_else(|| json!({ "type": "object", "properties": {} })),
            );
            Some(json!({ "type": "function", "function": function }))
        })
        .collect()
}

fn anthropic_tool_choice_to_responses(value: &Value) -> Option<Value> {
    match value.get("type").and_then(Value::as_str) {
        Some("auto") => Some(Value::String("auto".to_string())),
        Some("any") | Some("required") => Some(Value::String("required".to_string())),
        Some("none") => Some(Value::String("none".to_string())),
        Some("tool") => value
            .get("name")
            .and_then(Value::as_str)
            .filter(|name| !name.trim().is_empty())
            .map(|name| json!({ "type": "function", "name": name })),
        _ => None,
    }
}

fn anthropic_tool_choice_to_chat(value: &Value) -> Option<Value> {
    match value.get("type").and_then(Value::as_str) {
        Some("auto") => Some(Value::String("auto".to_string())),
        Some("any") | Some("required") => Some(Value::String("required".to_string())),
        Some("none") => Some(Value::String("none".to_string())),
        Some("tool") => value
            .get("name")
            .and_then(Value::as_str)
            .filter(|name| !name.trim().is_empty())
            .map(|name| json!({ "type": "function", "function": { "name": name } })),
        _ => None,
    }
}

fn copy_model(request: &Value, object: &mut Map<String, Value>) {
    if let Some(model) = request.get("model").cloned() {
        object.insert("model".to_string(), model);
    }
}

fn copy_fields(request: &Value, object: &mut Map<String, Value>, fields: &[(&str, &str)]) {
    for (source, target) in fields {
        if let Some(value) = request.get(source).cloned() {
            if !value.is_null() {
                object.insert((*target).to_string(), value);
            }
        }
    }
}

fn copy_max_tokens(request: &Value, object: &mut Map<String, Value>, target: &str) {
    for source in ["max_tokens", "max_output_tokens"] {
        if let Some(value) = request.get(source).cloned() {
            if !value.is_null() {
                object.insert(target.to_string(), value);
                return;
            }
        }
    }
}

fn normalize_stop_sequences(value: Option<&Value>) -> Option<Value> {
    let value = value?;
    let mut items = Vec::new();
    match value {
        Value::String(text) if !text.trim().is_empty() => {
            items.push(Value::String(text.clone()));
        }
        Value::Array(array) => {
            for item in array {
                if let Some(text) = item.as_str().filter(|text| !text.trim().is_empty()) {
                    items.push(Value::String(text.to_string()));
                }
            }
        }
        _ => {
            if let Some(text) = extract_text(value) {
                if !text.trim().is_empty() {
                    items.push(Value::String(text));
                }
            }
        }
    }
    if items.is_empty() {
        None
    } else {
        Some(Value::Array(items))
    }
}

fn extract_system_text(request: &Value, source: Channel) -> Option<String> {
    let mut parts = Vec::new();
    match source {
        Channel::Chat => {
            if let Some(text) = request.get("system").and_then(extract_text) {
                parts.push(text);
            }
            if let Some(messages) = request.get("messages").and_then(Value::as_array) {
                for message in messages {
                    if is_instruction_role(
                        message
                            .get("role")
                            .and_then(Value::as_str)
                            .unwrap_or_default(),
                    ) {
                        if let Some(text) = message
                            .get("content")
                            .or_else(|| message.get("text"))
                            .and_then(extract_text)
                        {
                            parts.push(text);
                        }
                    }
                }
            }
        }
        Channel::Responses => {
            if let Some(text) = request.get("instructions").and_then(extract_text) {
                parts.push(text);
            }
            if let Some(messages) = request.get("messages").and_then(Value::as_array) {
                for message in messages {
                    if is_instruction_role(
                        message
                            .get("role")
                            .and_then(Value::as_str)
                            .unwrap_or_default(),
                    ) {
                        if let Some(text) = message
                            .get("content")
                            .or_else(|| message.get("text"))
                            .and_then(extract_text)
                        {
                            parts.push(text);
                        }
                    }
                }
            }
            if let Some(input) = request.get("input") {
                if let Some(text) = input.as_array().and_then(|items| {
                    items
                        .iter()
                        .filter(|item| {
                            is_instruction_role(
                                item.get("role").and_then(Value::as_str).unwrap_or_default(),
                            )
                        })
                        .filter_map(|item| {
                            item.get("content")
                                .or_else(|| item.get("text"))
                                .and_then(extract_text)
                        })
                        .reduce(|left, right| format!("{left}\n\n{right}"))
                }) {
                    parts.push(text);
                }
            }
        }
        Channel::Anthropic => {
            if let Some(text) = request.get("system").and_then(extract_text) {
                parts.push(text);
            }
            if let Some(messages) = request.get("messages").and_then(Value::as_array) {
                for message in messages {
                    if is_instruction_role(
                        message
                            .get("role")
                            .and_then(Value::as_str)
                            .unwrap_or_default(),
                    ) {
                        if let Some(text) = message
                            .get("content")
                            .or_else(|| message.get("text"))
                            .and_then(extract_text)
                        {
                            parts.push(text);
                        }
                    }
                }
            }
        }
    }

    merge_text_parts(parts)
}

/// Convert Chat history into Responses input without flattening a completed
/// assistant tool call and its matching tool result into user text.
///
/// This deliberately lives only on the Chat -> Responses path: the Anthropic
/// conversion has a different tool schema and continues to use
/// normalize_message.
fn chat_messages_to_responses_input(messages: Option<&Value>) -> Vec<Value> {
    let Some(messages) = messages.and_then(Value::as_array) else {
        return Vec::new();
    };
    let mut input = Vec::new();
    for (message_index, message) in messages.iter().enumerate() {
        let role = message
            .get("role")
            .and_then(Value::as_str)
            .unwrap_or("user");
        match role {
            "assistant" => {
                if let Some(normalized) = normalize_message(message) {
                    input.push(normalized);
                }
                let tool_calls = message
                    .get("tool_calls")
                    .and_then(Value::as_array)
                    .cloned()
                    .or_else(|| message.get("function_call").cloned().map(|call| vec![call]))
                    .unwrap_or_default();
                for (tool_index, call) in tool_calls.iter().enumerate() {
                    if let Some(item) =
                        chat_tool_call_to_responses_item(call, message_index, tool_index)
                    {
                        input.push(item);
                    }
                }
            }
            "tool" => {
                let call_id = message
                    .get("tool_call_id")
                    .or_else(|| message.get("call_id"))
                    .and_then(Value::as_str)
                    .filter(|id| !id.is_empty());
                if let Some(call_id) = call_id {
                    input.push(json!({
                        "type": "function_call_output",
                        "call_id": call_id,
                        "output": chat_tool_output_string(message),
                    }));
                } else if let Some(normalized) = normalize_message(message) {
                    // An id-less legacy tool message cannot be represented as
                    // a valid Responses tool output. Retain its text rather
                    // than silently discarding caller data.
                    input.push(normalized);
                }
            }
            _ => {
                if let Some(normalized) = normalize_message(message) {
                    input.push(normalized);
                }
            }
        }
    }
    input
}

fn chat_tool_call_to_responses_item(
    call: &Value,
    message_index: usize,
    tool_index: usize,
) -> Option<Value> {
    let function = call.get("function").unwrap_or(call);
    let name = function
        .get("name")
        .or_else(|| call.get("name"))
        .and_then(Value::as_str)
        .filter(|name| !name.is_empty())?;
    let call_id = call
        .get("id")
        .or_else(|| call.get("call_id"))
        .and_then(Value::as_str)
        .filter(|id| !id.is_empty())
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| format!("call_{message_index}_{tool_index}"));
    let arguments = function
        .get("arguments")
        .or_else(|| call.get("arguments"))
        .map(chat_tool_json_string)
        .unwrap_or_default();
    Some(json!({
        "type": "function_call",
        "call_id": call_id,
        "name": name,
        "arguments": arguments,
    }))
}

fn chat_tool_output_string(message: &Value) -> String {
    let content = message
        .get("content")
        .or_else(|| message.get("output"))
        .or_else(|| message.get("text"));
    match content {
        None | Some(Value::Null) => String::new(),
        Some(Value::String(text)) => text.clone(),
        Some(Value::Array(_)) => extract_text(content.unwrap())
            .unwrap_or_else(|| chat_tool_json_string(content.unwrap())),
        Some(value) => chat_tool_json_string(value),
    }
}

fn chat_tool_json_string(value: &Value) -> String {
    value
        .as_str()
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| canonical_json_string(value))
}

fn extract_messages(request: &Value, source: Channel) -> Vec<Value> {
    match source {
        Channel::Chat | Channel::Anthropic => request
            .get("messages")
            .and_then(Value::as_array)
            .map(|messages| {
                messages
                    .iter()
                    .filter_map(normalize_message)
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default(),
        Channel::Responses => {
            let mut messages = Vec::new();
            if let Some(items) = request.get("input").and_then(Value::as_array) {
                for item in items {
                    if let Some(message) = normalize_message(item) {
                        messages.push(message);
                    }
                }
            } else if let Some(input) = request.get("input") {
                if let Some(text) = extract_text(input) {
                    messages.push(json!({
                        "role": "user",
                        "content": text,
                    }));
                }
            }
            if messages.is_empty() {
                if let Some(legacy) = request.get("messages").and_then(Value::as_array) {
                    for item in legacy {
                        if let Some(message) = normalize_message(item) {
                            messages.push(message);
                        }
                    }
                }
            }
            messages
        }
    }
}

fn normalize_message(message: &Value) -> Option<Value> {
    let object = message.as_object()?;
    let role = object.get("role").and_then(Value::as_str).unwrap_or("user");
    if is_instruction_role(role) {
        return None;
    }
    let normalized_role = match role {
        "assistant" => "assistant",
        "tool" => "user",
        _ => "user",
    };
    let content = object
        .get("content")
        .or_else(|| object.get("text"))
        .or_else(|| object.get("input_text"))
        .or_else(|| object.get("output_text"))
        .or_else(|| object.get("message"))?;
    let text = extract_text(content)?;
    if text.trim().is_empty() {
        return None;
    }
    Some(json!({
        "role": normalized_role,
        "content": text,
    }))
}

fn extract_text(value: &Value) -> Option<String> {
    match value {
        Value::String(text) => {
            let trimmed = text.trim();
            if trimmed.is_empty() {
                None
            } else {
                Some(trimmed.to_string())
            }
        }
        Value::Array(items) => {
            let mut parts = Vec::new();
            for item in items {
                if let Some(text) = extract_text(item) {
                    parts.push(text);
                }
            }
            merge_text_parts(parts)
        }
        Value::Object(map) => {
            for key in [
                "text",
                "output_text",
                "content",
                "message",
                "input",
                "instructions",
                "system",
                "delta",
                "reason",
            ] {
                if let Some(text) = map.get(key).and_then(extract_text) {
                    return Some(text);
                }
            }
            if let Some(type_value) = map.get("type").and_then(Value::as_str) {
                if matches!(type_value, "text" | "output_text" | "input_text") {
                    if let Some(text) = map.get("text").and_then(Value::as_str) {
                        let trimmed = text.trim();
                        if !trimmed.is_empty() {
                            return Some(trimmed.to_string());
                        }
                    }
                }
            }
            None
        }
        _ => None,
    }
}

fn merge_text_parts(parts: Vec<String>) -> Option<String> {
    let merged = parts
        .into_iter()
        .map(|part| part.trim().to_string())
        .filter(|part| !part.is_empty())
        .collect::<Vec<_>>()
        .join("\n\n");
    let trimmed = merged.trim().to_string();
    if trimmed.is_empty() {
        None
    } else {
        Some(trimmed)
    }
}

fn transform_response_bytes(
    client_channel: &Channel,
    upstream_channel: &Channel,
    model: &str,
    bytes: &[u8],
) -> Vec<u8> {
    if client_channel == upstream_channel {
        return bytes.to_vec();
    }
    let Ok(value) = serde_json::from_slice::<Value>(bytes) else {
        return bytes.to_vec();
    };
    if value.get("error").is_some_and(|error| !error.is_null()) {
        return bytes.to_vec();
    }
    let transformed = transform_response_value(client_channel, model, &value);
    serde_json::to_vec(&transformed).unwrap_or_else(|_| bytes.to_vec())
}

fn normalize_response_body_for_client(
    client_channel: &Channel,
    _content_type: &str,
    body: Vec<u8>,
    non_sse_compact_compat: bool,
) -> Vec<u8> {
    if non_sse_compact_compat && matches!(client_channel, Channel::Responses) {
        normalize_responses_json_for_client(&body)
    } else {
        body
    }
}

fn maybe_normalize_responses_json_for_client(bytes: &[u8], enabled: bool) -> Vec<u8> {
    if enabled {
        normalize_responses_json_for_client(bytes)
    } else {
        bytes.to_vec()
    }
}

fn non_sse_compact_compat_for_decision(config: &AppConfig, decision: &RouteDecision) -> bool {
    config.non_sse_compact_compat_enabled_for_provider(&decision.provider.id)
}

fn normalize_responses_json_for_client(bytes: &[u8]) -> Vec<u8> {
    let Ok(mut value) = serde_json::from_slice::<Value>(bytes) else {
        return bytes.to_vec();
    };
    if value.get("error").is_some_and(|error| !error.is_null()) {
        return bytes.to_vec();
    }
    let is_response = value
        .get("object")
        .and_then(Value::as_str)
        .is_some_and(|object| object == "response")
        || value.get("output").is_some_and(Value::is_array);
    if !is_response {
        return bytes.to_vec();
    }

    let response_id = value
        .get("id")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| format!("resp_{}", Uuid::new_v4().simple()));
    let Some(output) = value.get_mut("output").and_then(Value::as_array_mut) else {
        return serde_json::to_vec(&value).unwrap_or_else(|_| bytes.to_vec());
    };
    for (output_index, item) in output.iter_mut().enumerate() {
        let Some(item_object) = item.as_object_mut() else {
            continue;
        };
        if !item_object.get("id").is_some_and(Value::is_string) {
            item_object.insert(
                "id".to_string(),
                Value::String(format!("msg_{}_{}", response_id, output_index)),
            );
        }
        let Some(content) = item_object.get_mut("content").and_then(Value::as_array_mut) else {
            continue;
        };
        for content_item in content.iter_mut() {
            let Some(content_object) = content_item.as_object_mut() else {
                continue;
            };
            if !content_object
                .get("annotations")
                .is_some_and(Value::is_array)
            {
                content_object.insert("annotations".to_string(), Value::Array(Vec::new()));
            }
        }
    }

    serde_json::to_vec(&value).unwrap_or_else(|_| bytes.to_vec())
}

fn is_text_event_stream(content_type: &str) -> bool {
    content_type
        .to_ascii_lowercase()
        .contains("text/event-stream")
}

fn should_proxy_upstream_as_stream(
    is_success_status: bool,
    client_requested_stream: bool,
    buffered_cross_protocol_stream: bool,
    _requires_sse_content_type: bool,
    _upstream_body: &Value,
    content_type: &str,
) -> bool {
    if !is_success_status || !client_requested_stream || buffered_cross_protocol_stream {
        return false;
    }
    // The outbound stream flag is not proof that this upstream response is
    // SSE. A 2xx JSON body can carry response.failed; buffer and settle
    // non-SSE bodies so semantic errors never become successful relays.
    is_text_event_stream(content_type)
}

fn supports_incremental_cross_protocol_stream(
    client_channel: &Channel,
    upstream_channel: &Channel,
) -> bool {
    matches!(
        (client_channel, upstream_channel),
        (Channel::Responses, Channel::Chat | Channel::Anthropic)
            | (Channel::Chat, Channel::Responses | Channel::Anthropic)
            | (Channel::Anthropic, Channel::Responses | Channel::Chat)
    )
}

fn route_supports_incremental_cross_protocol_stream(
    client_channel: &Channel,
    decision: &RouteDecision,
) -> bool {
    supports_incremental_cross_protocol_stream(client_channel, &decision.upstream_channel)
        && model_for_route_decision(decision)
            .map(|model| model.supports_streaming)
            .unwrap_or(true)
}

fn responses_sse_to_non_stream_json(
    bytes: &[u8],
    model: &str,
    non_sse_compact_compat: bool,
) -> Vec<u8> {
    if serde_json::from_slice::<Value>(bytes).is_ok() {
        return maybe_normalize_responses_json_for_client(bytes, non_sse_compact_compat);
    }

    let text = String::from_utf8_lossy(bytes);
    let mut current_event: Option<String> = None;
    let mut data_lines: Vec<String> = Vec::new();
    let mut completed_response: Option<Value> = None;
    let mut assembled_text = String::new();
    let mut usage: Option<Value> = None;
    let mut response_id: Option<String> = None;
    let mut response_model: Option<String> = None;

    let flush_event = |event: Option<&str>,
                       data_lines: &mut Vec<String>,
                       completed_response: &mut Option<Value>,
                       assembled_text: &mut String,
                       usage: &mut Option<Value>,
                       response_id: &mut Option<String>,
                       response_model: &mut Option<String>| {
        if data_lines.is_empty() {
            return;
        }
        let payload = data_lines.join("\n");
        data_lines.clear();
        let payload = payload.trim();
        if payload.is_empty() || payload == "[DONE]" {
            return;
        }
        let Ok(value) = serde_json::from_str::<Value>(payload) else {
            return;
        };
        let event_type = value.get("type").and_then(Value::as_str).or(event);
        if let Some(id) = response_id_from_value(&value) {
            *response_id = Some(id);
        }
        if let Some(model_value) = extract_model(&value) {
            *response_model = Some(model_value);
        }
        if let Some(value_usage) = value
            .get("usage")
            .or_else(|| value.pointer("/response/usage"))
            .cloned()
        {
            *usage = Some(value_usage);
        }
        if event_type == Some("response.completed") {
            if let Some(response) = value.get("response").cloned() {
                if let Some(id) = response_id_from_value(&response) {
                    *response_id = Some(id);
                }
                if let Some(model_value) = extract_model(&response) {
                    *response_model = Some(model_value);
                }
                if let Some(value_usage) = response.get("usage").cloned() {
                    *usage = Some(value_usage);
                }
                *completed_response = Some(response);
                return;
            }
            if value
                .get("object")
                .and_then(Value::as_str)
                .is_some_and(|object| object == "response")
                || value.get("output").is_some_and(Value::is_array)
            {
                *completed_response = Some(value);
                return;
            }
        }
        if value
            .get("object")
            .and_then(Value::as_str)
            .is_some_and(|object| object == "response")
            || value.get("output").is_some_and(Value::is_array)
        {
            *completed_response = Some(value);
            return;
        }
        if event_type == Some("response.output_text.delta") {
            if let Some(delta) = value.get("delta").and_then(Value::as_str) {
                assembled_text.push_str(delta);
            }
        } else if let Some(delta) = value
            .get("delta")
            .and_then(|delta| delta.get("text"))
            .and_then(Value::as_str)
        {
            assembled_text.push_str(delta);
        } else if let Some(delta) = value.get("text").and_then(Value::as_str) {
            assembled_text.push_str(delta);
        }
    };

    for raw_line in text.lines() {
        let line = raw_line.trim_end_matches('\r');
        if line.is_empty() {
            flush_event(
                current_event.as_deref(),
                &mut data_lines,
                &mut completed_response,
                &mut assembled_text,
                &mut usage,
                &mut response_id,
                &mut response_model,
            );
            current_event = None;
            continue;
        }
        if let Some(event) = line.strip_prefix("event:") {
            current_event = Some(event.trim().to_string());
        } else if let Some(data) = line.strip_prefix("data:") {
            data_lines.push(data.trim_start().to_string());
        }
    }
    flush_event(
        current_event.as_deref(),
        &mut data_lines,
        &mut completed_response,
        &mut assembled_text,
        &mut usage,
        &mut response_id,
        &mut response_model,
    );

    if let Some(response) = completed_response {
        return maybe_normalize_responses_json_for_client(
            &serde_json::to_vec(&response).unwrap_or_else(|_| bytes.to_vec()),
            non_sse_compact_compat,
        );
    }
    if assembled_text.is_empty() {
        return bytes.to_vec();
    }

    let response_id = response_id.unwrap_or_else(|| format!("resp_{}", Uuid::new_v4().simple()));
    let response = json!({
        "id": response_id,
        "object": "response",
        "created_at": Utc::now().timestamp(),
        "model": response_model.unwrap_or_else(|| model.to_string()),
        "status": "completed",
        "output": [{
            "type": "message",
            "id": format!("msg_{}_0", response_id),
            "role": "assistant",
            "content": [{
                "type": "output_text",
                "text": assembled_text,
                "annotations": [],
            }],
        }],
        "output_text": assembled_text,
        "usage": usage,
    });
    maybe_normalize_responses_json_for_client(
        &serde_json::to_vec(&response).unwrap_or_else(|_| bytes.to_vec()),
        non_sse_compact_compat,
    )
}

fn chat_sse_to_non_stream_json(bytes: &[u8], model: &str) -> Vec<u8> {
    if serde_json::from_slice::<Value>(bytes).is_ok() {
        return bytes.to_vec();
    }

    let text = String::from_utf8_lossy(bytes);
    let mut current_event: Option<String> = None;
    let mut data_lines: Vec<String> = Vec::new();
    let mut assembled_text = String::new();
    let mut response_id: Option<String> = None;
    let mut response_model: Option<String> = None;
    let mut usage: Option<Value> = None;
    let mut finish_reason: Option<String> = None;
    let mut error: Option<Value> = None;
    let mut saw_done_marker = false;
    let mut saw_payload = false;

    let flush_chat_payload = |event: Option<&str>,
                              data_lines: &mut Vec<String>,
                              assembled_text: &mut String,
                              response_id: &mut Option<String>,
                              response_model: &mut Option<String>,
                              usage: &mut Option<Value>,
                              finish_reason: &mut Option<String>,
                              error: &mut Option<Value>,
                              saw_done_marker: &mut bool,
                              saw_payload: &mut bool| {
        if data_lines.is_empty() {
            return;
        }
        let payload = data_lines.join("\n");
        data_lines.clear();
        let payload = payload.trim();
        if payload.is_empty() {
            return;
        }
        if payload == "[DONE]" {
            *saw_done_marker = true;
            return;
        }
        let Ok(value) = serde_json::from_str::<Value>(payload) else {
            return;
        };
        *saw_payload = true;
        if event == Some("error")
            || value.get("error").is_some_and(|error| !error.is_null())
            || value.get("type").and_then(Value::as_str) == Some("error")
        {
            *error = Some(normalize_sse_error_value(&value));
            return;
        }
        if let Some(id) = value.get("id").and_then(Value::as_str) {
            *response_id = Some(id.to_string());
        }
        if let Some(model_value) = extract_model(&value) {
            *response_model = Some(model_value);
        }
        if let Some(value_usage) = value
            .get("usage")
            .or_else(|| value.pointer("/x_gpt/usage"))
            .or_else(|| value.pointer("/response/usage"))
            .cloned()
        {
            *usage = Some(value_usage);
        }
        if let Some(choices) = value.get("choices").and_then(Value::as_array) {
            for choice in choices {
                if let Some(content) = choice.pointer("/delta/content").and_then(extract_text) {
                    assembled_text.push_str(&content);
                } else if let Some(content) =
                    choice.pointer("/message/content").and_then(extract_text)
                {
                    assembled_text.push_str(&content);
                }
                if let Some(reason) = choice.get("finish_reason").and_then(Value::as_str) {
                    *finish_reason = Some(reason.to_string());
                }
            }
        }
    };

    for line in text.lines() {
        let trimmed = line.trim_end();
        if trimmed.is_empty() {
            flush_chat_payload(
                current_event.as_deref(),
                &mut data_lines,
                &mut assembled_text,
                &mut response_id,
                &mut response_model,
                &mut usage,
                &mut finish_reason,
                &mut error,
                &mut saw_done_marker,
                &mut saw_payload,
            );
            current_event = None;
            continue;
        }
        let trimmed_start = trimmed.trim_start();
        if let Some(event) = trimmed_start.strip_prefix("event:") {
            current_event = Some(event.trim().to_string());
        } else if let Some(payload) = trimmed_start.strip_prefix("data:") {
            data_lines.push(payload.trim_start().to_string());
        };
    }
    flush_chat_payload(
        current_event.as_deref(),
        &mut data_lines,
        &mut assembled_text,
        &mut response_id,
        &mut response_model,
        &mut usage,
        &mut finish_reason,
        &mut error,
        &mut saw_done_marker,
        &mut saw_payload,
    );

    if let Some(error) = error {
        return serde_json::to_vec(&error).unwrap_or_else(|_| bytes.to_vec());
    }
    if assembled_text.trim().is_empty() && saw_payload && !saw_done_marker {
        let error = json!({
            "error": {
                "message": "chat-compatible compact stream ended without a completion marker or output text",
                "type": "atoapi_compact_stream_incomplete",
            }
        });
        return serde_json::to_vec(&error).unwrap_or_else(|_| bytes.to_vec());
    }

    let response = json!({
        "id": response_id.unwrap_or_else(|| format!("chatcmpl_{}", Uuid::new_v4().simple())),
        "object": "chat.completion",
        "created": Utc::now().timestamp(),
        "model": response_model.unwrap_or_else(|| model.to_string()),
        "choices": [{
            "index": 0,
            "message": {
                "role": "assistant",
                "content": assembled_text,
            },
            "finish_reason": finish_reason.unwrap_or_else(|| "stop".to_string()),
        }],
        "usage": usage.unwrap_or_else(|| json!({})),
    });
    serde_json::to_vec(&response).unwrap_or_else(|_| bytes.to_vec())
}

fn normalize_sse_error_value(value: &Value) -> Value {
    if let Some(error) = value.get("error").filter(|error| !error.is_null()) {
        return json!({ "error": error });
    }
    let message = value
        .pointer("/message")
        .or_else(|| value.pointer("/delta/message"))
        .or_else(|| value.pointer("/response/error/message"))
        .and_then(extract_text)
        .unwrap_or_else(|| value.to_string());
    json!({
        "error": {
            "message": message,
            "type": value
                .get("type")
                .and_then(Value::as_str)
                .unwrap_or("upstream_sse_error"),
        }
    })
}

fn json_body_has_error(bytes: &[u8]) -> bool {
    serde_json::from_slice::<Value>(bytes)
        .ok()
        .is_some_and(|value| json_value_has_error(&value))
}

fn transform_response_value(client_channel: &Channel, model: &str, value: &Value) -> Value {
    let response_id = value
        .get("id")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| format!("resp-{}", Uuid::new_v4().simple()));
    let text = extract_response_text(value).unwrap_or_else(|| value.to_string());
    let finish_reason = extract_finish_reason(value);
    let usage = normalize_usage(value.get("usage"));
    let created = Utc::now().timestamp();
    match client_channel {
        Channel::Chat => json!({
            "id": response_id,
            "object": "chat.completion",
            "created": created,
            "model": extract_model(value).unwrap_or_else(|| model.to_string()),
            "choices": [{
                "index": 0,
                "message": {
                    "role": "assistant",
                    "content": text,
                },
                "finish_reason": finish_reason,
            }],
            "usage": usage,
        }),
        Channel::Responses => json!({
            "id": response_id,
            "object": "response",
            "created_at": created,
            "model": extract_model(value).unwrap_or_else(|| model.to_string()),
            "status": "completed",
            "output": [{
                "type": "message",
                "id": format!("msg-{}", Uuid::new_v4().simple()),
                "role": "assistant",
                "content": [{
                    "type": "output_text",
                    "text": text,
                }],
            }],
            "output_text": text,
            "usage": usage,
        }),
        Channel::Anthropic => json!({
            "id": response_id,
            "type": "message",
            "role": "assistant",
            "model": extract_model(value).unwrap_or_else(|| model.to_string()),
            "content": [{
                "type": "text",
                "text": text,
            }],
            "stop_reason": finish_reason.unwrap_or_else(|| "end_turn".to_string()),
            "usage": usage.unwrap_or_else(|| json!({})),
        }),
    }
}

fn response_json_to_sse(channel: &Channel, bytes: &[u8]) -> Vec<u8> {
    let payload = String::from_utf8_lossy(bytes).to_string();
    let Ok(value) = serde_json::from_str::<Value>(&payload) else {
        return format!("data: {payload}\n\ndata: [DONE]\n\n").into_bytes();
    };
    let text = extract_response_text(&value).unwrap_or(payload.clone());
    match channel {
        Channel::Chat => {
            let chunk = json!({
                "id": value.get("id").cloned().unwrap_or_else(|| Value::String(format!("chunk-{}", Uuid::new_v4().simple()))),
                "object": "chat.completion.chunk",
                "created": Utc::now().timestamp(),
                "model": extract_model(&value).unwrap_or_else(|| "unknown".to_string()),
                "choices": [{
                    "index": 0,
                    "delta": {
                        "role": "assistant",
                        "content": text,
                    },
                    "finish_reason": Value::Null,
                }],
            });
            format!(
                "data: {}\n\ndata: [DONE]\n\n",
                serde_json::to_string(&chunk).unwrap_or_else(|_| payload.clone())
            )
            .into_bytes()
        }
        Channel::Responses => {
            let completed = serde_json::to_string(&value).unwrap_or_else(|_| payload.clone());
            let delta = json!({
                "type": "response.output_text.delta",
                "delta": text,
            });
            format!(
                "event: response.output_text.delta\ndata: {}\n\nevent: response.completed\ndata: {}\n\n",
                serde_json::to_string(&delta).unwrap_or_else(|_| "{}".to_string()),
                completed
            )
            .into_bytes()
        }
        Channel::Anthropic => {
            let message_start = json!({
                "type": "message_start",
                "message": {
                    "id": value.get("id").cloned().unwrap_or_else(|| Value::String(format!("msg-{}", Uuid::new_v4().simple()))),
                    "type": "message",
                    "role": "assistant",
                    "model": extract_model(&value).unwrap_or_else(|| "unknown".to_string()),
                    "content": [],
                    "usage": value.get("usage").cloned().unwrap_or_else(|| json!({})),
                }
            });
            let content_delta = json!({
                "type": "content_block_delta",
                "index": 0,
                "delta": {
                    "type": "text_delta",
                    "text": text,
                }
            });
            format!(
                "event: message_start\ndata: {}\n\nevent: content_block_delta\ndata: {}\n\nevent: message_stop\ndata: {{}}\n\n",
                serde_json::to_string(&message_start).unwrap_or_else(|_| "{}".to_string()),
                serde_json::to_string(&content_delta).unwrap_or_else(|_| "{}".to_string())
            )
            .into_bytes()
        }
    }
}

fn extract_response_text(value: &Value) -> Option<String> {
    if let Some(text) = value.get("output_text").and_then(extract_text) {
        return Some(text);
    }
    if let Some(text) = value.get("text").and_then(extract_text) {
        return Some(text);
    }
    if let Some(choices) = value.get("choices").and_then(Value::as_array) {
        for choice in choices {
            if let Some(text) = choice
                .get("message")
                .and_then(|message| message.get("content"))
                .and_then(extract_text)
            {
                return Some(text);
            }
            if let Some(text) = choice
                .get("delta")
                .and_then(|delta| delta.get("content"))
                .and_then(extract_text)
            {
                return Some(text);
            }
        }
    }
    if let Some(output) = value.get("output").and_then(Value::as_array) {
        for item in output {
            if let Some(text) = item
                .get("content")
                .and_then(extract_text)
                .or_else(|| item.get("text").and_then(extract_text))
            {
                return Some(text);
            }
        }
    }
    if let Some(content) = value.get("content").and_then(extract_text) {
        return Some(content);
    }
    if let Some(error) = value.get("error") {
        if let Some(text) = error.get("message").and_then(extract_text) {
            return Some(text);
        }
    }
    None
}

fn extract_finish_reason(value: &Value) -> Option<String> {
    value
        .pointer("/choices/0/finish_reason")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
        .or_else(|| {
            value
                .get("stop_reason")
                .and_then(Value::as_str)
                .map(ToOwned::to_owned)
        })
}

fn extract_model(value: &Value) -> Option<String> {
    value
        .get("model")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
}

fn normalize_usage(value: Option<&Value>) -> Option<Value> {
    let usage = value?;
    let input_tokens = usage
        .get("input_tokens")
        .or_else(|| usage.get("prompt_tokens"))
        .and_then(Value::as_u64);
    let output_tokens = usage
        .get("output_tokens")
        .or_else(|| usage.get("completion_tokens"))
        .and_then(Value::as_u64);
    let cached_tokens = provider_cached_tokens(usage);
    let total_tokens = usage
        .get("total_tokens")
        .and_then(Value::as_u64)
        .or_else(|| match (input_tokens, output_tokens) {
            (Some(input), Some(output)) => Some(input + output),
            _ => None,
        });

    let mut object = Map::new();
    if let Some(value) = input_tokens {
        object.insert("input_tokens".to_string(), Value::Number(value.into()));
    }
    if let Some(value) = output_tokens {
        object.insert("output_tokens".to_string(), Value::Number(value.into()));
    }
    if let Some(value) = total_tokens {
        object.insert("total_tokens".to_string(), Value::Number(value.into()));
    }
    if let Some(value) = cached_tokens {
        object.insert("cached_tokens".to_string(), Value::Number(value.into()));
        object.insert(
            "input_tokens_details".to_string(),
            json!({ "cached_tokens": value }),
        );
    }
    if object.is_empty() {
        None
    } else {
        Some(Value::Object(object))
    }
}

fn upstream_url(base_url: &str, channel: &Channel) -> String {
    let trimmed = base_url.trim_end_matches('/');
    let endpoint = channel.endpoint_path();
    if trimmed.ends_with(endpoint)
        || trimmed.ends_with("/chat/completions")
        || trimmed.ends_with("/responses")
        || trimmed.ends_with("/messages")
    {
        trimmed.to_string()
    } else if trimmed.ends_with("/v1") {
        format!("{trimmed}{endpoint}")
    } else {
        format!("{trimmed}/v1{endpoint}")
    }
}

fn responses_compact_url(base_url: &str, response_id: &str) -> String {
    let trimmed = base_url.trim_end_matches('/');
    let response_id = response_id.trim_matches('/');
    if trimmed.ends_with("/responses") {
        format!("{trimmed}/{response_id}/compact")
    } else if trimmed.ends_with("/v1") {
        format!("{trimmed}/responses/{response_id}/compact")
    } else {
        format!("{trimmed}/v1/responses/{response_id}/compact")
    }
}

fn compact_request_set_response_id(request: &mut Value, response_id: &str) {
    if let Value::Object(object) = request {
        object.insert(
            "response_id".to_string(),
            Value::String(response_id.to_string()),
        );
    }
}

fn compact_request_body_for_official_endpoint(body: &Value) -> Value {
    let mut compact_body = body.clone();
    if let Value::Object(object) = &mut compact_body {
        object.remove("response_id");
        object.remove("stream");
        object.remove("stream_options");
    }
    compact_body
}

fn should_fallback_compact_to_responses(status: u16) -> bool {
    matches!(status, 400 | 404 | 405 | 501)
}

fn collect_provider_usage_for_diagnostics(
    bytes: &[u8],
    decision: &RouteDecision,
) -> Option<UsageRecord> {
    let mut record = provider_usage_from_bytes(bytes);
    if !record.has_usage() {
        return None;
    }
    record.provider = decision.provider.name.clone();
    if record.model == "unknown" {
        record.model = decision.model.clone();
    }
    Some(record)
}

#[derive(Debug, Clone)]
struct ProviderUsageObservation {
    raw: UsageRecord,
    effective: UsageRecord,
}

async fn collect_provider_usage(
    state: &AppState,
    bytes: &[u8],
    decision: &RouteDecision,
    prefix_state_key: Option<&str>,
    used_response_session: bool,
) -> Option<ProviderUsageObservation> {
    let mut record = provider_usage_from_bytes(bytes);
    if !record.has_usage() {
        return None;
    }
    record.provider = decision.provider.name.clone();
    if record.model == "unknown" {
        record.model = decision.model.clone();
    }
    let is_response_session_delta = provider_usage_is_response_session_delta(
        state,
        prefix_state_key,
        &record,
        used_response_session,
    )
    .await;
    let effective = provider_usage_effective_for_prefix_metrics(&record, is_response_session_delta);
    Some(ProviderUsageObservation {
        raw: record,
        effective,
    })
}

async fn collect_provider_usage_from_record(
    state: &AppState,
    mut record: UsageRecord,
    decision: &RouteDecision,
    prefix_state_key: Option<&str>,
    used_response_session: bool,
) -> Option<ProviderUsageObservation> {
    if !record.has_usage() {
        return None;
    }
    record.provider = decision.provider.name.clone();
    if record.model == "unknown" {
        record.model = decision.model.clone();
    }
    let is_response_session_delta = provider_usage_is_response_session_delta(
        state,
        prefix_state_key,
        &record,
        used_response_session,
    )
    .await;
    let effective = provider_usage_effective_for_prefix_metrics(&record, is_response_session_delta);
    Some(ProviderUsageObservation {
        raw: record,
        effective,
    })
}

async fn provider_usage_is_response_session_delta(
    state: &AppState,
    prefix_state_key: Option<&str>,
    record: &UsageRecord,
    used_response_session: bool,
) -> bool {
    if !used_response_session {
        return false;
    }
    let Some(key) = prefix_state_key else {
        return true;
    };
    let states = state.prefix_states.lock().await;
    let Some(previous) = lookup_provider_prefix_state(&states, key) else {
        return true;
    };
    !response_session_usage_looks_like_full_context(previous, record)
}

fn provider_usage_effective_for_prefix_metrics(
    record: &UsageRecord,
    is_response_session_delta: bool,
) -> UsageRecord {
    let mut effective = record.clone();
    if is_response_session_delta {
        effective.cache_read_tokens = effective
            .cache_read_tokens
            .max(provider_cache_bucket_max(effective.input_tokens));
    }
    effective
}

fn responses_huge_dynamic_history_cold_read(
    record: &UsageRecord,
    tail_input_diagnostics: &TailInputDiagnostics,
) -> bool {
    if record.input_tokens < 32_000 || provider_cache_shortfall(record) < 8192 {
        return false;
    }
    let ratio = provider_cache_ratio(record).unwrap_or_default();
    if ratio >= 0.50 || record.cache_read_tokens >= 32_768 {
        return false;
    }
    let huge_history_tail = tail_input_diagnostics.input_items >= 32
        && (tail_input_diagnostics.message_chars >= 50_000
            || tail_input_diagnostics.tool_output_chars >= 80_000
            || tail_input_diagnostics.largest_tool_output_chars >= 32_000);
    if !huge_history_tail {
        return false;
    }
    matches!(
        tail_input_diagnostics.source.as_deref(),
        Some("mixed") | Some("tool_output") | None
    )
}

fn provider_cache_shortfall(record: &UsageRecord) -> u64 {
    provider_cache_bucket_max(record.input_tokens).saturating_sub(record.cache_read_tokens)
}

fn provider_cache_bucket_max(input_tokens: u64) -> u64 {
    (input_tokens / 512) * 512
}

fn provider_cache_shortfall_128(record: &UsageRecord) -> u64 {
    provider_cache_bucket_max_128(record.input_tokens).saturating_sub(record.cache_read_tokens)
}

fn provider_cache_bucket_max_128(input_tokens: u64) -> u64 {
    if input_tokens < 1024 {
        0
    } else {
        1024 + ((input_tokens - 1024) / 128) * 128
    }
}

fn strip_response_session_volatile_fields(value: &mut Value) {
    match value {
        Value::Object(map) => {
            map.remove("previous_response_id");
            map.remove("store");
            map.remove("stream");
            map.remove("include");
            map.remove("metadata");
            map.remove("user");
            map.remove("service_tier");
            map.remove("truncation");
            for child in map.values_mut() {
                strip_response_session_volatile_fields(child);
            }
        }
        Value::Array(items) => {
            for item in items {
                strip_response_session_volatile_fields(item);
            }
        }
        _ => {}
    }
}

fn trim_response_session_input_to_anchor(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };
    let Some(input) = object.get_mut("input") else {
        return;
    };
    let Some(items) = input.as_array_mut() else {
        return;
    };
    if items.len() > 1 {
        items.truncate(1);
    }
}

fn provider_cache_ratio(record: &UsageRecord) -> Option<f64> {
    if record.input_tokens == 0 {
        None
    } else {
        Some(record.cache_read_tokens as f64 / record.input_tokens as f64)
    }
}

fn provider_cache_diagnostic(record: &UsageRecord) -> String {
    if record.input_tokens == 0 {
        return "provider-no-usage".to_string();
    }

    let bucket_max = (record.input_tokens / 512) * 512;
    if bucket_max < 1024 {
        return "provider-prefix-ineligible-small".to_string();
    }

    if record.cache_read_tokens == 0 {
        return "provider-cold-start".to_string();
    }

    let bucket_gap = bucket_max.saturating_sub(record.cache_read_tokens);
    if bucket_gap == 0 {
        return "provider-warm-full".to_string();
    }
    if bucket_gap <= 512 {
        return "provider-small-gap".to_string();
    }
    if (record.cache_read_tokens as f64 / bucket_max as f64) >= 0.99 {
        return "provider-warm-99".to_string();
    }
    "provider-prefix-break".to_string()
}

fn provider_usage_from_bytes(bytes: &[u8]) -> UsageRecord {
    if let Ok(value) = serde_json::from_slice::<Value>(bytes) {
        return provider_usage_from_value(&value);
    }

    let mut record = UsageRecord::default();
    let text = String::from_utf8_lossy(bytes);
    for line in text.lines() {
        let Some(payload) = line.trim_start().strip_prefix("data:") else {
            continue;
        };
        let payload = payload.trim();
        if payload.is_empty() || payload == "[DONE]" {
            continue;
        }
        if let Ok(value) = serde_json::from_str::<Value>(payload) {
            record.merge(provider_usage_from_value(&value));
        }
    }
    record
}

fn provider_usage_from_value(value: &Value) -> UsageRecord {
    let usage = value
        .get("usage")
        .or_else(|| value.pointer("/message/usage"))
        .or_else(|| value.pointer("/response/usage"));
    let input_tokens = usage
        .and_then(|usage| usage.get("input_tokens"))
        .or_else(|| usage.and_then(|usage| usage.get("prompt_tokens")))
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let cached_tokens = usage.and_then(provider_cached_tokens).unwrap_or(0);
    let output_tokens = usage
        .and_then(|usage| usage.get("output_tokens"))
        .or_else(|| usage.and_then(|usage| usage.get("completion_tokens")))
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let cache_creation_tokens = usage
        .and_then(|usage| usage.get("cache_creation_input_tokens"))
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let model = value
        .get("model")
        .or_else(|| value.pointer("/message/model"))
        .or_else(|| value.pointer("/response/model"))
        .and_then(Value::as_str)
        .unwrap_or("unknown")
        .to_string();

    UsageRecord {
        provider: String::new(),
        model,
        input_tokens,
        output_tokens,
        cache_read_tokens: cached_tokens,
        cache_creation_tokens,
    }
}

fn provider_cached_tokens(usage: &Value) -> Option<u64> {
    [
        usage.pointer("/prompt_tokens_details/cached_tokens"),
        usage.pointer("/input_tokens_details/cached_tokens"),
        usage.get("cache_read_input_tokens"),
        usage.get("cached_input_tokens"),
    ]
    .into_iter()
    .flatten()
    .filter_map(Value::as_u64)
    .max()
}

fn raw_response(status: u16, content_type: &str, body: Vec<u8>) -> Response {
    Response::builder()
        .status(status)
        .header(header::CONTENT_TYPE, content_type)
        .body(Body::from(body))
        .unwrap_or_else(|_| {
            json_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "failed to build response",
            )
        })
}

fn json_error(status: StatusCode, message: &str) -> Response {
    (
        status,
        [(
            header::CONTENT_TYPE,
            HeaderValue::from_static("application/json"),
        )],
        Json(json!({
            "error": {
                "message": message,
                "type": "atoapi_error"
            }
        })),
    )
        .into_response()
}

