    #[test]
    fn agent_generation_bypasses_local_response_replay_cache() {
        let config = AppConfig::default();
        let request = json!({
            "model": "gpt-5.5",
            "temperature": 0.0,
            "messages": [{ "role": "user", "content": "hello" }]
        });

        assert!(local_response_cache_eligible(
            &config, false, &request, None
        ));
        assert!(!local_response_cache_eligible(
            &config,
            false,
            &request,
            Some("codex")
        ));
        assert!(local_response_cache_material(
            true,
            &Channel::Responses,
            &Channel::Responses,
            true,
            false,
            &request,
        )
        .is_some());
        assert!(local_response_cache_material(
            false,
            &Channel::Responses,
            &Channel::Responses,
            true,
            false,
            &request,
        )
        .is_none());
    }

    #[test]
    fn chat_responses_stream_cache_material_isolated_by_usage_option() {
        let request = json!({
            "model": "gpt-response",
            "stream": true,
            "messages": [{ "role": "user", "content": "cache me" }]
        });
        let without_usage = local_response_cache_material(
            true,
            &Channel::Chat,
            &Channel::Responses,
            true,
            false,
            &request,
        )
        .unwrap();
        let with_usage = local_response_cache_material(
            true,
            &Channel::Chat,
            &Channel::Responses,
            true,
            true,
            &request,
        )
        .unwrap();

        assert_eq!(without_usage["chat_stream_include_usage"], false);
        assert_eq!(with_usage["chat_stream_include_usage"], true);
        assert_ne!(
            cache::cache_key(&without_usage, "provider", "gpt-response", "workspace"),
            cache::cache_key(&with_usage, "provider", "gpt-response", "workspace")
        );
        assert!(chat_stream_include_usage_requested(
            &json!({ "stream_options": { "include_usage": true } }),
            &Channel::Chat
        ));
        assert!(!chat_stream_include_usage_requested(
            &json!({ "stream_options": { "include_usage": true } }),
            &Channel::Responses
        ));
    }

