    #[test]
    fn chat_prefix_optimizer_stabilizes_actual_outbound_body() {
        let mut config = AppConfig::default();
        config.cache.enabled = true;
        config.cache.mode = CacheMode::PrefixPrewarm;
        let provider = ProviderConfig {
            id: "share".to_string(),
            name: "Share".to_string(),
            base_url: "https://api.example.com/v1".to_string(),
            models_url: None,
            is_full_url: false,
            custom_user_agent: None,
            channel: Channel::Chat,
            prompt_cache_retention_enabled: false,
            request_body_gzip_enabled: false,
            use_system_proxy: false,
            api_key_encrypted: None,
            models: Vec::new(),
            enabled: true,
            created_at: Utc::now(),
            updated_at: Utc::now(),
        };
        let decision = RouteDecision {
            provider,
            upstream_channel: Channel::Chat,
            model: "gpt-5.5".to_string(),
        };
        let mut left = json!({
            "model": "gpt-5.5",
            "request_id": "req-left",
            "messages": [
                { "role": "system", "content": "Stable instructions" },
                {
                    "role": "assistant",
                    "tool_calls": [{
                        "id": "call_1",
                        "type": "function",
                        "function": {
                            "name": "read_file",
                            "arguments": "{\"path\":\"README.md\",\"limit\":20}"
                        }
                    }]
                }
            ],
            "tools": [{
                "description": "Read file",
                "parameters": {
                    "required": ["limit", "path"],
                    "type": "object",
                    "properties": {
                        "path": { "type": "string" },
                        "limit": { "type": "integer" }
                    }
                },
                "name": "read_file"
            }],
            "tool_choice": { "function": { "name": "read_file" }, "type": "function" }
        });
        let mut right = json!({
            "tool_choice": { "type": "function", "function": { "name": "read_file" } },
            "tools": [{
                "name": "read_file",
                "type": "function",
                "parameters": {
                    "properties": {
                        "limit": { "type": "integer" },
                        "path": { "type": "string" }
                    },
                    "required": ["path", "limit"],
                    "type": "object"
                },
                "description": "Read file"
            }],
            "messages": [
                { "content": "Stable instructions", "role": "system" },
                {
                    "tool_calls": [{
                        "function": {
                            "arguments": "{\"limit\":20,\"path\":\"README.md\"}",
                            "name": "read_file"
                        },
                        "type": "function",
                        "id": "call_1"
                    }],
                    "role": "assistant"
                }
            ],
            "model": "gpt-5.5",
            "request_id": "req-right"
        });

        optimize_provider_prefix(&mut left, &config, &decision);
        optimize_provider_prefix(&mut right, &config, &decision);

        assert_eq!(left, right);
        assert_eq!(
            left.pointer("/messages/1/tool_calls/0/id")
                .and_then(Value::as_str),
            Some("call_1")
        );
        assert_eq!(
            left.pointer("/messages/1/tool_calls/0/function/arguments")
                .and_then(Value::as_str),
            Some("{\"limit\":20,\"path\":\"README.md\"}")
        );
    }

