    #[test]
    fn responses_wire_prefix_fingerprints_isolate_cache_instruction_and_tool_drift() {
        let baseline = json!({
            "model": "gpt-5.6-luna",
            "prompt_cache_key": "cache-a",
            "instructions": "stable instruction",
            "tools": [{ "type": "function", "name": "read_file" }],
            "input": [{ "type": "message", "role": "user", "content": "history" }]
        });
        let baseline_hashes = responses_wire_prefix_fingerprints(&Channel::Responses, &baseline)
            .expect("Responses requests have wire diagnostics");

        let mut changed_cache = baseline.clone();
        changed_cache["prompt_cache_key"] = json!("cache-b");
        let changed_cache = responses_wire_prefix_fingerprints(&Channel::Responses, &changed_cache)
            .expect("Responses requests have wire diagnostics");
        assert_ne!(baseline_hashes.cache_metadata, changed_cache.cache_metadata);
        assert_eq!(baseline_hashes.instructions, changed_cache.instructions);
        assert_eq!(baseline_hashes.tools_schema, changed_cache.tools_schema);

        let mut changed_instructions = baseline.clone();
        changed_instructions["instructions"] = json!("changed instruction");
        let changed_instructions =
            responses_wire_prefix_fingerprints(&Channel::Responses, &changed_instructions)
                .expect("Responses requests have wire diagnostics");
        assert_eq!(
            baseline_hashes.cache_metadata,
            changed_instructions.cache_metadata
        );
        assert_ne!(
            baseline_hashes.instructions,
            changed_instructions.instructions
        );
        assert_eq!(
            baseline_hashes.tools_schema,
            changed_instructions.tools_schema
        );

        let mut changed_tools = baseline;
        changed_tools["tools"] = json!([{ "type": "function", "name": "write_file" }]);
        let changed_tools = responses_wire_prefix_fingerprints(&Channel::Responses, &changed_tools)
            .expect("Responses requests have wire diagnostics");
        assert_eq!(baseline_hashes.cache_metadata, changed_tools.cache_metadata);
        assert_eq!(baseline_hashes.instructions, changed_tools.instructions);
        assert_ne!(baseline_hashes.tools_schema, changed_tools.tools_schema);
    }

    #[test]
    fn upstream_request_diagnostics_keep_the_final_attempt_prefix_hashes() {
        let first_body = json!({
            "model": "gpt-5.5",
            "input": [{ "type": "message", "role": "user", "content": "first" }]
        });
        let final_body = json!({
            "model": "gpt-5.5",
            "input": [{ "type": "message", "role": "user", "content": "final" }]
        });
        let mut diagnostics = UpstreamRequestDiagnostics {
            outbound_prefix_fingerprints: responses_wire_prefix_fingerprints(
                &Channel::Responses,
                &first_body,
            ),
            ..UpstreamRequestDiagnostics::default()
        };
        let final_attempt = UpstreamRequestDiagnostics {
            outbound_prefix_fingerprints: responses_wire_prefix_fingerprints(
                &Channel::Responses,
                &final_body,
            ),
            ..UpstreamRequestDiagnostics::default()
        };

        diagnostics.absorb(&final_attempt);

        assert_eq!(
            diagnostics.outbound_prefix_fingerprints,
            final_attempt.outbound_prefix_fingerprints
        );
    }

    #[test]
    fn stage2_candidate_wire_changes_only_prompt_cache_key() {
        let mut decision = cache_affinity::ShadowAffinityDecision {
            mode: "shadow".to_string(),
            assignment_key: Some("conversation-a".to_string()),
            realm_id: "realm-a".to_string(),
            cohort_id: "cohort-candidate".to_string(),
            lane: cache_affinity::ShadowCacheLane::Steady,
            candidate_variant: cache_affinity::ShadowCacheCandidateVariant::CohortKey,
            arm: cache_affinity::ShadowAffinityArm::Candidate,
            shard: 0,
            policy_epoch: cache_affinity::SHADOW_POLICY_EPOCH,
            anchor_epoch: 0,
            trusted_identity: true,
            decision: "assigned".to_string(),
            skip_reason: None,
            policy_compute_ms: 0,
            validation_run_id: None,
            automatic_canary_status: None,
            automatic_canary_reason: None,
        };
        assert!(cache_affinity::apply_static_cohort_canary(
            &mut decision,
            true
        ));
        let candidate_key = cache_affinity::static_cohort_prompt_cache_key(&decision)
            .expect("applied candidate must have a cache key")
            .to_string();

        let baseline = json!({
            "model": "gpt-5.5",
            "prompt_cache_key": "cohort-baseline",
            "instructions": "stable system",
            "tools": [{ "type": "function", "name": "read_file" }],
            "input": [{ "type": "message", "role": "user", "content": "fresh" }],
            "reasoning": { "effort": "high" },
            "stream": true
        });
        let mut candidate = baseline.clone();
        candidate
            .as_object_mut()
            .expect("request body must be an object")
            .insert(
                "prompt_cache_key".to_string(),
                Value::String(candidate_key.clone()),
            );

        let baseline_wire = legacy_upstream_request_body_bytes(&Channel::Responses, &baseline);
        let candidate_wire = legacy_upstream_request_body_bytes(&Channel::Responses, &candidate);
        assert_ne!(baseline_wire, candidate_wire);
        assert!(String::from_utf8_lossy(&candidate_wire).contains(&candidate_key));

        let without_key = |wire: &[u8]| {
            let mut value: Value = serde_json::from_slice(wire).expect("wire JSON");
            value
                .as_object_mut()
                .expect("wire JSON object")
                .remove("prompt_cache_key");
            value
        };
        assert_eq!(without_key(&baseline_wire), without_key(&candidate_wire));

        let baseline_headers = build_upstream_request_headers(
            &HeaderMap::new(),
            "upstream-key",
            &Channel::Responses,
            true,
            None,
            false,
        );
        let candidate_headers = build_upstream_request_headers(
            &HeaderMap::new(),
            "upstream-key",
            &Channel::Responses,
            true,
            None,
            false,
        );
        assert_eq!(baseline_headers, candidate_headers);

        decision.candidate_variant = cache_affinity::ShadowCacheCandidateVariant::CohortTwoShard;
        let mut two_shard = baseline.clone();
        let two_shard_outcome = apply_candidate_prompt_cache_routing(&mut two_shard, &decision);
        assert!(two_shard_outcome.applied);
        assert!(two_shard_outcome.changed);
        let two_shard_key = two_shard
            .get("prompt_cache_key")
            .and_then(Value::as_str)
            .expect("two-shard candidate must have a cache key");
        assert_ne!(two_shard_key, candidate_key);
        let repeated_two_shard = apply_candidate_prompt_cache_routing(&mut two_shard, &decision);
        assert!(repeated_two_shard.applied);
        assert!(!repeated_two_shard.changed);
        assert_eq!(
            without_key(&baseline_wire),
            without_key(&legacy_upstream_request_body_bytes(
                &Channel::Responses,
                &two_shard,
            ))
        );

        decision.candidate_variant = cache_affinity::ShadowCacheCandidateVariant::ProviderNative;
        let mut provider_native = baseline.clone();
        let provider_native_outcome =
            apply_candidate_prompt_cache_routing(&mut provider_native, &decision);
        assert!(provider_native_outcome.applied);
        assert!(provider_native_outcome.changed);
        assert!(provider_native.get("prompt_cache_key").is_none());
        let repeated_provider_native =
            apply_candidate_prompt_cache_routing(&mut provider_native, &decision);
        assert!(repeated_provider_native.applied);
        assert!(!repeated_provider_native.changed);
        assert_eq!(without_key(&baseline_wire), provider_native);
    }

