    #[tokio::test]
    async fn agent_finalization_persists_real_post_burst_observation_fields() {
        let dir = std::env::temp_dir().join(format!(
            "atoapi-post-burst-finalize-{}",
            Uuid::new_v4().simple()
        ));
        let state = AppState::for_test(
            AppConfig::default(),
            dir.join("config.toml"),
            CacheStore::load(cache_path(&dir)).unwrap(),
        )
        .unwrap();
        let affinity_identity = affinity_identity::AffinityIdentity {
            realm_id: "post-burst-realm".to_string(),
            cohort_id: "post-burst-cohort".to_string(),
            stable_prefix_digest: "post-burst-prefix".to_string(),
            trusted_conversation_id: Some("post-burst-conversation".to_string()),
            trusted_identity_source: Some("test".to_string()),
        };
        let route = RouteDecision {
            provider: test_responses_provider("http://127.0.0.1:1/v1".to_string()),
            upstream_channel: Channel::Responses,
            model: "gpt-5.5".to_string(),
        };

        for index in 0..4_u64 {
            let inbound_request_id = format!("post-burst-inbound-{index}");
            let attempt_id = format!("post-burst-attempt-{index}");
            assert!(
                state
                    .metrics
                    .begin_agent_inbound(AgentInboundStart {
                        inbound_request_id: inbound_request_id.clone(),
                        at: Utc::now(),
                        attempt_policy: "single".to_string(),
                        attempt_budget: 1,
                    })
                    .await
            );
            assert_eq!(
                state
                    .metrics
                    .begin_agent_attempt(AgentAttemptStart {
                        inbound_request_id: inbound_request_id.clone(),
                        attempt_id: attempt_id.clone(),
                        at: Utc::now(),
                        attempt_reason: "primary".to_string(),
                        provider: route.provider.name.clone(),
                        model: route.model.clone(),
                        upstream_channel: "responses".to_string(),
                    })
                    .await,
                Some(1)
            );

            let mut shadow_decision = {
                let mut store = state.shadow_affinity.lock().await;
                cache_affinity::compute_shadow_affinity(
                    &mut store,
                    &affinity_identity,
                    None,
                    Utc::now(),
                    if index == 0 { 90_000 } else { 0 },
                    if index == 0 { 90_000 } else { 0 },
                )
            };
            shadow_decision.arm = cache_affinity::ShadowAffinityArm::Baseline;

            let started = Instant::now();
            let mut request_log = upstream_transport_failure_log(
                &inbound_request_id,
                &started,
                &Channel::Responses,
                &Channel::Responses,
                &route,
                None,
                Some("post-burst-prefix"),
                None,
                &PrefixGuardWaitDiagnostics::default(),
                0,
                &BodyDiagnostics::default(),
                &json!({"model":"gpt-5.5","stream":true}),
                false,
                &ResponseSessionReuseDiagnostics::default(),
                Some("gpt-5.5".to_string()),
                "test-post-burst",
            );
            request_log.status = 200;
            request_log.cache_status = "bypass".to_string();
            request_log.ttft_ms = 1_100 + index;
            request_log.input_tokens = Some(100_000);
            request_log.output_tokens = Some(100);
            request_log.cache_read_tokens = Some(88_000);
            request_log.cache_avoidable_gap_tokens = Some(1_536 + index);
            request_log.cache_provider_unstable_gap_tokens = Some(256 + index);
            request_log.tail_tool_output_chars = Some(if index == 0 { 90_000 } else { 0 });
            request_log.tail_largest_tool_output_chars = Some(if index == 0 { 90_000 } else { 0 });
            request_log.upstream_attempt_total = Some(1);
            request_log.upstream_attempts = Some(1);

            finalize_agent_generation(
                &state,
                &inbound_request_id,
                Some(attempt_id),
                request_log,
                AgentAttemptOutcome::HttpSuccess,
                AgentInboundOutcome::Success,
                Some(200),
                None,
                "response_completed",
                None,
                None,
                Vec::new(),
                Some(shadow_decision),
                None,
            )
            .await;
        }

        let mut store = state.shadow_affinity.lock().await;
        let status = cache_affinity::post_burst_evidence_status(&mut store, Utc::now());
        assert_eq!(status.open_windows, 0);
        assert_eq!(status.evidence_records, 3);
        let observations = store.post_burst.evidence.iter().collect::<Vec<_>>();
        assert_eq!(observations[0].followup_index, 1);
        assert_eq!(observations[2].followup_index, 3);
        assert_eq!(observations[0].cache_ratio_bps, 8_800);
        assert_eq!(observations[0].avoidable_gap_tokens, 1_537);
        assert_eq!(observations[0].provider_unstable_gap_tokens, 257);
        assert_eq!(observations[0].ttft_ms, 1_101);
        assert_eq!(observations[0].attempt_count, 1);
        drop(store);

        state.persist_runtime_state().await.unwrap();
        let persisted: Value = serde_json::from_str(
            &fs::read_to_string(&state.runtime_state_path).expect("runtime state must be saved"),
        )
        .unwrap();
        assert_eq!(
            persisted
                .pointer("/shadow_affinity/post_burst/evidence")
                .and_then(Value::as_array)
                .map(Vec::len),
            Some(3)
        );
        fs::remove_dir_all(dir).ok();
    }

    #[tokio::test]
    async fn configured_model_reasoning_rejection_is_one_shot_reasoning_compatibility_and_persists_next_turn(
    ) {
        let attempted_efforts = Arc::new(tokio::sync::Mutex::new(Vec::<String>::new()));
        let attempted_efforts_for_route = attempted_efforts.clone();
        let upstream_listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
        let upstream_addr = upstream_listener.local_addr().unwrap();
        let upstream_app = Router::new().route(
            "/v1/responses",
            post(move |Json(body): Json<Value>| {
                let attempted_efforts = attempted_efforts_for_route.clone();
                async move {
                    let effort = body
                        .pointer("/reasoning/effort")
                        .and_then(Value::as_str)
                        .unwrap_or_default()
                        .to_string();
                    attempted_efforts.lock().await.push(effort.clone());
                    if effort == "ultra" {
                        let rejection = json!({
                            "error": {
                                "message": format!(
                                    "level \"{effort}\" not supported, valid levels: low, medium, high, xhigh"
                                )
                            }
                        });
                        raw_response(
                            502,
                            "application/json",
                            serde_json::to_vec(&rejection).unwrap(),
                        )
                    } else if effort == "max" {
                        raw_response(
                            200,
                            "text/event-stream",
                            concat!(
                                "event: response.output_text.delta\n",
                                "data: {\"type\":\"response.output_text.delta\",\"delta\":\"ready\"}\n\n",
                                "event: response.completed\n",
                                "data: {\"type\":\"response.completed\",\"response\":{\"id\":\"resp_reasoning\",\"usage\":{\"input_tokens\":2,\"output_tokens\":1}}}\n\n"
                            )
                            .as_bytes()
                            .to_vec(),
                        )
                    } else {
                        raw_response(
                            400,
                            "application/json",
                            serde_json::to_vec(&json!({
                                "error": { "message": format!("unexpected effort {effort}") }
                            }))
                            .unwrap(),
                        )
                    }
                }
            }),
        );
        tokio::spawn(async move {
            axum::serve(upstream_listener, upstream_app).await.unwrap();
        });

        let mut config = AppConfig::default();
        config.local_key = "local-test-key".to_string();
        config.workspace_fingerprint = "workspace-test".to_string();
        let mut provider = test_responses_provider(format!("http://{upstream_addr}/v1"));
        provider.id = "reasoning-fallback-provider".to_string();
        provider.models = vec![
            ModelConfig {
                id: "gpt-5.6-luna".to_string(),
                request_model_id: None,
                display_name: "gpt-5.6-luna".to_string(),
                context_window: None,
                output_window: None,
                reasoning_effort_override_enabled: true,
                reasoning_effort: Some("ultra".to_string()),
                supported_reasoning_efforts: Vec::new(),
                supports_tools: true,
                supports_streaming: true,
                enabled: true,
            },
            ModelConfig {
                id: "unrelated-model".to_string(),
                request_model_id: None,
                display_name: "Unrelated Model".to_string(),
                context_window: None,
                output_window: None,
                reasoning_effort_override_enabled: true,
                reasoning_effort: Some("ultra".to_string()),
                supported_reasoning_efforts: Vec::new(),
                supports_tools: true,
                supports_streaming: true,
                enabled: true,
            },
        ];
        config.providers = vec![provider];
        config.agent_injections = vec![AgentInjectionConfig {
            id: "codex".to_string(),
            label: "Codex".to_string(),
            kind: AgentInjectionKind::Codex,
            enabled: true,
            provider_id: Some("reasoning-fallback-provider".to_string()),
            model_id: None,
            target_path: None,
            last_injected_at: None,
            last_status: None,
            local_key: None,
            hidden_provider_ids: Vec::new(),
        }];
        let dir = std::env::temp_dir().join(format!(
            "atoapi-agent-reasoning-fallback-{}",
            Uuid::new_v4().simple()
        ));
        let config_path = dir.join("config.toml");
        let state = Arc::new(
            AppState::for_test(
                config,
                config_path.clone(),
                CacheStore::load(dir.join("cache.bin")).unwrap(),
            )
            .unwrap(),
        );
        let mut headers = HeaderMap::new();
        headers.insert(
            header::AUTHORIZATION,
            HeaderValue::from_static("Bearer local-test-key"),
        );
        let request = || {
            Bytes::from(
                serde_json::to_vec(&json!({
                    "thread_id": "reasoning-fallback-session",
                    "model": "gpt-5.6-luna",
                    "input": [{ "type": "message", "role": "user", "content": "hello" }]
                }))
                .unwrap(),
            )
        };

        let first = handle_generation_for_agent(
            state.clone(),
            headers.clone(),
            request(),
            Channel::Responses,
            Some("codex"),
        )
        .await;
        assert_eq!(first.status(), StatusCode::BAD_GATEWAY);
        let first_body = axum::body::to_bytes(first.into_body(), usize::MAX)
            .await
            .unwrap();
        assert!(String::from_utf8_lossy(&first_body).contains("not supported"));
        assert_eq!(*attempted_efforts.lock().await, vec!["ultra".to_string()]);
        let first_metrics = state.metrics.snapshot().await;
        assert_eq!(first_metrics.upstream_requests, 1);
        assert_eq!(first_metrics.retries, 0);
        assert!(first_metrics.recent_requests.is_empty());
        assert_eq!(first_metrics.recent_failed_requests.len(), 1);
        assert_eq!(first_metrics.recent_agent_upstream_attempts.len(), 1);
        {
            let config = state.config.read().await;
            let provider = config
                .providers
                .iter()
                .find(|provider| provider.id == "reasoning-fallback-provider")
                .unwrap();
            assert_eq!(
                provider
                    .models
                    .iter()
                    .find(|model| model.id == "gpt-5.6-luna")
                    .and_then(|model| model.reasoning_effort.as_deref()),
                Some("max")
            );
            assert_eq!(
                provider
                    .models
                    .iter()
                    .find(|model| model.id == "unrelated-model")
                    .and_then(|model| model.reasoning_effort.as_deref()),
                Some("ultra")
            );
        }
        state.flush_config().await.unwrap();
        let persisted: AppConfig =
            toml::from_str(&fs::read_to_string(&config_path).unwrap()).unwrap();
        let persisted_provider = persisted
            .providers
            .iter()
            .find(|provider| provider.id == "reasoning-fallback-provider")
            .unwrap();
        assert_eq!(
            persisted_provider
                .models
                .iter()
                .find(|model| model.id == "gpt-5.6-luna")
                .and_then(|model| model.reasoning_effort.as_deref()),
            Some("max")
        );

        let second = handle_generation_for_agent(
            state.clone(),
            headers,
            request(),
            Channel::Responses,
            Some("codex"),
        )
        .await;
        assert_eq!(second.status(), StatusCode::OK);
        let second_body = axum::body::to_bytes(second.into_body(), usize::MAX)
            .await
            .unwrap();
        assert!(String::from_utf8_lossy(&second_body).contains("ready"));
        assert_eq!(
            *attempted_efforts.lock().await,
            vec!["ultra".to_string(), "max".to_string()]
        );

        tokio::time::sleep(std::time::Duration::from_millis(50)).await;
        let metrics = state.metrics.snapshot().await;
        assert_eq!(metrics.total_requests, 2);
        assert_eq!(metrics.successful_requests, 1);
        assert_eq!(metrics.upstream_requests, 2);
        assert_eq!(metrics.retries, 0);
        assert_eq!(metrics.recent_upstream_calls.len(), 1);
        assert_eq!(metrics.recent_requests.len(), 1);
        assert_eq!(metrics.recent_failed_requests.len(), 1);
        assert_eq!(metrics.recent_agent_upstream_attempts.len(), 2);

        fs::remove_dir_all(dir).ok();
    }

    #[tokio::test]
    async fn ordinary_cloudflare_and_generic_5xx_do_not_downgrade_model_reasoning_effort() {
        let attempted_efforts = Arc::new(tokio::sync::Mutex::new(Vec::<String>::new()));
        let attempted_efforts_for_route = attempted_efforts.clone();
        let upstream_listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
        let upstream_addr = upstream_listener.local_addr().unwrap();
        let upstream_app = Router::new().route(
            "/v1/responses",
            post(move |Json(body): Json<Value>| {
                let attempted_efforts = attempted_efforts_for_route.clone();
                async move {
                    let effort = body
                        .pointer("/reasoning/effort")
                        .and_then(Value::as_str)
                        .unwrap_or_default()
                        .to_string();
                    attempted_efforts.lock().await.push(effort);
                    if body
                        .pointer("/input/0/content")
                        .and_then(Value::as_str)
                        == Some("generic-5xx")
                    {
                        raw_response(
                            502,
                            "application/json",
                            serde_json::to_vec(&json!({
                                "error": { "message": "invalid upstream gateway response" }
                            }))
                            .unwrap(),
                        )
                    } else {
                        raw_response(
                            502,
                            "text/html",
                            format!(
                                "<!DOCTYPE html><html><body>{}</body><div id=\"cf-error-details\">502: Bad gateway</div></html>",
                                "x".repeat(720)
                            )
                            .into_bytes(),
                        )
                    }
                }
            }),
        );
        tokio::spawn(async move {
            axum::serve(upstream_listener, upstream_app).await.unwrap();
        });

        let mut config = AppConfig::default();
        config.local_key = "local-test-key".to_string();
        config.workspace_fingerprint = "workspace-test".to_string();
        let mut provider = test_responses_provider(format!("http://{upstream_addr}/v1"));
        provider.id = "ordinary-gateway-provider".to_string();
        provider.models = vec![ModelConfig {
            id: "gpt-5.6-luna".to_string(),
            request_model_id: None,
            display_name: "gpt-5.6-luna".to_string(),
            context_window: None,
            output_window: None,
            reasoning_effort_override_enabled: true,
            reasoning_effort: Some("ultra".to_string()),
            supported_reasoning_efforts: Vec::new(),
            supports_tools: true,
            supports_streaming: true,
            enabled: true,
        }];
        config.providers = vec![provider];
        config.agent_injections = vec![AgentInjectionConfig {
            id: "codex".to_string(),
            label: "Codex".to_string(),
            kind: AgentInjectionKind::Codex,
            enabled: true,
            provider_id: Some("ordinary-gateway-provider".to_string()),
            model_id: None,
            target_path: None,
            last_injected_at: None,
            last_status: None,
            local_key: None,
            hidden_provider_ids: Vec::new(),
        }];
        let dir = std::env::temp_dir().join(format!(
            "atoapi-agent-ordinary-gateway-{}",
            Uuid::new_v4().simple()
        ));
        let config_path = dir.join("config.toml");
        let state = Arc::new(
            AppState::for_test(
                config,
                config_path.clone(),
                CacheStore::load(dir.join("cache.bin")).unwrap(),
            )
            .unwrap(),
        );
        let mut headers = HeaderMap::new();
        headers.insert(
            header::AUTHORIZATION,
            HeaderValue::from_static("Bearer local-test-key"),
        );
        let request = |content: &str| {
            Bytes::from(
                serde_json::to_vec(&json!({
                    "thread_id": "ordinary-gateway-session",
                    "model": "gpt-5.6-luna",
                    "input": [{ "type": "message", "role": "user", "content": content }]
                }))
                .unwrap(),
            )
        };

        let response = handle_generation_for_agent(
            state.clone(),
            headers.clone(),
            request("cloudflare-502"),
            Channel::Responses,
            Some("codex"),
        )
        .await;
        assert_eq!(response.status(), StatusCode::BAD_GATEWAY);
        let _ = axum::body::to_bytes(response.into_body(), usize::MAX)
            .await
            .unwrap();
        assert_eq!(*attempted_efforts.lock().await, vec!["ultra".to_string()]);

        // Keep the second assertion focused on error classification rather
        // than the independent short-lived prefix error guard.
        state.prefix_error_cooldowns.lock().await.clear();

        let generic = handle_generation_for_agent(
            state.clone(),
            headers,
            request("generic-5xx"),
            Channel::Responses,
            Some("codex"),
        )
        .await;
        assert_eq!(generic.status(), StatusCode::BAD_GATEWAY);
        let _ = axum::body::to_bytes(generic.into_body(), usize::MAX)
            .await
            .unwrap();
        assert_eq!(
            *attempted_efforts.lock().await,
            vec!["ultra".to_string(), "ultra".to_string()]
        );
        assert!(!config_path.exists());

        let config = state.config.read().await;
        let model = config.providers[0]
            .models
            .iter()
            .find(|model| model.id == "gpt-5.6-luna")
            .unwrap();
        assert_eq!(model.reasoning_effort.as_deref(), Some("ultra"));
        drop(config);

        let metrics = state.metrics.snapshot().await;
        assert_eq!(metrics.upstream_requests, 2);
        assert_eq!(metrics.retries, 0);

        fs::remove_dir_all(dir).ok();
    }

